local Utilities = {}
function Utilities.findPlayer(inputName)
	local input = tostring(inputName):lower()
	if input == "" then
		return nil
	end
	local exactMatch = nil
	local partialMatch = nil
	if input == "me" then
		return Players.LocalPlayer
	end
	for _, player in ipairs(Players:GetPlayers()) do
		local username = player.Name:lower()
		local displayName = player.DisplayName:lower()
		if username == input or displayName == input then
			exactMatch = player
			break
		end
		if not partialMatch then
			if username:sub(1, #input) == input or displayName:sub(1, #input) == input then
				partialMatch = player
			end
		end
	end
	return exactMatch or partialMatch
end

function Utilities.calculateLevenshteinDistance(s1: string, s2: string): number
	local len1, len2 = #s1, #s2
	if len1 == 0 then
		return len2
	end
	if len2 == 0 then
		return len1
	end
	local matrix = {}
	for i = 0, len1 do
		matrix[i] = {}
		matrix[i][0] = i
	end
	for j = 0, len2 do
		matrix[0][j] = j
	end
	for i = 1, len1 do
		for j = 1, len2 do
			local cost = (s1:sub(i, i) == s2:sub(j, j)) and 0 or 1
			matrix[i][j] = math.min(matrix[i - 1][j] + 1, matrix[i][j - 1] + 1, matrix[i - 1][j - 1] + cost)
		end
	end
	return matrix[len1][len2]
end
local Prefix = ";"
local Commands = {}
