			local fovRadius = 75
			local smoothingEnabled = false
			local smoothingFactor = 0.2
			local PROJECTILE_SPEED = 4500
			local gravityEnabled = false
			local selectedPlayerTarget, selectedPart = nil, nil
			local playerTargetEnabled = false
			local aiming = false
			local ignoreTeamEnabled = false
			local wallCheckEnabled = true
			local wallCheckParams = RaycastParams.new()
			wallCheckParams.FilterType = Enum.RaycastFilterType.Exclude
			local activeESPs = {}
			table.insert(
				janitor,
				gravityToggle.MouseButton1Click:Connect(function()
					gravityEnabled = not gravityEnabled
					gravityToggle.Text = "Gravity Drop: " .. (gravityEnabled and "ON" or "OFF")
				end)
			)
			table.insert(
				janitor,
				projSpeedBox.FocusLost:Connect(function()
					local val = tonumber(projSpeedBox.Text)
					if val and val > 0 then
						PROJECTILE_SPEED = val
					else
						projSpeedBox.Text = tostring(PROJECTILE_SPEED)
					end
				end)
			)
			local FovCircle = nil
			if Drawing and typeof(Drawing.new) == "function" then
				FovCircle = Drawing.new("Circle")
				FovCircle.Visible = false
				FovCircle.Thickness = 0.5
				FovCircle.NumSides = 64
				FovCircle.Color = Color3.fromRGB(255, 255, 255)
				FovCircle.Transparency = 0.7
				FovCircle.Filled = false
			else
				warn("Zuka's Log: 'Drawing' library not found. FOV circle visualization will be disabled.")
			end
			local minFov, maxFov = 50, 500
			local function updateFovFromHandlePosition()
				local trackWidth = sliderTrack.AbsoluteSize.X
				local handleX = sliderHandle.Position.X.Offset
				local ratio = math.clamp(handleX / (trackWidth - sliderHandle.AbsoluteSize.X), 0, 1)
				fovRadius = minFov + (maxFov - minFov) * ratio
				fovValueLabel.Text = tostring(math.floor(fovRadius)) .. "px"
				if FovCircle then
					FovCircle.Radius = fovRadius
				end
			end
			local function updateHandleFromFovValue()
				local trackWidth = sliderTrack.AbsoluteSize.X
				if trackWidth == 0 then
					return
				end
				local ratio = (fovRadius - minFov) / (maxFov - minFov)
				local handleX = ratio * (trackWidth - sliderHandle.AbsoluteSize.X)
				sliderHandle.Position = UDim2.new(0, handleX, 0.5, -6)
			end
			local isDraggingSlider = false
			table.insert(
				janitor,
				sliderHandle.InputBegan:Connect(function(input)
					if input.UserInputType == Enum.UserInputType.MouseButton1 then
						isDraggingSlider = true
					end
				end)
			)
			table.insert(
				janitor,
				UserInputService.InputEnded:Connect(function(input)
					if input.UserInputType == Enum.UserInputType.MouseButton1 then
						isDraggingSlider = false
					end
				end)
			)
			table.insert(
				janitor,
				UserInputService.InputChanged:Connect(function(input)
					if isDraggingSlider and input.UserInputType == Enum.UserInputType.MouseMovement then
						local mouseX = UserInputService:GetMouseLocation().X
						local trackStartX = sliderTrack.AbsolutePosition.X
						local handleWidth = sliderHandle.AbsoluteSize.X
						local trackWidth = sliderTrack.AbsoluteSize.X
						local newHandleX = mouseX - trackStartX - (handleWidth / 2)
						local clampedX = math.clamp(newHandleX, 0, trackWidth - handleWidth)
						sliderHandle.Position = UDim2.new(0, clampedX, 0.5, -6)
						updateFovFromHandlePosition()
					end
				end)
			)
			table.insert(
				janitor,
				smoothingToggle.MouseButton1Click:Connect(function()
					smoothingEnabled = not smoothingEnabled
					smoothingToggle.Text = "Smoothing: " .. (smoothingEnabled and "ON" or "OFF")
				end)
			)
			local minSmooth, maxSmooth = 0.05, 1.0
			local function updateSmoothFromHandlePosition()
				local trackWidth = smoothingSliderTrack.AbsoluteSize.X
				local handleX = smoothingSliderHandle.Position.X.Offset
				local ratio = math.clamp(handleX / (trackWidth - smoothingSliderHandle.AbsoluteSize.X), 0, 1)
				smoothingFactor = minSmooth + (maxSmooth - minSmooth) * ratio
				smoothingValueLabel.Text = string.format("%.2f", smoothingFactor)
			end
			local function updateHandleFromSmoothValue()
				local trackWidth = smoothingSliderTrack.AbsoluteSize.X
				if trackWidth == 0 then
					return
				end
				local ratio = (smoothingFactor - minSmooth) / (maxSmooth - minSmooth)
				local handleX = ratio * (trackWidth - smoothingSliderHandle.AbsoluteSize.X)
				smoothingSliderHandle.Position = UDim2.new(0, handleX, 0.5, -6)
			end
			local isDraggingSmoothSlider = false
			table.insert(
				janitor,
				smoothingSliderHandle.InputBegan:Connect(function(input)
					if input.UserInputType == Enum.UserInputType.MouseButton1 then
						isDraggingSmoothSlider = true
					end
				end)
			)
			table.insert(
				janitor,
				UserInputService.InputEnded:Connect(function(input)
					if input.UserInputType == Enum.UserInputType.MouseButton1 then
						isDraggingSmoothSlider = false
					end
				end)
			)
			table.insert(
				janitor,
				UserInputService.InputChanged:Connect(function(input)
					if isDraggingSmoothSlider and input.UserInputType == Enum.UserInputType.MouseMovement then
						local mouseX = UserInputService:GetMouseLocation().X
						local trackStartX = smoothingSliderTrack.AbsolutePosition.X
						local handleWidth = smoothingSliderHandle.AbsoluteSize.X
						local trackWidth = smoothingSliderTrack.AbsoluteSize.X
						local newHandleX = mouseX - trackStartX - (handleWidth / 2)
						local clampedX = math.clamp(newHandleX, 0, trackWidth - handleWidth)
						smoothingSliderHandle.Position = UDim2.new(0, clampedX, 0.5, -6)
						updateSmoothFromHandlePosition()
					end
				end)
			)
			task.wait()
			updateHandleFromFovValue()
			updateFovFromHandlePosition()
			updateHandleFromSmoothValue()
			updateSmoothFromHandlePosition()
			local function isTeammate(player)
				if not ignoreTeamEnabled or not player then
					return false
				end
				if LocalPlayer.Team and player.Team and LocalPlayer.Team == player.Team then
					return true
				end
				if LocalPlayer.TeamColor and player.TeamColor and LocalPlayer.TeamColor == player.TeamColor then
					return true
				end
				return false
			end
			local function isPartVisible(targetPart)
				if not LocalPlayer.Character or not targetPart or not targetPart.Parent then
					return false
				end
				local targetCharacter = targetPart:FindFirstAncestorOfClass("Model") or targetPart.Parent
				local origin = Camera.CFrame.Position
				wallCheckParams.FilterDescendantsInstances = { LocalPlayer.Character, targetCharacter }
				local result = Workspace:Raycast(origin, targetPart.Position - origin, wallCheckParams)
				return not result
			end
			local function manageESP(part, color, name)
				if not part or not part.Parent then
					return
				end
				if activeESPs[part] then
					activeESPs[part].Color3 = color
					activeESPs[part].Name = name
					activeESPs[part].Adornee = part
					activeESPs[part].Size = part.Size
				else
					local espBox = Instance.new("BoxHandleAdornment")
					espBox.Name = name
					espBox.Adornee = part
					espBox.AlwaysOnTop = true
					espBox.ZIndex = 10
					espBox.Size = part.Size
					espBox.Color3 = color
					espBox.Transparency = 0.4
					espBox.Parent = part
					activeESPs[part] = espBox
				end
			end
			local function clearESP(part)
				if part then
					if activeESPs[part] then
						activeESPs[part]:Destroy()
						activeESPs[part] = nil
					end
				else
					for _, espBox in pairs(activeESPs) do
						pcall(function()
							espBox:Destroy()
						end)
					end
					activeESPs = {}
				end
			end
			local function getClosestTargetInScope()
				local mousePos = UserInputService:GetMouseLocation()
				local minScore, closestTargetModel = math.huge, nil
				local aimPartName = partDropdown.Text
				for _, model in ipairs(getgenv().TargetIndex) do
					if model and model.Parent then
						local player = Players:GetPlayerFromCharacter(model)
						if not (player and player == LocalPlayer) and not (player and isTeammate(player)) then
							local targetPart = model:FindFirstChild(aimPartName)
							if targetPart and (not wallCheckEnabled or isPartVisible(targetPart)) then
								local pos, onScreen = Camera:WorldToViewportPoint(targetPart.Position)
								if onScreen then
									local screenDist = (Vector2.new(pos.X, pos.Y) - mousePos).Magnitude
									if screenDist <= fovRadius then
										local humanoid = model:FindFirstChildOfClass("Humanoid")
										local healthPenalty = humanoid
												and (humanoid.Health / math.max(humanoid.MaxHealth, 1)) * 10
											or 0
										local score = screenDist + healthPenalty
										if score < minScore then
											minScore = score
											closestTargetModel = model
										end
									end
								end
							end
						end
					end
				end
				return closestTargetModel
			end
			local function buildPlayerDropdownFrame()
				if playerDropdownFrame then
					playerDropdownFrame:Destroy()
				end
				local playersList = Players:GetPlayers()
				playerDropdownFrame = Instance.new("Frame", AimbotPage)
				local absolutePos = playerDropdown.AbsolutePosition
				local guiPos = MainWindow.AbsolutePosition
				playerDropdownFrame.Size = UDim2.new(0, playerDropdown.AbsoluteSize.X, 0, #playersList * 22)
				playerDropdownFrame.Position = UDim2.new(0, absolutePos.X - guiPos.X, 0, absolutePos.Y - guiPos.Y + 22)
				playerDropdownFrame.BackgroundColor3 = Color3.fromRGB(30, 30, 40)
				playerDropdownFrame.BackgroundTransparency = 0.2
				playerDropdownFrame.BorderSizePixel = 0
				playerDropdownFrame.ZIndex = 5
				makeUICorner(playerDropdownFrame, 6)
				local stroke = Instance.new("UIStroke", playerDropdownFrame)
				stroke.Color = Color3.fromRGB(80, 80, 90)
				stroke.Thickness = 1
				for i, plr in ipairs(playersList) do
					local btn = Instance.new("TextButton", playerDropdownFrame)
					btn.Size = UDim2.new(1, 0, 0, 22)
					btn.Position = UDim2.new(0, 0, 0, (i - 1) * 22)
					btn.BackgroundColor3 = Color3.fromRGB(40, 40, 40)
					btn.TextColor3 = Color3.fromRGB(255, 255, 255)
					btn.Font = Enum.Font.Code
					btn.TextSize = 15
					btn.Text = plr.Name
					makeUICorner(btn, 6)
					table.insert(
						janitor,
						btn.MouseButton1Click:Connect(function()
							selectedPlayerTarget = plr
							playerDropdown.Text = plr.Name
							if playerDropdownFrame then
								playerDropdownFrame:Destroy()
							end
							playerDropdownOpen = false
							if playerTargetEnabled then
								statusLabel.Text = "Aimbot: Will target " .. plr.Name
							end
						end)
					)
				end
			end
			table.insert(
				janitor,
				targetPlayerToggle.MouseButton1Click:Connect(function()
					playerTargetEnabled = not playerTargetEnabled
					targetPlayerToggle.Text = "Target Selected: " .. (playerTargetEnabled and "ON" or "OFF")
					if not playerTargetEnabled then
						statusLabel.Text = "Aimbot ready. Hold toggle key to aim."
					elseif selectedPlayerTarget then
						statusLabel.Text = "Aimbot: Will target " .. selectedPlayerTarget.Name
					end
				end)
			)
			table.insert(
				janitor,
				playerDropdown.MouseButton1Click:Connect(function()
					if playerDropdownOpen then
						if playerDropdownFrame then
							playerDropdownFrame:Destroy()
						end
						playerDropdownOpen = false
						return
					end
					playerDropdownOpen = true
					buildPlayerDropdownFrame()
				end)
			)
			table.insert(
				janitor,
				Players.PlayerAdded:Connect(function()
					if playerDropdownOpen then
						buildPlayerDropdownFrame()
					end
				end)
			)
			table.insert(
				janitor,
				Players.PlayerRemoving:Connect(function(plr)
					if selectedPlayerTarget == plr then
						selectedPlayerTarget = nil
						playerDropdown.Text = "None"
						if playerTargetEnabled then
							playerTargetEnabled = false
							targetPlayerToggle.Text = "Target Selected: OFF"
						end
					end
					if playerDropdownOpen then
						buildPlayerDropdownFrame()
					end
				end)
			)
			table.insert(
				janitor,
				UserInputService.InputBegan:Connect(function(input, processed)
					if processed or toggleKeyBox:IsFocused() then
						return
					end
					if input.KeyCode == Enum.KeyCode.V then
						local target = LocalPlayer:GetMouse().Target
						if target and target.Parent then
							local modelAncestor = target:FindFirstAncestorOfClass("Model")
							if
								(modelAncestor and modelAncestor == LocalPlayer.Character)
								or target:IsDescendantOf(LocalPlayer.Character)
							then
								statusLabel.Text = "Cannot delete your own character."
								return
							end
							if modelAncestor and modelAncestor ~= Workspace then
								local modelName = modelAncestor.Name
								modelAncestor:Destroy()
								statusLabel.Text = "Deleted model: " .. modelName
							else
								if target.Parent ~= Workspace then
									local targetName = target.Name
									target:Destroy()
									statusLabel.Text = "Deleted part: " .. targetName
								else
									statusLabel.Text = "Cannot delete baseplate or map."
								end
							end
						else
							statusLabel.Text = "No target under mouse to delete."
						end
					end
					local key = toggleKeyBox.Text:upper()
					if
						(key == "MOUSEBUTTON2" and input.UserInputType == Enum.UserInputType.MouseButton2)
						or (input.UserInputType == Enum.UserInputType.Keyboard and input.KeyCode.Name:upper() == key)
					then
						aiming = true
						if FovCircle then
							FovCircle.Visible = true
						end
					end
				end)
			)
			table.insert(
				janitor,
				UserInputService.InputEnded:Connect(function(input)
					local key = toggleKeyBox.Text:upper()
					if
						(key == "MOUSEBUTTON2" and input.UserInputType == Enum.UserInputType.MouseButton2)
						or (input.UserInputType == Enum.UserInputType.Keyboard and input.KeyCode.Name:upper() == key)
					then
						aiming = false
						if FovCircle then
							FovCircle.Visible = false
						end
						clearESP()
					end
				end)
			)
			local currentTarget = nil
			table.insert(
				janitor,
				RunService.RenderStepped:Connect(function(deltaTime)
					if FovCircle and FovCircle.Visible then
						FovCircle.Position = UserInputService:GetMouseLocation()
					end
					local isCurrentTargetValid = currentTarget
						and currentTarget.Parent
						and currentTarget:FindFirstChildOfClass("Humanoid")
						and currentTarget:FindFirstChildOfClass("Humanoid").Health > 0
					if aiming then
						local freshTarget = getClosestTargetInScope()
						if freshTarget then
							currentTarget = freshTarget
						elseif not isCurrentTargetValid then
							currentTarget = nil
						end
					else
						currentTarget = nil
					end
					local aimPart, targetPlayer, targetModel = nil, nil, nil
					local partsToDrawESPFor = {}
					if
						playerTargetEnabled
						and selectedPlayerTarget
						and selectedPlayerTarget.Character
						and selectedPlayerTarget ~= LocalPlayer
					then
						if not isTeammate(selectedPlayerTarget) then
							targetModel = selectedPlayerTarget.Character
							targetPlayer = selectedPlayerTarget
						else
							targetModel = nil
						end
					elseif aiming and currentTarget then
						targetModel = currentTarget
						targetPlayer = Players:GetPlayerFromCharacter(targetModel)
					end
					if targetModel then
						aimPart = targetModel:FindFirstChild(partDropdown.Text)
					end
					if aiming and aimPart and targetModel then
						if not wallCheckEnabled or isPartVisible(aimPart) then
							table.insert(
								partsToDrawESPFor,
								{ Part = aimPart, Color = Color3.fromRGB(255, 80, 80), Name = "AimbotESP" }
							)
							local velocity = aimPart.AssemblyLinearVelocity
							local distance = (Camera.CFrame.Position - aimPart.Position).Magnitude
							local travelTime = distance / math.max(PROJECTILE_SPEED, 1)
							local predictedPosition = aimPart.Position + (velocity * travelTime)
							if gravityEnabled then
								local gravity = Workspace.Gravity
								predictedPosition = predictedPosition
									+ Vector3.new(0, 0.5 * gravity * travelTime * travelTime, 0)
							end
							if smoothingEnabled then
								local SLERP_SPEED = 20
								local currentDir = Camera.CFrame.LookVector
								local goalDir = (predictedPosition - Camera.CFrame.Position).Unit
								local angle = math.acos(math.clamp(currentDir:Dot(goalDir), -1, 1))
								if angle > 0.0001 then
									local maxStep = SLERP_SPEED * deltaTime * smoothingFactor
									local t = math.min(1, maxStep / angle)
									local newDir = currentDir:Lerp(goalDir, t).Unit
									Camera.CFrame = CFrame.new(Camera.CFrame.Position, Camera.CFrame.Position + newDir)
								end
							else
								Camera.CFrame = CFrame.lookAt(Camera.CFrame.Position, predictedPosition)
							end
							statusLabel.Text = "Aimbot: Targeting "
								.. (targetPlayer and targetPlayer.Name or targetModel.Name)
						else
							statusLabel.Text = "Aimbot: Target is behind a wall"
							currentTarget = nil
						end
					elseif aiming then
						statusLabel.Text = "Aimbot: No visible target in index"
					elseif not aiming then
						statusLabel.Text = "Aimbot ready. Hold toggle key to aim."
					end
					for part, espBox in pairs(activeESPs) do
						local found = false
						for _, data in ipairs(partsToDrawESPFor) do
							if data.Part == part then
								found = true
								break
							end
						end
						if not found or not part.Parent then
							clearESP(part)
						end
					end
					for _, data in ipairs(partsToDrawESPFor) do
						manageESP(data.Part, data.Color, data.Name)
					end
				end)
			)
			table.insert(
				janitor,
				ignoreTeamToggle.MouseButton1Click:Connect(function()
					ignoreTeamEnabled = not ignoreTeamEnabled
					ignoreTeamToggle.Text = "Ignore Team: " .. (ignoreTeamEnabled and "ON" or "OFF")
				end)
			)
			table.insert(
				janitor,
				wallCheckToggle.MouseButton1Click:Connect(function()
					wallCheckEnabled = not wallCheckEnabled
					wallCheckToggle.Text = "Wall Check: " .. (wallCheckEnabled and "ON" or "OFF")
				end)
			)
			local indexerUpdateSignal = Instance.new("BindableEvent")
			table.insert(
				janitor,
				ExplorerButton.MouseButton1Click:Connect(function()
					createExplorerWindow(statusLabel, indexerUpdateSignal)
				end)
			)
			task.spawn(function()
				local function RebuildTargetIndex()
					local newIndex = {}
					if not getgenv().TargetScope or not getgenv().TargetScope.Parent then
						getgenv().TargetScope = Workspace
					end
					for _, descendant in ipairs(getgenv().TargetScope:GetDescendants()) do
						if descendant:IsA("Model") and descendant:FindFirstChildOfClass("Humanoid") then
							table.insert(newIndex, descendant)
						end
					end
					getgenv().TargetIndex = newIndex
				end
				table.insert(janitor, indexerUpdateSignal.Event:Connect(RebuildTargetIndex))
				while task.wait(2) and MainScreenGui.Parent do
					RebuildTargetIndex()
				end
			end)
			indexerUpdateSignal:Fire()
			if args and args[1] then
				task.wait(0.1)
				local targetName = args[1]
				if targetName:lower() == "clear" or targetName:lower() == "reset" or targetName:lower() == "off" then
					playerTargetEnabled = false
					selectedPlayerTarget = nil
					targetPlayerToggle.Text = "Target Selected: OFF"
					playerDropdown.Text = "None"
					statusLabel.Text = "Aimbot ready. Hold toggle key to aim."
					DoNotif("Aimbot target lock cleared.", 2)
				else
					local foundPlayer = Utilities.findPlayer(targetName)
					if foundPlayer then
						playerTargetEnabled = true
						selectedPlayerTarget = foundPlayer
						targetPlayerToggle.Text = "Target Selected: ON"
						playerDropdown.Text = foundPlayer.Name
						statusLabel.Text = "Aimbot: Will target " .. foundPlayer.Name
						DoNotif("Aimbot locked onto target: " .. foundPlayer.Name, 3)
					else
						DoNotif("Target player '" .. targetName .. "' not found.", 3)
					end
				end
			end
		end
	end)
	if not success then
		warn("Failed to load Aimbot GUI:", err)
		if DoNotif then
			DoNotif("Error loading Aimbot: " .. tostring(err), 5)
		end
		local gui = CoreGui:FindFirstChild("UTS_CGE_Suite")
		if gui then
			gui:Destroy()
		end
	end
end
RegisterCommand({
	Name = "aimbot",
	Aliases = {},
	Description = "Loads the aimbot GUI. Optional: [player name] to lock target.",
}, function(args)
	if not game:GetService("CoreGui"):FindFirstChild("UTS_CGE_Suite") then
		loadAimbotGUI(args)
	else
		if args and args[1] then
			DoNotif("Aimbot is already open. Re-open to set a command-line target.", 4)
		else
			DoNotif("Aimbot GUI is already open.", 2)
		end
	end
end)
Modules.Performance = {
	State = {
		IsEnabled = false,
		OriginalProperties = {},
		Connections = {},
	},
}
local LIGHTING_EFFECT_CLASSES = {
	"Atmosphere",
	"Clouds",
	"BloomEffect",
	"BlurEffect",
	"SunRaysEffect",
	"DepthOfFieldEffect",
	"ColorCorrectionEffect",
}
local QUALITY_LEVEL_STEP = Enum.QualityLevel.Level01
local function SaveAndDisable(instance, props)
	local saved = {}
	for _, prop in ipairs(props) do
		local ok, val = pcall(function()
			return instance[prop]
		end)
		if ok then
			saved[prop] = val
			pcall(function()
				instance[prop] = (type(val) == "boolean" and false or getattr(val))
			end)
		end
	end
	return saved
end
local function DisableParticlesIn(root, store)
	for _, obj in ipairs(root:GetDescendants()) do
		if obj:IsA("ParticleEmitter") or obj:IsA("Trail") or obj:IsA("Beam") then
			local ok, cur = pcall(function()
				return obj.Enabled
			end)
			if ok then
				store[obj] = cur
				pcall(function()
					obj.Enabled = false
				end)
			end
		end
	end
end
function Modules.Performance:Enable()
	if self.State.IsEnabled then
		return
	end
	self.State.IsEnabled = true
	self.State.OriginalProperties = {}
	local orig = self.State.OriginalProperties
	local lighting = game:GetService("Lighting")
	local terrain = workspace:FindFirstChildOfClass("Terrain")
	local matService = game:GetService("MaterialService")
	local renderSettings = settings():GetService("RenderSettings")
	orig.Lighting = {
		Technology = lighting.Technology,
		GlobalShadows = lighting.GlobalShadows,
		EnvironmentDiffuseScale = lighting.EnvironmentDiffuseScale,
		EnvironmentSpecularScale = lighting.EnvironmentSpecularScale,
	}
	pcall(function()
		lighting.Technology = Enum.Technology.Compatibility
		lighting.GlobalShadows = false
		lighting.EnvironmentDiffuseScale = 0
		lighting.EnvironmentSpecularScale = 0
	end)
	orig.LightingEffects = {}
	for _, effect in ipairs(lighting:GetChildren()) do
		for _, cls in ipairs(LIGHTING_EFFECT_CLASSES) do
			if effect:IsA(cls) then
				local ok, enabled = pcall(function()
					return effect.Enabled
				end)
				if ok then
					orig.LightingEffects[effect] = enabled
					pcall(function()
						effect.Enabled = false
					end)
				end
				break
			end
		end
	end
	if terrain then
		orig.Terrain = {
			Decoration = terrain.Decoration,
			WaterWaveSize = terrain.WaterWaveSize,
			WaterWaveSpeed = terrain.WaterWaveSpeed,
		}
		pcall(function()
			terrain.Decoration = false
			terrain.WaterWaveSize = 0
			terrain.WaterWaveSpeed = 0
		end)
	end
	local okM, curQ = pcall(function()
		return matService.MaterialQuality
	end)
	if okM then
		orig.MaterialService = { MaterialQuality = curQ }
		pcall(function()
			matService.MaterialQuality = Enum.MaterialQuality.Low
		end)
	end
	local okQ, curLevel = pcall(function()
		return renderSettings.QualityLevel
	end)
	if okQ then
		orig.QualityLevel = curLevel
		pcall(function()
			renderSettings.QualityLevel = QUALITY_LEVEL_STEP
		end)
	end
	orig.Particles = {}
	DisableParticlesIn(workspace, orig.Particles)
	self.State.Connections.ParticleAdded = workspace.DescendantAdded:Connect(function(obj)
		if obj:IsA("ParticleEmitter") or obj:IsA("Trail") or obj:IsA("Beam") then
			if self.State.OriginalProperties.Particles then
				local ok, cur = pcall(function()
					return obj.Enabled
				end)
				if ok then
					self.State.OriginalProperties.Particles[obj] = cur
					pcall(function()
						obj.Enabled = false
					end)
				end
			end
		end
	end)
	DoNotif("Performance Mode: ENABLED", 2)
end
function Modules.Performance:Disable()
	if not self.State.IsEnabled then
		return
	end
	self.State.IsEnabled = false
	for _, conn in pairs(self.State.Connections) do
		pcall(function()
			conn:Disconnect()
		end)
	end
	self.State.Connections = {}
	local orig = self.State.OriginalProperties
	local lighting = game:GetService("Lighting")
	local terrain = workspace:FindFirstChildOfClass("Terrain")
	local matService = game:GetService("MaterialService")
	local renderSettings = settings():GetService("RenderSettings")
	if orig.Lighting then
		for prop, val in pairs(orig.Lighting) do
			pcall(function()
				lighting[prop] = val
			end)
		end
	end
	if orig.LightingEffects then
		for effect, wasEnabled in pairs(orig.LightingEffects) do
			if effect and effect.Parent then
				pcall(function()
					effect.Enabled = wasEnabled
				end)
			end
		end
	end
	if terrain and orig.Terrain then
		for prop, val in pairs(orig.Terrain) do
			pcall(function()
				terrain[prop] = val
			end)
		end
	end
	if orig.MaterialService then
		for prop, val in pairs(orig.MaterialService) do
			pcall(function()
				matService[prop] = val
			end)
		end
	end
	if orig.QualityLevel then
		pcall(function()
			renderSettings.QualityLevel = orig.QualityLevel
		end)
	end
	if orig.Particles then
		for obj, wasEnabled in pairs(orig.Particles) do
			if obj and obj.Parent then
				pcall(function()
					obj.Enabled = wasEnabled
				end)
			end
		end
	end
	self.State.OriginalProperties = {}
	DoNotif("Performance Mode: DISABLED", 2)
end
function Modules.Performance:Toggle()
	if self.State.IsEnabled then
		self:Disable()
	else
		self:Enable()
	end
end
RegisterCommand({
	Name = "fpsboost",
	Aliases = { "noshadows", "performance" },
	Description = "Toggles performance mode — disables shadows, effects, particles, and steps down render quality.",
}, function()
	Modules.Performance:Toggle()
end)
Modules.Freecam = {
	State = {
		IsEnabled = false,
		Connections = {},
		Camera = nil,
		OriginalCameraType = nil,
		OriginalCFrame = nil,
	},
	Config = {
		BaseSpeed = 32,
		ShiftMultiplier = 3,
		ScrollStep = 8,
		Sensitivity = 0.35,
		SpeedMin = 4,
		SpeedMax = 512,
		SmoothFactor = 12,
	},
}
local UIS = game:GetService("UserInputService")
local RunSvc = game:GetService("RunService")
local Players = game:GetService("Players")
local KEYS = {
	Forward = Enum.KeyCode.W,
	Backward = Enum.KeyCode.S,
	Left = Enum.KeyCode.A,
	Right = Enum.KeyCode.D,
	Up = Enum.KeyCode.E,
	Down = Enum.KeyCode.Q,
	Sprint = Enum.KeyCode.LeftShift,
	SpeedUp = Enum.KeyCode.Equals,
	SpeedDown = Enum.KeyCode.Minus,
}
function Modules.Freecam:Enable()
	if self.State.IsEnabled then
		return
	end
	self.State.IsEnabled = true
	local cam = workspace.CurrentCamera
	self.State.Camera = cam
	self.State.OriginalCameraType = cam.CameraType
	self.State.OriginalCFrame = cam.CFrame
	pcall(function()
		UIS.MouseBehavior = Enum.MouseBehavior.LockCenter
	end)
	pcall(function()
		UIS.MouseIconEnabled = false
	end)
	local cfg = self.Config
	local yaw, pitch = 0, 0
	local velocity = Vector3.zero
	local currentSpeed = cfg.BaseSpeed
	local _, iY, _ = cam.CFrame:ToEulerAnglesYXZ()
	yaw = iY
	self.State.Connections.MouseMove = UIS.InputChanged:Connect(function(inp)
		if not self.State.IsEnabled then
			return
		end
		if inp.UserInputType == Enum.UserInputType.MouseMovement then
			yaw = yaw - inp.Delta.X * cfg.Sensitivity * 0.01
			pitch = math.clamp(pitch - inp.Delta.Y * cfg.Sensitivity * 0.01, math.rad(-89), math.rad(89))
		end
	end)
	self.State.Connections.Scroll = UIS.InputChanged:Connect(function(inp)
		if not self.State.IsEnabled then
			return
		end
		if inp.UserInputType == Enum.UserInputType.MouseWheel then
			currentSpeed = math.clamp(currentSpeed + inp.Position.Z * cfg.ScrollStep, cfg.SpeedMin, cfg.SpeedMax)
		end
	end)
	self.State.Connections.SpeedKey = UIS.InputBegan:Connect(function(inp, gpe)
		if gpe or not self.State.IsEnabled then
			return
		end
		if inp.KeyCode == KEYS.SpeedUp then
			currentSpeed = math.clamp(currentSpeed + cfg.ScrollStep, cfg.SpeedMin, cfg.SpeedMax)
		elseif inp.KeyCode == KEYS.SpeedDown then
			currentSpeed = math.clamp(currentSpeed - cfg.ScrollStep, cfg.SpeedMin, cfg.SpeedMax)
		end
	end)
	self.State.Connections.Render = RunSvc.RenderStepped:Connect(function(dt)
		if not self.State.IsEnabled then
			return
		end
		cam.CameraType = Enum.CameraType.Scriptable
		local speed = currentSpeed * (UIS:IsKeyDown(KEYS.Sprint) and cfg.ShiftMultiplier or 1)
		local move = Vector3.new(
			(UIS:IsKeyDown(KEYS.Right) and 1 or 0) - (UIS:IsKeyDown(KEYS.Left) and 1 or 0),
			(UIS:IsKeyDown(KEYS.Up) and 1 or 0) - (UIS:IsKeyDown(KEYS.Down) and 1 or 0),
			(UIS:IsKeyDown(KEYS.Backward) and 1 or 0) - (UIS:IsKeyDown(KEYS.Forward) and 1 or 0)
		)
		if move.Magnitude > 0 then
			move = move.Unit * speed
		end
		local rotCF = CFrame.fromEulerAnglesYXZ(pitch, yaw, 0)
		local worldMove = rotCF:VectorToWorldSpace(move)
		local alpha = 1 - math.exp(-cfg.SmoothFactor * dt)
		velocity = velocity:Lerp(worldMove, alpha)
		cam.CFrame = CFrame.new(cam.CFrame.Position + velocity * dt) * rotCF
	end)
	DoNotif("Freecam ON  —  WASD/QE · Shift sprint · Scroll speed", 3)
end
function Modules.Freecam:Disable()
	if not self.State.IsEnabled then
		return
	end
	self.State.IsEnabled = false
	for key, conn in pairs(self.State.Connections) do
		pcall(function()
			conn:Disconnect()
		end)
		self.State.Connections[key] = nil
	end
	local cam = self.State.Camera or workspace.CurrentCamera
	pcall(function()
		cam.CameraType = self.State.OriginalCameraType or Enum.CameraType.Custom
	end)
	pcall(function()
		UIS.MouseBehavior = Enum.MouseBehavior.Default
	end)
	pcall(function()
		UIS.MouseIconEnabled = true
	end)
	local char = Players.LocalPlayer and Players.LocalPlayer.Character
	local hrp = char and char:FindFirstChild("HumanoidRootPart")
	if hrp then
		pcall(function()
			cam.CFrame = CFrame.new(hrp.Position + Vector3.new(0, 2, 8), hrp.Position)
		end)
	elseif self.State.OriginalCFrame then
		pcall(function()
			cam.CFrame = self.State.OriginalCFrame
		end)
	end
	self.State.Camera = nil
	self.State.OriginalCFrame = nil
	DoNotif("Freecam OFF", 2)
end
function Modules.Freecam:Toggle()
	if self.State.IsEnabled then
		self:Disable()
	else
		self:Enable()
	end
end
function Modules.Freecam:SetSpeed(n)
	self.Config.BaseSpeed = math.clamp(tonumber(n) or 32, self.Config.SpeedMin, self.Config.SpeedMax)
	DoNotif(("Freecam speed: %d"):format(self.Config.BaseSpeed), 2)
end
function Modules.Freecam:Initialize()
	local module = self
	RegisterCommand({
		Name = "freecam",
		Aliases = { "fc" },
		Description = "Free camera — WASD/QE move, Shift sprint, Scroll/+- speed.",
	}, function()
		module:Toggle()
	end)
	RegisterCommand({
		Name = "fcspeed",
		Aliases = { "freecamspeed" },
		Description = "Set freecam base speed. Usage: ;fcspeed <number>",
	}, function(args)
		module:SetSpeed(args[1])
	end)
end
RegisterCommand({
	Name = "desync",
	Aliases = { "psync" },
	Description = "Zukas Desync.",
	ArgsDesc = {},
	Permissions = {},
}, function(args, speaker)
	local TOGGLE_KEY = Enum.KeyCode.End
	local SPAWN_PROTECTION_DURATION = 2
	local Players = game:GetService("Players")
	local UserInputService = game:GetService("UserInputService")
	local Workspace = game:GetService("Workspace")
	local StarterGui = game:GetService("StarterGui")
	local RunService = game:GetService("RunService")
	local LocalPlayer = Players.LocalPlayer
	local function DoNotif(msg, duration)
		pcall(function()
			StarterGui:SetCore("SendNotification", {
				Title = "Zuka Says:",
				Text = msg,
				Duration = duration or 1.5,
			})
		end)
	end
	local State = {
		isProjecting = false,
		isSpawning = false,
		originalHRP = nil,
		originalParent = nil,
		deathConnection = nil,
		positionMarker = nil,
	}
	local PLAYER_GUI = LocalPlayer:WaitForChild("PlayerGui")
	local screenGui = Instance.new("ScreenGui")
	screenGui.Name = "TopBarPlus"
	screenGui.ResetOnSpawn = false
	screenGui.Parent = PLAYER_GUI
	local TopBarPlus = Instance.new("TextButton")
	TopBarPlus.Name = "TopBarToggle"
	TopBarPlus.Size = UDim2.fromOffset(64, 64)
	TopBarPlus.AnchorPoint = Vector2.new(1, 1)
	TopBarPlus.Position = UDim2.new(1, -20, 1, -100)
	TopBarPlus.Font = Enum.Font.GothamBold
	TopBarPlus.BackgroundTransparency = 0.5
	TopBarPlus.Text = "Sync"
	TopBarPlus.TextSize = 14
	TopBarPlus.Parent = screenGui
	Instance.new("UICorner", TopBarPlus).CornerRadius = UDim.new(1, 0)
	local stroke = Instance.new("UIStroke", TopBarPlus)
	stroke.Color = Color3.fromRGB(100, 100, 120)
	stroke.Thickness = 1.5
	local function updateUIState()
		if State.isSpawning then
			TopBarPlus.BackgroundColor3 = Color3.fromRGB(255, 160, 0)
			TopBarPlus.TextColor3 = Color3.fromRGB(255, 255, 255)
		elseif State.isProjecting then
			TopBarPlus.BackgroundColor3 = Color3.fromRGB(0, 200, 255)
			TopBarPlus.TextColor3 = Color3.fromRGB(10, 10, 10)
		else
			TopBarPlus.BackgroundColor3 = Color3.fromRGB(40, 40, 50)
			TopBarPlus.TextColor3 = Color3.fromRGB(200, 200, 220)
		end
	end
	local function applyVisuals(character, isAstral)
		local highlight = character:FindFirstChild("AstralHighlight")
		if isAstral and not highlight then
			highlight = Instance.new("Highlight", character)
			highlight.Name = "AstralHighlight"
			highlight.FillColor = Color3.fromRGB(0, 200, 255)
			highlight.OutlineColor = Color3.fromRGB(200, 255, 255)
			highlight.FillTransparency = 0.5
		elseif not isAstral and highlight then
			highlight:Destroy()
		end
	end
	local function setState(shouldProject)
		if State.isSpawning then
			return
		end
		if State.isProjecting == shouldProject then
			return
		end
		local character = LocalPlayer.Character
		if not character then
			return
		end
		local hrp = character:FindFirstChild("HumanoidRootPart")
		local humanoid = character:FindFirstChildOfClass("Humanoid")
		if shouldProject then
			if not hrp or not humanoid then
				return
			end
			State.originalHRP = hrp
			State.originalParent = character
			local originalCFrame = hrp.CFrame
			hrp.Parent = nil
			State.isProjecting = true
			if State.positionMarker then
				State.positionMarker:Destroy()
			end
			local marker = Instance.new("Part")
			marker.Name = "PhysicalAnchor"
			marker.Size = Vector3.new(4, 5, 2)
			marker.CFrame = originalCFrame
			marker.Anchored = false
			marker.CanCollide = false
			marker.Transparency = 0.9
			marker.Parent = Workspace
			State.positionMarker = marker
			local hl = Instance.new("Highlight", marker)
			hl.FillColor = Color3.fromRGB(255, 50, 50)
			hl.OutlineColor = Color3.fromRGB(255, 255, 255)
			hl.FillTransparency = 0.6
			humanoid:ChangeState(Enum.HumanoidStateType.Running)
			applyVisuals(character, true)
			DoNotif("ENABLED", 1.5)
		else
			if State.positionMarker then
				State.positionMarker:Destroy()
				State.positionMarker = nil
			end
			if State.originalHRP and State.originalParent then
				State.originalHRP.Parent = State.originalParent
			end
			State.originalHRP = nil
			State.originalParent = nil
			State.isProjecting = false
			applyVisuals(character, false)
			DoNotif("DISABLED", 1.5)
		end
		updateUIState()
	end
	local function makeDraggable(guiObject)
		local dragging, dragStart, startPos
		guiObject.InputBegan:Connect(function(input)
			if
				input.UserInputType == Enum.UserInputType.MouseButton1
				or input.UserInputType == Enum.UserInputType.Touch
			then
				dragging = true
				dragStart = input.Position
				startPos = guiObject.Position
			end
		end)
		UserInputService.InputChanged:Connect(function(input)
			if
				dragging
				and (
					input.UserInputType == Enum.UserInputType.MouseMovement
					or input.UserInputType == Enum.UserInputType.Touch
				)
			then
				local delta = input.Position - dragStart
				guiObject.Position = UDim2.new(
					startPos.X.Scale,
					startPos.X.Offset + delta.X,
					startPos.Y.Scale,
					startPos.Y.Offset + delta.Y
				)
			end
		end)
		UserInputService.InputEnded:Connect(function(input)
			if
				input.UserInputType == Enum.UserInputType.MouseButton1
				or input.UserInputType == Enum.UserInputType.Touch
			then
				dragging = false
			end
		end)
	end
	local function onCharacterAdded(character)
		State.isSpawning = true
		updateUIState()
		if State.isProjecting then
			setState(false)
		end
		if State.deathConnection then
			State.deathConnection:Disconnect()
		end
		local humanoid = character:WaitForChild("Humanoid")
		State.deathConnection = humanoid.Died:Connect(function()
			setState(false)
		end)
		task.wait(SPAWN_PROTECTION_DURATION)
		State.isSpawning = false
		updateUIState()
	end
	makeDraggable(TopBarPlus)
	TopBarPlus.MouseButton1Click:Connect(function()
		setState(not State.isProjecting)
	end)
	UserInputService.InputBegan:Connect(function(input, gp)
		if gp then
			return
		end
		if input.KeyCode == TOGGLE_KEY then
			setState(not State.isProjecting)
		end
	end)
	if LocalPlayer.Character then
		task.spawn(onCharacterAdded, LocalPlayer.Character)
	end
	LocalPlayer.CharacterAdded:Connect(onCharacterAdded)
	RunService.Heartbeat:Connect(function()
		if State.isProjecting and State.originalHRP and State.originalHRP.Parent ~= nil then
			State.originalHRP.Parent = nil
		end
	end)
end)
Modules.AnchorSelf = {
	State = {
		IsEnabled = false,
		CharacterAddedConnection = nil,
	},
}
function Modules.AnchorSelf:Enable()
	if self.State.IsEnabled then
		return
	end
	self.State.IsEnabled = true
	local function applyAnchor(character)
		if not character then
			return
		end
		local hrp = character:WaitForChild("HumanoidRootPart", 2)
		if hrp then
			hrp.Anchored = true
		end
	end
	if LocalPlayer.Character then
		applyAnchor(LocalPlayer.Character)
	end
	self.State.CharacterAddedConnection = LocalPlayer.CharacterAdded:Connect(applyAnchor)
	DoNotif("Self Anchor: ENABLED.", 2)
end
function Modules.AnchorSelf:Disable()
	if not self.State.IsEnabled then
		return
	end
	self.State.IsEnabled = false
	if LocalPlayer.Character then
		local hrp = LocalPlayer.Character:FindFirstChild("HumanoidRootPart")
		if hrp then
			hrp.Anchored = false
		end
	end
	if self.State.CharacterAddedConnection then
		self.State.CharacterAddedConnection:Disconnect()
		self.State.CharacterAddedConnection = nil
	end
	DoNotif("Self Anchor: DISABLED.", 2)
end
function Modules.AnchorSelf:Toggle()
	if self.State.IsEnabled then
		self:Disable()
	else
		self:Enable()
	end
end
RegisterCommand(
	{ Name = "anchor", Aliases = { "lock", "lockpos" }, Description = "Toggles anchoring your character in place." },
	function()
		Modules.AnchorSelf:Toggle()
	end
)
Modules.AutoComplete = {}
function Modules.AutoComplete:GetMatches(prefix)
	local matches = {}
	if typeof(prefix) ~= "string" or #prefix == 0 then
		return matches
	end
	prefix = prefix:lower()
	for cmdName, _ in pairs(Commands) do
		if cmdName:sub(1, #prefix) == prefix then
			table.insert(matches, cmdName)
		end
	end
	table.sort(matches)
	return matches
end
Modules.CommandList = {
	State = {
		UI = nil,
		IsEnabled = false,
		IsMinimized = false,
		IsAnimating = false,
	},
}
function Modules.CommandList:Initialize()
	local self = self
	local ui = Instance.new("ScreenGui")
	ui.Name = "CommandListUI_v7_Radiant"
	ui.ResetOnSpawn = false
	ui.ZIndexBehavior = Enum.ZIndexBehavior.Global
	ui.Enabled = false
	self.State.UI = ui
	local mainFrame = Instance.new("Frame")
	mainFrame.Name = "MainFrame"
	mainFrame.Size = UDim2.fromOffset(450, 350)
	mainFrame.AnchorPoint = Vector2.new(0.5, 0.5)
	mainFrame.Position = UDim2.fromScale(0.5, 0.5)
	mainFrame.BackgroundColor3 = Color3.fromRGB(34, 32, 38)
	mainFrame.BackgroundTransparency = 0.1
	mainFrame.BorderSizePixel = 0
	mainFrame.ClipsDescendants = true
	mainFrame.Parent = ui
	Instance.new("UICorner", mainFrame).CornerRadius = UDim.new(0, 8)
	local uiStroke = Instance.new("UIStroke", mainFrame)
	uiStroke.Color = Color3.fromRGB(255, 105, 180)
	uiStroke.Thickness = 2
	local glowConnection
	glowConnection = RunService.RenderStepped:Connect(function()
		if not (uiStroke and uiStroke.Parent) then
			glowConnection:Disconnect()
			return
		end
		local sine = math.sin(os.clock() * 4)
		uiStroke.Thickness = 2 + (sine * 0.5)
		uiStroke.Transparency = 0.3 + (sine * 0.2)
	end)
	local canvasGroup = Instance.new("CanvasGroup", mainFrame)
	canvasGroup.Name = "Canvas"
	canvasGroup.Size = UDim2.fromScale(1, 1)
	canvasGroup.BackgroundTransparency = 1
	canvasGroup.GroupTransparency = 1
	local title = Instance.new("TextLabel", canvasGroup)
	title.Name = "Title"
	title.Size = UDim2.new(1, 0, 0, 40)
	title.BackgroundTransparency = 1
	title.Font = Enum.Font.GothamSemibold
	title.Text = "Command List"
	title.TextColor3 = Color3.fromRGB(255, 182, 193)
	title.TextSize = 20
	local closeButton = Instance.new("TextButton", canvasGroup)
	closeButton.Name = "CloseButton"
	closeButton.Size = UDim2.fromOffset(25, 25)
	closeButton.AnchorPoint = Vector2.new(1, 0)
	closeButton.Position = UDim2.new(1, -10, 0, 10)
	closeButton.BackgroundTransparency = 1
	closeButton.Font = Enum.Font.GothamBold
	closeButton.Text = "X"
	closeButton.TextColor3 = Color3.fromRGB(255, 255, 255)
	closeButton.TextSize = 20
	closeButton.MouseButton1Click:Connect(function()
		self:Toggle()
	end)
	local minimizeButton = Instance.new("TextButton", canvasGroup)
	minimizeButton.Name = "MinimizeButton"
	minimizeButton.Size = UDim2.fromOffset(25, 25)
	minimizeButton.AnchorPoint = Vector2.new(1, 0)
	minimizeButton.Position = UDim2.new(1, -40, 0, 10)
	minimizeButton.BackgroundTransparency = 1
	minimizeButton.Font = Enum.Font.GothamBold
	minimizeButton.Text = "-"
	minimizeButton.TextColor3 = Color3.fromRGB(255, 255, 255)
	minimizeButton.TextSize = 24
	local scrollingFrame = Instance.new("ScrollingFrame", canvasGroup)
	scrollingFrame.Name = "ScrollingFrame"
	scrollingFrame.Size = UDim2.new(1, -20, 1, -50)
	scrollingFrame.Position = UDim2.fromOffset(10, 40)
	scrollingFrame.BackgroundTransparency = 1
	scrollingFrame.BorderSizePixel = 0
	scrollingFrame.ScrollBarThickness = 6
	scrollingFrame.ScrollBarImageColor3 = Color3.fromRGB(255, 105, 180)
	local listLayout = Instance.new("UIListLayout", scrollingFrame)
	listLayout.Padding = UDim.new(0, 5)
	local function drag(input)
		local dragStart = input.Position
		local startPos = mainFrame.Position
		local moveConn, endConn
		moveConn = UserInputService.InputChanged:Connect(function(moveInput)
			if moveInput.UserInputType == Enum.UserInputType.MouseMovement then
				local delta = moveInput.Position - dragStart
				mainFrame.Position = UDim2.new(
					startPos.X.Scale,
					startPos.X.Offset + delta.X,
					startPos.Y.Scale,
					startPos.Y.Offset + delta.Y
				)
			end
		end)
		endConn = UserInputService.InputEnded:Connect(function(endInput)
			if endInput.UserInputType == Enum.UserInputType.MouseButton1 then
				moveConn:Disconnect()
				endConn:Disconnect()
			end
		end)
	end
	title.InputBegan:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1 then
			drag(input)
		end
	end)
	local tweenInfo = TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.Out)
	minimizeButton.MouseButton1Click:Connect(function()
		self.State.IsMinimized = not self.State.IsMinimized
		local goalSize
		if self.State.IsMinimized then
			goalSize = UDim2.fromOffset(mainFrame.AbsoluteSize.X, 40)
			minimizeButton.Text = "+"
			scrollingFrame.Visible = false
		else
			goalSize = UDim2.fromOffset(mainFrame.AbsoluteSize.X, 350)
			minimizeButton.Text = "-"
			scrollingFrame.Visible = true
		end
		TweenService:Create(mainFrame, tweenInfo, { Size = goalSize }):Play()
	end)
	ui.Parent = CoreGui
end
function Modules.CommandList:Populate()
	local scrollingFrame = self.State.UI.MainFrame.Canvas:FindFirstChild("ScrollingFrame")
	if not scrollingFrame then
		return
	end
	scrollingFrame:ClearAllChildren()
	local listLayout = Instance.new("UIListLayout", scrollingFrame)
	listLayout.Padding = UDim.new(0, 8)
	listLayout:GetPropertyChangedSignal("AbsoluteContentSize"):Connect(function()
		scrollingFrame.CanvasSize = UDim2.fromOffset(0, listLayout.AbsoluteContentSize.Y)
	end)
	table.sort(CommandInfo, function(a, b)
		return a.Name < b.Name
	end)
	for _, info in ipairs(CommandInfo) do
		local entryFrame = Instance.new("Frame")
		entryFrame.Name = info.Name .. "_Entry"
		entryFrame.BackgroundTransparency = 0.8
		entryFrame.BackgroundColor3 = Color3.fromRGB(20, 20, 25)
		entryFrame.Size = UDim2.new(1, 0, 0, 0)
		entryFrame.AutomaticSize = Enum.AutomaticSize.Y
		entryFrame.Parent = scrollingFrame
		Instance.new("UICorner", entryFrame).CornerRadius = UDim.new(0, 6)
		local frameLayout = Instance.new("UIListLayout", entryFrame)
		frameLayout.Padding = UDim.new(0, 5)
		local framePadding = Instance.new("UIPadding", entryFrame)
		framePadding.PaddingLeft = UDim.new(0, 10)
		framePadding.PaddingRight = UDim.new(0, 10)
		framePadding.PaddingTop = UDim.new(0, 8)
		framePadding.PaddingBottom = UDim.new(0, 8)
		local entry = Instance.new("TextLabel")
		entry.Name = info.Name
		entry.Size = UDim2.new(1, 0, 0, 0)
		entry.AutomaticSize = Enum.AutomaticSize.Y
		entry.BackgroundTransparency = 1
		entry.Font = Enum.Font.Gotham
		entry.TextSize = 15
		entry.RichText = true
		entry.TextXAlignment = Enum.TextXAlignment.Left
		entry.TextWrapped = true
		entry.Parent = entryFrame
		local aliases = ""
		if info.Aliases and #info.Aliases > 0 then
			aliases =
				string.format("<font size='12' color='#AAAAAA'><i>(%s)</i></font>", table.concat(info.Aliases, ", "))
		end
		local description = info.Description or "No description provided."
		entry.Text = string.format(
			"<font face='GothamBold' color='#FF69B4'>;%s</font> %s\n<font face='Gotham' size='13' color='#E0E0E0'>  %s</font>",
			info.Name,
			aliases,
			description
		)
	end
end
function Modules.CommandList:Toggle()
	if self.State.IsAnimating then
		return
	end
	self.State.IsAnimating = true
	self.State.IsEnabled = not self.State.IsEnabled
	local mainFrame = self.State.UI.MainFrame
	local canvasGroup = mainFrame.Canvas
	local tweenInfo = TweenInfo.new(0.3, Enum.EasingStyle.Quint, Enum.EasingDirection.Out)
	if self.State.IsEnabled then
		self.State.UI.Enabled = true
		if self.State.IsMinimized then
			self.State.IsMinimized = false
			mainFrame.Size = UDim2.fromOffset(450, 350)
			mainFrame.Canvas.ScrollingFrame.Visible = true
			mainFrame.Canvas.MinimizeButton.Text = "-"
		end
		self:Populate()
		mainFrame.Size = UDim2.fromOffset(450, 320)
		canvasGroup.GroupTransparency = 1
		local sizeAnim = TweenService:Create(mainFrame, tweenInfo, { Size = UDim2.fromOffset(450, 350) })
		local fadeAnim = TweenService:Create(canvasGroup, tweenInfo, { GroupTransparency = 0 })
		sizeAnim:Play()
		fadeAnim:Play()
		fadeAnim.Completed:Connect(function()
			self.State.IsAnimating = false
		end)
	else
		local sizeAnim = TweenService:Create(mainFrame, tweenInfo, { Size = UDim2.fromOffset(450, 320) })
		local fadeAnim = TweenService:Create(canvasGroup, tweenInfo, { GroupTransparency = 1 })
		sizeAnim:Play()
		fadeAnim:Play()
		fadeAnim.Completed:Connect(function()
			self.State.UI.Enabled = false
			self.State.IsAnimating = false
		end)
	end
end
local TweenService = game:GetService("TweenService")
local RunService = game:GetService("RunService")
local function RainbowOutline(frame, thickness, speed, recolorText)
	thickness = thickness or 2
	speed = speed or 1
	local stroke = Instance.new("UIStroke", frame)
	stroke.Thickness = thickness
	stroke.ApplyStrokeMode = Enum.ApplyStrokeMode.Border
	local hue = 0
	local conn = RunService.Heartbeat:Connect(function(dt)
		hue = (hue + dt * speed * 0.2) % 1
		local color = Color3.fromHSV(hue, 1, 1)
		stroke.Color = color
		if recolorText then
			for _, v in ipairs(frame:GetDescendants()) do
				if v:IsA("TextLabel") or v:IsA("TextButton") or v:IsA("TextBox") then
					v.TextColor3 = color
				end
			end
		end
	end)
	stroke.AncestryChanged:Connect(function()
		if not stroke.Parent then
			conn:Disconnect()
		end
	end)
	return stroke, conn
end
local function PulseOutline(frame, color, thickness, speed)
	color = color or Color3.fromRGB(0, 200, 255)
	thickness = thickness or 2
	speed = speed or 1.5
	local stroke = Instance.new("UIStroke", frame)
	stroke.Color = color
	stroke.Thickness = thickness
	stroke.ApplyStrokeMode = Enum.ApplyStrokeMode.Border
	local function pulse()
		TweenService:Create(stroke, TweenInfo.new(speed * 0.5, Enum.EasingStyle.Sine), {
			Thickness = thickness * 3,
			Transparency = 0.6,
		}):Play()
		task.wait(speed * 0.5)
		TweenService:Create(stroke, TweenInfo.new(speed * 0.5, Enum.EasingStyle.Sine), {
			Thickness = thickness,
			Transparency = 0,
		}):Play()
		task.wait(speed * 0.5)
	end
	local running = true
	local thread = task.spawn(function()
		while running do
			pulse()
		end
	end)
	stroke.AncestryChanged:Connect(function()
		if not stroke.Parent then
			running = false
		end
	end)
	return stroke
end
local function GlowOutline(frame, color, thickness)
	color = color or Color3.fromRGB(200, 0, 255)
	thickness = thickness or 3
	local glow = Instance.new("UIStroke", frame)
	glow.Color = color
	glow.Thickness = thickness * 3
	glow.Transparency = 0.7
	glow.ApplyStrokeMode = Enum.ApplyStrokeMode.Border
	local inner = Instance.new("UIStroke", frame)
	inner.Color = color
	inner.Thickness = thickness
	inner.Transparency = 0
	inner.ApplyStrokeMode = Enum.ApplyStrokeMode.Border
	local function glowPulse()
		TweenService:Create(glow, TweenInfo.new(1.2, Enum.EasingStyle.Sine, Enum.EasingDirection.InOut), {
			Transparency = 0.4,
		}):Play()
		task.wait(1.2)
		TweenService:Create(glow, TweenInfo.new(1.2, Enum.EasingStyle.Sine, Enum.EasingDirection.InOut), {
			Transparency = 0.8,
		}):Play()
		task.wait(1.2)
	end
	local running = true
	task.spawn(function()
		while running do
			glowPulse()
		end
	end)
	glow.AncestryChanged:Connect(function()
		if not glow.Parent then
			running = false
		end
	end)
	return inner, glow
end
