Modules.Fling = {
	State = {
		IsFlinging = false,
		OldPos = nil,
		WelcomeDone = false,
		FPDH = workspace.FallenPartsDestroyHeight,
	},
	Config = {
		Whitelist = { 20460194 },
		FlingWaitTime = 2,
		Power = 9e7,
	},
	Services = {
		Players = game:GetService("Players"),
		RunService = game:GetService("RunService"),
		StarterGui = game:GetService("StarterGui"),
	},
}
function Modules.Fling:Notify(title, text, duration)
	self.Services.StarterGui:SetCore("SendNotification", {
		Title = title,
		Text = text,
		Duration = duration or 5,
	})
end
function Modules.Fling:GetTarget(Name)
	local Players = self.Services.Players
	local LocalPlayer = Players.LocalPlayer
	Name = Name:lower()
	if Name == "all" or Name == "others" then
		local targets = {}
		for _, p in ipairs(Players:GetPlayers()) do
			if p ~= LocalPlayer then
				table.insert(targets, p)
			end
		end
		return targets
	elseif Name == "random" then
		local pList = Players:GetPlayers()
		table.remove(pList, table.find(pList, LocalPlayer))
		return { pList[math.random(#pList)] }
	else
		for _, p in ipairs(Players:GetPlayers()) do
			if p ~= LocalPlayer and (p.Name:lower():find(Name) or p.DisplayName:lower():find(Name)) then
				return { p }
			end
		end
	end
	return nil
end
function Modules.Fling:SkidFling(TargetPlayer)
	local Player = self.Services.Players.LocalPlayer
	local Character = Player.Character
	local Humanoid = Character and Character:FindFirstChildOfClass("Humanoid")
	local RootPart = Humanoid and Humanoid.RootPart
	local TCharacter = TargetPlayer.Character
	if not TCharacter or not TCharacter:FindFirstChildOfClass("Humanoid") then
		return
	end
	local THumanoid = TCharacter:FindFirstChildOfClass("Humanoid")
	local TRootPart = THumanoid.RootPart
	local THead = TCharacter:FindFirstChild("Head")
	if Character and Humanoid and RootPart then
		if RootPart.Velocity.Magnitude < 50 then
			self.State.OldPos = RootPart.CFrame
		end
		workspace.CurrentCamera.CameraSubject = THead or TRootPart or THumanoid
		local function FPos(BasePart, Pos, Ang)
			RootPart.CFrame = CFrame.new(BasePart.Position) * Pos * Ang
			Character:SetPrimaryPartCFrame(CFrame.new(BasePart.Position) * Pos * Ang)
			RootPart.Velocity = Vector3.new(self.Config.Power, self.Config.Power * 10, self.Config.Power)
			RootPart.RotVelocity = Vector3.new(self.Config.Power * 10, self.Config.Power * 10, self.Config.Power * 10)
		end
		local function SFBasePart(BasePart)
			local Time = tick()
			local Angle = 0
			repeat
				if RootPart and THumanoid then
					Angle = Angle + 100
					FPos(
						BasePart,
						CFrame.new(0, 1.5, 0) + THumanoid.MoveDirection * BasePart.Velocity.Magnitude / 1.25,
						CFrame.Angles(math.rad(Angle), 0, 0)
					)
					task.wait()
				else
					break
				end
			until BasePart.Velocity.Magnitude > 500 or tick() > Time + self.Config.FlingWaitTime
		end
		workspace.FallenPartsDestroyHeight = 0 / 0
		Humanoid:SetStateEnabled(Enum.HumanoidStateType.Seated, false)
		if TRootPart then
			SFBasePart(TRootPart)
		elseif THead then
			SFBasePart(THead)
		end
		Humanoid:SetStateEnabled(Enum.HumanoidStateType.Seated, true)
		workspace.CurrentCamera.CameraSubject = Humanoid
		repeat
			RootPart.CFrame = self.State.OldPos * CFrame.new(0, 0.5, 0)
			Character:SetPrimaryPartCFrame(self.State.OldPos * CFrame.new(0, 0.5, 0))
			Humanoid:ChangeState("GettingUp")
			for _, v in ipairs(Character:GetChildren()) do
				if v:IsA("BasePart") then
					v.Velocity, v.RotVelocity = Vector3.new(), Vector3.new()
				end
			end
			task.wait()
		until (RootPart.Position - self.State.OldPos.p).Magnitude < 10
		workspace.FallenPartsDestroyHeight = self.State.FPDH
	end
end
function Modules.Fling:Initialize()
	local module = self
	if not self.State.WelcomeDone then
		self:Notify("Flinger", "Working", 1)
		self.State.WelcomeDone = true
	end
	RegisterCommand({
		Name = "fling",
		Aliases = { "ff" },
		Description = "Flings a target player using physics manipulation.",
	}, function(args)
		local targetName = args[1] or ""
		local targets = module:GetTarget(targetName)
		if targets then
			for _, p in ipairs(targets) do
				if table.find(module.Config.Whitelist, p.UserId) then
					module:Notify("Error", p.Name .. " is whitelisted.", 5)
				else
					module:SkidFling(p)
				end
			end
		else
			module:Notify("Error", "Target not found.", 5)
		end
	end)
end
Modules.FlingProtection = {
	State = {
		IsEnabled = false,
		SteppedConnection = nil,
		PlayerConnections = {},
	},
	Config = {
		MAX_VELOCITY_MAGNITUDE = 200,
		LOCAL_PLAYER_GROUP = "LocalPlayerCollisionGroup",
		OTHER_PLAYERS_GROUP = "OtherPlayersCollisionGroup",
	},
}
function Modules.FlingProtection:_setCollisionGroupForCharacter(character, groupName)
	if not character then
		return
	end
	for _, part in ipairs(character:GetDescendants()) do
		if part:IsA("BasePart") then
			pcall(function()
				part.CollisionGroup = groupName
			end)
		end
	end
end
function Modules.FlingProtection:_setupPlayerCollisions()
	local PhysicsService = game:GetService("PhysicsService")
	pcall(function()
		PhysicsService:CreateCollisionGroup(self.Config.LOCAL_PLAYER_GROUP)
	end)
	pcall(function()
		PhysicsService:CreateCollisionGroup(self.Config.OTHER_PLAYERS_GROUP)
	end)
	PhysicsService:CollisionGroupSetCollidable(self.Config.LOCAL_PLAYER_GROUP, self.Config.OTHER_PLAYERS_GROUP, false)
	for _, player in ipairs(Players:GetPlayers()) do
		local group = (player == LocalPlayer) and self.Config.LOCAL_PLAYER_GROUP or self.Config.OTHER_PLAYERS_GROUP
		if player.Character then
			self:_setCollisionGroupForCharacter(player.Character, group)
		end
		local conn = player.CharacterAdded:Connect(function(character)
			self:_setCollisionGroupForCharacter(character, group)
		end)
		table.insert(self.State.PlayerConnections, conn)
	end
	local conn = Players.PlayerAdded:Connect(function(player)
		local group = self.Config.OTHER_PLAYERS_GROUP
		local charConn = player.CharacterAdded:Connect(function(character)
			self:_setCollisionGroupForCharacter(character, group)
		end)
		table.insert(self.State.PlayerConnections, charConn)
	end)
	table.insert(self.State.PlayerConnections, conn)
end
function Modules.FlingProtection:_revertPlayerCollisions()
	for _, conn in ipairs(self.State.PlayerConnections) do
		conn:Disconnect()
	end
	self.State.PlayerConnections = {}
	for _, player in ipairs(Players:GetPlayers()) do
		if player.Character then
			self:_setCollisionGroupForCharacter(player.Character, "Default")
		end
	end
end
function Modules.FlingProtection:_enforceStability()
	local hrp = LocalPlayer.Character and LocalPlayer.Character:FindFirstChild("HumanoidRootPart")
	if not (hrp and not hrp.Anchored) then
		return
	end
	if hrp.AssemblyLinearVelocity.Magnitude > self.Config.MAX_VELOCITY_MAGNITUDE then
		hrp.AssemblyLinearVelocity = Vector3.zero
	end
end
function Modules.FlingProtection:Toggle()
	self.State.IsEnabled = not self.State.IsEnabled
	if self.State.IsEnabled then
		DoNotif("Fling & Player Collision Protection: ENABLED", 2)
		self:_setupPlayerCollisions()
		self.State.SteppedConnection = RunService.Stepped:Connect(function()
			self:_enforceStability()
		end)
	else
		DoNotif("Fling & Player Collision Protection: DISABLED", 2)
		self:_revertPlayerCollisions()
		if self.State.SteppedConnection then
			self.State.SteppedConnection:Disconnect()
			self.State.SteppedConnection = nil
		end
	end
end
do
	local ATTR_OG_SIZE = "Zuka_OriginalSize"
	local SEL_BOX_NAME = "Zuka_ReachSelectionBox"
	local TweenService = game:GetService("TweenService")
	local UserInputService = game:GetService("UserInputService")
	local activeTool: Tool? = nil
	local modifiedPart: BasePart? = nil
	local persistentToolName: string? = nil
	local persistentPartName: string? = nil
	local currentReachSize: number = 20
	local currentReachType: string = "directional"
	local function tween(obj, props, t, style, dir)
		style = style or Enum.EasingStyle.Quad
		dir = dir or Enum.EasingDirection.Out
		TweenService:Create(obj, TweenInfo.new(t or 0.15, style, dir), props):Play()
	end
	local function applyPart(part: BasePart, size: number?, reachType: string?)
		if not part or not part.Parent then
			return
		end
		if not size then
			local og = part:GetAttribute(ATTR_OG_SIZE)
			if og then
				part.Size = og
				part:SetAttribute(ATTR_OG_SIZE, nil)
			end
			local sb = part:FindFirstChild(SEL_BOX_NAME)
			if sb then
				sb:Destroy()
			end
			return
		end
		if not part:GetAttribute(ATTR_OG_SIZE) then
			part:SetAttribute(ATTR_OG_SIZE, part.Size)
		end
		local sb = part:FindFirstChild(SEL_BOX_NAME)
		if not sb then
			sb = Instance.new("SelectionBox")
			sb.Name = SEL_BOX_NAME
			sb.Adornee = part
			sb.LineThickness = 0.025
			sb.Parent = part
		end
		sb.Color3 = reachType == "box" and Color3.fromRGB(30, 140, 255) or Color3.fromRGB(255, 60, 60)
		if reachType == "box" then
			part.Size = Vector3.one * size
		else
			part.Size = Vector3.new(part.Size.X, part.Size.Y, size)
		end
		part.Massless = true
	end
	local function resetReach()
		if modifiedPart then
			applyPart(modifiedPart, nil, nil)
			modifiedPart = nil
		end
		persistentToolName, persistentPartName = nil, nil
	end
	local function makeConnManager()
		local m = { _c = {} }
		function m:add(key, conn)
			if self._c[key] then
				self._c[key]:Disconnect()
			end
			self._c[key] = conn
		end
		function m:disconnect(key)
			if self._c[key] then
				self._c[key]:Disconnect()
				self._c[key] = nil
			end
		end
		function m:clean()
			for _, c in pairs(self._c) do
				c:Disconnect()
			end
			table.clear(self._c)
		end
		return m
	end
	Modules.ReachController = {
		State = {
			IsEnabled = false,
			UI = nil,
		},
	}
	function Modules.ReachController:Enable()
		if self.State.IsEnabled then
			return
		end
		self.State.IsEnabled = true
		local conns = makeConnManager()
		self._conns = conns
		local ui = Instance.new("ScreenGui")
		ui.Name = "ReachController_Zuka"
		ui.ZIndexBehavior = Enum.ZIndexBehavior.Global
		ui.ResetOnSpawn = false
		self.State.UI = ui
		local W, H_FULL, H_MIN = 260, 340, 32
		local isCollapsed = false
		local frame = Instance.new("Frame", ui)
		frame.Size = UDim2.fromOffset(W, H_FULL)
		frame.Position = UDim2.fromScale(0, 0)
		frame.BackgroundColor3 = Color3.fromRGB(12, 12, 18)
		frame.BorderSizePixel = 0
		frame.ClipsDescendants = true
		Instance.new("UICorner", frame).CornerRadius = UDim.new(0, 8)
		local outerStroke = Instance.new("UIStroke", frame)
		outerStroke.Color = Color3.fromRGB(55, 55, 75)
		outerStroke.Thickness = 1
		local accent = Instance.new("Frame", frame)
		accent.Size = UDim2.new(1, 0, 0, 2)
		accent.BackgroundColor3 = Color3.fromRGB(60, 160, 255)
		accent.BorderSizePixel = 0
		local titleBar = Instance.new("Frame", frame)
		titleBar.Size = UDim2.new(1, 0, 0, H_MIN)
		titleBar.BackgroundColor3 = Color3.fromRGB(18, 18, 28)
		titleBar.BorderSizePixel = 0
		local titleLabel = Instance.new("TextLabel", titleBar)
		titleLabel.Size = UDim2.new(1, -40, 1, 0)
		titleLabel.Position = UDim2.fromOffset(10, 0)
		titleLabel.BackgroundTransparency = 1
		titleLabel.Font = Enum.Font.GothamBold
		titleLabel.Text = "REACH CONTROLLER"
		titleLabel.TextColor3 = Color3.fromRGB(180, 210, 255)
		titleLabel.TextSize = 11
		titleLabel.TextXAlignment = Enum.TextXAlignment.Left
		local collapseBtn = Instance.new("TextButton", titleBar)
		collapseBtn.Size = UDim2.fromOffset(22, 22)
