RegisterCommand({
	Name = "antitp",
	Aliases = {},
	Description = "Anti Teleporter.",
	ArgsDesc = {},
	Permissions = {},
}, function(args, speaker)
	local TeleportService = game:GetService("TeleportService")
	local getRawMetatable = (debug and debug.getmetatable) or getrawmetatable
	local setReadOnly = setreadonly
		or (
			make_writeable and function(t, ro)
				if ro then
					make_readonly(t)
				else
					make_writeable(t)
				end
			end
		)
	if not (getRawMetatable and setReadOnly and hookfunction and newcclosure) then
		return warn("[Architect]: Executor lacks required metatable/hooking capabilities.")
	end
	local Config = {
		Debug = true,
		Mode = "block",
	}
	local function Log(msg)
		if Config.Debug then
			print(string.format("[Anti-Teleport]: %s", msg))
		end
	end
	local Meta = getRawMetatable(game)
	local OldNamecall = Meta.__namecall
	local OldIndex = Meta.__index
	local OldNewIndex = Meta.__newindex
	local TeleportMethods = {
		"Teleport",
		"TeleportToPlaceInstance",
		"TeleportAsync",
		"TeleportPartyAsync",
		"TeleportToPrivateServer",
	}
	for _, methodName in ipairs(TeleportMethods) do
		local originalMethod = TeleportService[methodName]
		if originalMethod and typeof(originalMethod) == "function" then
			hookfunction(
				originalMethod,
				newcclosure(function(self, ...)
					if self == TeleportService then
						Log("Blocked Direct Call: " .. methodName)
						if Config.Mode == "error" then
							error("Teleport blocked via hook: " .. methodName, 0)
						end
						return nil
					end
					return originalMethod(self, ...)
				end)
			)
		end
	end
	setReadOnly(Meta, false)
	Meta.__namecall = newcclosure(function(self, ...)
		local method = getnamecallmethod()
		local methodName = tostring(method or "")
		if self == TeleportService and string.find(methodName:lower(), "teleport") then
			Log("Blocked Namecall: " .. methodName)
			if Config.Mode == "error" then
				error("Teleport blocked via namecall: " .. methodName, 0)
			end
			return nil
		end
		return OldNamecall(self, ...)
	end)
	Meta.__index = newcclosure(function(self, key)
		if self == TeleportService and type(key) == "string" then
			local k = key:lower()
			if k:find("teleport") then
				Log("Blocked Attempt to Index: " .. key)
				if Config.Mode == "error" then
					return function()
						error("Method " .. key .. " is protected.", 0)
					end
				else
					return function() end
				end
			end
		end
		return OldIndex(self, key)
	end)
	Meta.__newindex = newcclosure(function(self, key, value)
		if self == TeleportService and type(key) == "string" then
			local k = key:lower()
			if k:find("teleport") then
				Log("Blocked Attempt to Overwrite: " .. key)
				return nil
			end
		end
		return OldNewIndex(self, key, value)
	end)
	setReadOnly(Meta, true)
	Log("Anti-Teleport on.")
end)
RegisterCommand({
	Name = "anticframetp",
	Aliases = { "antic" },
	Description = "Anti Cframe Teleporter.",
	ArgsDesc = {},
	Permissions = {},
}, function(args, speaker)
	local Players = game:GetService("Players")
	local RunService = game:GetService("RunService")
	local LocalPlayer = Players.LocalPlayer or Players.PlayerAdded:Wait()
	local AntiCFrame = {
		Enabled = false,
		Debug = true,
		Connections = {},
		Allowed = {},
		LastCFrame = {},
		ProtectedParts = {},
	}
	local function Log(msg)
		if AntiCFrame.Debug then
			print(string.format("[Anti-CFrame]: %s", msg))
		end
	end
	local function ClearConnections(group)
		if AntiCFrame.Connections[group] then
			for _, con in ipairs(AntiCFrame.Connections[group]) do
				con:Disconnect()
			end
			AntiCFrame.Connections[group] = {}
		end
	end
	local function HookPart(part)
		if not part:IsA("BasePart") or AntiCFrame.Allowed[part] ~= nil then
			return
		end
		AntiCFrame.Allowed[part] = false
		AntiCFrame.LastCFrame[part] = part.CFrame
		table.insert(AntiCFrame.ProtectedParts, part)
		local con = part:GetPropertyChangedSignal("CFrame"):Connect(function()
			if not AntiCFrame.Enabled then
				return
			end
			if AntiCFrame.Allowed[part] then
				return
			end
			local last = AntiCFrame.LastCFrame[part]
			if last then
				AntiCFrame.Allowed[part] = true
				part.CFrame = last
				task.wait()
				AntiCFrame.Allowed[part] = false
				Log("Blocked forced movement on: " .. part.Name)
			end
		end)
		table.insert(AntiCFrame.Connections["Character"], con)
	end
	local function SetupCharacter(char)
		ClearConnections("Character")
		AntiCFrame.Allowed = {}
		AntiCFrame.LastCFrame = {}
		AntiCFrame.ProtectedParts = {}
		AntiCFrame.Connections["Character"] = {}
		for _, part in ipairs(char:GetDescendants()) do
			if part:IsA("BasePart") then
				HookPart(part)
			end
		end
		local descCon = char.DescendantAdded:Connect(function(desc)
			if desc:IsA("BasePart") then
				HookPart(desc)
			end
		end)
		table.insert(AntiCFrame.Connections["Character"], descCon)
		task.spawn(function()
			while AntiCFrame.Enabled and char and char.Parent do
				for _, part in ipairs(AntiCFrame.ProtectedParts) do
					if part and part.Parent and not AntiCFrame.Allowed[part] then
						AntiCFrame.LastCFrame[part] = part.CFrame
					end
				end
				task.wait(0.1)
			end
		end)
	end
	function AntiCFrame:Toggle(state)
		self.Enabled = state
		if state then
			local char = LocalPlayer.Character
			if char then
				SetupCharacter(char)
			end
			local respawnCon = LocalPlayer.CharacterAdded:Connect(function(newChar)
				task.wait(0.5)
				SetupCharacter(newChar)
			end)
			self.Connections["Global"] = { respawnCon }
			Log("Anti-CFrame Teleport Protection Active.")
		else
			ClearConnections("Global")
			ClearConnections("Character")
			self.Allowed = {}
			self.LastCFrame = {}
			self.ProtectedParts = {}
			Log("Anti-CFrame Teleport Protection Disabled.")
		end
	end
	AntiCFrame:Toggle(true)
end)
Modules.FireRemotes = {
	State = {
		Enabled = false,
	},
}
function Modules.FireRemotes:Initialize()
	RegisterCommand({
		Name = "fireremotes",
		Aliases = { "fall" },
		Description = "Attempts to fire every discoverable RemoteEvent and RemoteFunction and logs results.",
	}, function(args)
		local CoreGui = game:GetService("CoreGui")
		local Stats = {
			SuccessCount = 0,
			FailCount = 0,
			LoggedRemotes = {},
		}
		print("Starting...")
		for _, obj in ipairs(game:GetDescendants()) do
			if (obj:IsA("RemoteEvent") or obj:IsA("RemoteFunction")) and not obj:IsDescendantOf(CoreGui) then
				task.spawn(function()
					local success, err
					local objPath = obj:GetFullName()
					local methodUsed = ""
					if obj:IsA("RemoteEvent") then
						methodUsed = "FireServer"
						success, err = pcall(function()
							obj:FireServer()
						end)
					elseif obj:IsA("RemoteFunction") then
						methodUsed = "InvokeServer"
						success, err = pcall(function()
							obj:InvokeServer()
						end)
					end
					if success then
						Stats.SuccessCount = Stats.SuccessCount + 1
						local logEntry = string.format("[%s] SUCCESS: %s | Args: (none)", methodUsed, objPath)
						table.insert(Stats.LoggedRemotes, logEntry)
						print(logEntry)
					else
						Stats.FailCount = Stats.FailCount + 1
						warn(string.format("[!] FAILED: %s | Error: %s", objPath, tostring(err)))
					end
				end)
				if _ % 100 == 0 then
					task.wait()
				end
			end
		end
		task.delay(3, function()
			local summary = string.format(
				"Execution Complete.\nSuccessfully Fired: %d\nFailed: %d\nCheck console (F9) for full argument logs.",
				Stats.SuccessCount,
				Stats.FailCount
			)
			if typeof(DoNotif) == "function" then
				DoNotif(summary)
			else
				print(summary)
			end
			if #Stats.LoggedRemotes > 0 then
				print("--- SUCCESSFUL REMOTE LIST ---")
				for _, log in ipairs(Stats.LoggedRemotes) do
					print(log)
				end
				print("ok")
			end
		end)
	end)
end
Modules.RemoveForces = {
	State = {},
