function Modules.RemoveForces:Initialize()
	RegisterCommand({
		Name = "deletevelocity",
		Aliases = { "novel" },
		Description = "Removes all force/velocity instances from your character to counter flings or fix physics glitches.",
	}, function(args)
		local Players = game:GetService("Players")
		local localPlayer = Players.LocalPlayer
		local character = localPlayer.Character
		if not character then
			return DoNotif("Character not found.", 3)
		end
		local forcesRemoved = 0
		for _, instance in ipairs(character:GetDescendants()) do
			if
				instance:isA("BodyVelocity")
				or instance:isA("BodyGyro")
				or instance:isA("RocketPropulsion")
				or instance:isA("BodyAngularVelocity")
				or instance:isA("BodyForce")
				or instance:isA("BodyThrust")
				or instance:isA("VectorForce")
				or instance:isA("LineForce")
				or instance:isA("AngularVelocity")
			then
				instance:Destroy()
				forcesRemoved = forcesRemoved + 1
			end
		end
		DoNotif("Removed " .. forcesRemoved .. " force instances from your character.", 3)
	end)
end
