	local state = Modules.AuthorityHijacker.State
	state.IsEnabled = not state.IsEnabled
	if state.IsEnabled then
		Modules.AuthorityHijacker:ApplyKernelHook()
		DoNotif("Kernel Hijack: ACTIVE. Engine constraints ignored.", 3)
	else
		DoNotif("Kernel Hijack: DISABLED.", 2)
	end
end)
Modules.InventoryVault = {
	State = {
		IsEnabled = false,
		Vault = {},
		Connections = {},
		HookActive = false,
		OriginalNewIndex = nil,
	},
	Dependencies = { "Players", "CoreGui", "RunService" },
}
function Modules.InventoryVault:Snapshot()
	local backpack = Players.LocalPlayer:FindFirstChildOfClass("Backpack")
	local char = Players.LocalPlayer.Character
	if not (backpack or char) then
		return
	end
	table.clear(self.State.Vault)
	local count = 0
	local function save(tool)
		if tool:IsA("Tool") and not self.State.Vault[tool.Name] then
			self.State.Vault[tool.Name] = tool:Clone()
			count = count + 1
		end
	end
	for _, t in ipairs(backpack:GetChildren()) do
		save(t)
	end
	for _, t in ipairs(char:GetChildren()) do
		save(t)
	end
	DoNotif("Vault: Saved " .. count .. " tools to local memory.", 3)
end
function Modules.InventoryVault:Restore()
	local backpack = Players.LocalPlayer:FindFirstChildOfClass("Backpack")
	if not backpack then
		return
	end
	local restored = 0
	for name, toolTemplate in pairs(self.State.Vault) do
		if
			not backpack:FindFirstChild(name)
			and not (Players.LocalPlayer.Character and Players.LocalPlayer.Character:FindFirstChild(name))
		then
			local clone = toolTemplate:Clone()
			clone.Parent = backpack
			restored = restored + 1
		end
	end
	DoNotif("Vault: Restored " .. restored .. " tools.", 2)
end
function Modules.InventoryVault:ApplyShield()
	if self.State.HookActive then
		return
	end
	local success, mt = pcall(getrawmetatable, game)
	if not success then
		return
	end
	self.State.OriginalNewIndex = mt.__newindex
	local old = mt.__newindex
	setreadonly(mt, false)
	mt.__newindex = newcclosure(function(t, k, v)
		if
			Modules.InventoryVault.State.IsEnabled
			and t:IsA("Tool")
			and k == "Parent"
			and v ~= Players.LocalPlayer:FindFirstChildOfClass("Backpack")
			and v ~= Players.LocalPlayer.Character
		then
			if not checkcaller() then
				warn("--> [Vault] Blocked attempt to remove tool: " .. t.Name)
				return nil
			end
		end
		return old(t, k, v)
	end)
	setreadonly(mt, true)
	self.State.HookActive = true
end
function Modules.InventoryVault:Toggle()
	self.State.IsEnabled = not self.State.IsEnabled
	if self.State.IsEnabled then
		self:ApplyShield()
		self:Snapshot()
		DoNotif("Inventory Shield: ACTIVE", 2)
	else
		DoNotif("Inventory Shield: DISABLED", 2)
	end
end
function Modules.InventoryVault:Initialize()
	local module = self
	module.Services = {}
	for _, s in ipairs(module.Dependencies) do
		module.Services[s] = game:GetService(s)
	end
	RegisterCommand({
		Name = "saveinv",
		Aliases = { "vaultsave" },
		Description = "Saves your current tools so you can restore them after death/stripping.",
	}, function()
		module:Snapshot()
	end)
	RegisterCommand({
		Name = "restoreinv",
		Aliases = { "getvault" },
		Description = "Brings back all tools saved in your vault.",
	}, function()
		module:Restore()
	end)
	RegisterCommand({
		Name = "antitoolremove",
		Aliases = { "atr" },
		Description = "Toggles a shield that blocks scripts from removing your tools.",
	}, function()
		module:Toggle()
	end)
end
Modules.PropertyForensics = {
	State = {
		OriginalSizes = setmetatable({}, { __mode = "k" }),
	},
}
function Modules.PropertyForensics:_resolvePath(path)
	local current = game
	local segments = string.split(path, ".")
	for i, name in ipairs(segments) do
		if i == 1 then
			if name:lower() == "workspace" then
				current = workspace
				continue
			elseif name:lower() == "game" then
				continue
			end
			local success, service = pcall(game.GetService, game, name)
			if success and service then
				current = service
			else
				current = current:FindFirstChild(name)
			end
		else
			current = current and current:FindFirstChild(name)
		end
		if not current then
			break
		end
	end
	return current
end
function Modules.PropertyForensics:Resize(path, x, y, z)
	local obj = self:_resolvePath(path)
	if not obj then
		return DoNotif("Resize Error: Path could not be resolved.", 3)
	end
	if obj:IsA("Model") then
		local scale = tonumber(x)
		if scale then
			local success, err = pcall(function()
				obj:ScaleTo(scale)
			end)
			if success then
				DoNotif("Model Scaled to: " .. scale, 2)
			else
				warn("Resize Error:", err)
			end
		else
			DoNotif("Usage for Models: ;size [path] [Multiplier]", 3)
		end
		return
	end
	if obj:IsA("BasePart") or obj:IsA("GuiObject") then
		local newSize
		if x and y and z then
			newSize = Vector3.new(tonumber(x), tonumber(y), tonumber(z))
		elseif x and not y then
			local factor = tonumber(x)
			newSize = obj.Size * factor
		end
		if newSize then
			if not self.State.OriginalSizes[obj] then
				self.State.OriginalSizes[obj] = obj.Size
			end
			pcall(function()
				obj.Size = newSize
			end)
			DoNotif("Resized: " .. obj.Name, 2)
		end
	else
		DoNotif("Error: Object type does not support Size.", 3)
	end
end
function Modules.PropertyForensics:Restore(path)
	local obj = self:_resolvePath(path)
	local original = self.State.OriginalSizes[obj]
	if obj and original then
		pcall(function()
			obj.Size = original
		end)
		self.State.OriginalSizes[obj] = nil
		DoNotif("Restored original size for: " .. obj.Name, 2)
	end
end
RegisterCommand({
	Name = "size",
	Aliases = { "resize", "scale" },
	Description = "Resizes an object by path. Usage: ;size [path] [multiplier] OR ;size [path] [x] [y] [z]",
}, function(args)
	if #args < 2 then
		return DoNotif("Usage: ;size workspace.Part 5", 3)
	end
	local path = args[1]
	local x = args[2]
	local y = args[3]
	local z = args[4]
	Modules.PropertyForensics:Resize(path, x, y, z)
end)
RegisterCommand({
	Name = "unsize",
	Aliases = { "revertsize" },
	Description = "Restores the original size of an object. Usage: ;unsize [path]",
}, function(args)
	if not args[1] then
		return
	end
	Modules.PropertyForensics:Restore(args[1])
end)
RegisterCommand({
	Name = "hsize",
	Aliases = { "hitboxsize", "ext" },
	Description = "Quick hitbox extender for players. Usage: ;hsize [Name] [Size]",
}, function(args)
	local target = Utilities.findPlayer(args[1])
	local size = args[2] or 10
	if target and target.Character then
		local hrp = target.Character:FindFirstChild("HumanoidRootPart")
		if hrp then
			Modules.PropertyForensics:Resize(hrp:GetFullName(), size)
			hrp.CanCollide = false
			hrp.Transparency = 0.7
		end
	else
		DoNotif("Target player character not found.", 3)
	end
end)
Modules.GrabTools = {
	State = {
		IsEnabled = false,
		Connection = nil,
		Grabbed = {},
		TotalGrabbed = 0,
	},
	Config = {
		ScanInterval = 0.25,
		VerboseNotify = true,
		DeepSearch = true,
		GrabFromChars = false,
	},
}
function Modules.GrabTools:_getBackpack()
	if not LocalPlayer then
		return nil
	end
	return LocalPlayer:FindFirstChildOfClass("Backpack")
end
function Modules.GrabTools:_getCharacterTools()
	local held = {}
	if LocalPlayer and LocalPlayer.Character then
		for _, v in ipairs(LocalPlayer.Character:GetChildren()) do
			if v:IsA("Tool") then
				held[v] = true
			end
		end
	end
	return held
end
function Modules.GrabTools:_collectTargets()
	local targets = {}
	if self.Config.DeepSearch then
		for _, inst in ipairs(Workspace:GetDescendants()) do
			if inst:IsA("Tool") then
				table.insert(targets, inst)
			end
		end
	else
		for _, child in ipairs(Workspace:GetChildren()) do
			if child:IsA("Tool") then
				table.insert(targets, child)
			end
		end
	end
	if self.Config.GrabFromChars then
		for _, plr in ipairs(game:GetService("Players"):GetPlayers()) do
			if plr ~= LocalPlayer then
				local bp = plr:FindFirstChildOfClass("Backpack")
				if bp then
					for _, tool in ipairs(bp:GetChildren()) do
						if tool:IsA("Tool") then
							table.insert(targets, tool)
						end
					end
				end
			end
		end
	end
	return targets
end
function Modules.GrabTools:_tryGrab(tool, backpack)
	if self.State.Grabbed[tool] then
		return false
	end
	local parent = tool.Parent
	if parent == backpack then
		return false
	end
	if LocalPlayer.Character and parent == LocalPlayer.Character then
		return false
	end
	local handle = tool:FindFirstChild("Handle")
	if handle and handle.Anchored then
		return false
	end
	local ok, err = pcall(function()
		tool.Parent = backpack
	end)
	if ok then
		self.State.Grabbed[tool] = true
		self.State.TotalGrabbed = self.State.TotalGrabbed + 1
		if self.Config.VerboseNotify then
			DoNotif("🎒 Grabbed: " .. tool.Name, 1.2)
		end
		return true
	else
		return false
	end
end
function Modules.GrabTools:_scan()
	local backpack = self:_getBackpack()
	if not backpack then
		return
	end
	local targets = self:_collectTargets()
	local grabCount = 0
	for _, tool in ipairs(targets) do
		if self:_tryGrab(tool, backpack) then
			grabCount = grabCount + 1
		end
	end
	if not self.Config.VerboseNotify and grabCount > 0 then
		DoNotif("🎒 Grabbed " .. grabCount .. " tool" .. (grabCount > 1 and "s" or ""), 1.5)
	end
end
function Modules.GrabTools:Enable()
	if self.State.IsEnabled then
		DoNotif("GrabTools already active", 1.5)
		return
	end
	local backpack = self:_getBackpack()
	if not backpack then
		DoNotif("No backpack found — are you in a game?", 2)
		return
	end
	self.State.IsEnabled = true
	self.State.Grabbed = {}
	self.State.TotalGrabbed = 0
	local timer = 0
	self.State.Connection = RunService.Heartbeat:Connect(function(dt)
		if not self.State.IsEnabled then
			return
		end
		timer = timer + dt
		if timer >= self.Config.ScanInterval then
			timer = 0
			self:_scan()
		end
	end)
	DoNotif("GrabTools ON — scanning every " .. self.Config.ScanInterval .. "s", 2)
end
function Modules.GrabTools:Disable()
	if not self.State.IsEnabled then
		DoNotif("GrabTools already off", 1.5)
		return
	end
	self.State.IsEnabled = false
	if self.State.Connection then
		self.State.Connection:Disconnect()
		self.State.Connection = nil
	end
	DoNotif("GrabTools OFF — grabbed " .. self.State.TotalGrabbed .. " tool(s) total", 2.5)
	self.State.Grabbed = {}
	self.State.TotalGrabbed = 0
end
function Modules.GrabTools:Toggle()
	if self.State.IsEnabled then
		self:Disable()
	else
		self:Enable()
	end
end
function Modules.GrabTools:GrabOnce()
	local backpack = self:_getBackpack()
	if not backpack then
		DoNotif("No backpack found", 2)
		return
	end
	local oldGrabbed = self.State.Grabbed
	self.State.Grabbed = {}
	local targets = self:_collectTargets()
	local grabbed = 0
	for _, tool in ipairs(targets) do
		if self:_tryGrab(tool, backpack) then
			grabbed = grabbed + 1
		end
	end
	self.State.Grabbed = oldGrabbed
	DoNotif("One-shot grab: got " .. grabbed .. " tool(s)", 2)
end
function Modules.GrabTools:Initialize()
	RegisterCommand({
		Name = "grabtools",
		Aliases = { "gt", "toolgrab" },
		Description = "Toggle auto tool grabber — picks up ALL tools from anywhere in workspace",
	}, function()
		Modules.GrabTools:Toggle()
	end)
	RegisterCommand({
		Name = "grab1",
		Aliases = { "grabonce", "graball" },
		Description = "One-shot: instantly grab every tool in workspace right now",
	}, function()
		Modules.GrabTools:GrabOnce()
	end)
	RegisterCommand({
		Name = "grabdeep",
		Aliases = { "gtdeep" },
		Description = "Toggle deep search (scans all descendants, not just workspace surface)",
	}, function()
		Modules.GrabTools.Config.DeepSearch = not Modules.GrabTools.Config.DeepSearch
		DoNotif("GrabTools deep search: " .. (Modules.GrabTools.Config.DeepSearch and "ON" or "OFF"), 2)
	end)
	RegisterCommand({
		Name = "grabchars",
		Aliases = { "gtchars" },
		Description = "Toggle grabbing tools from other players backpacks too",
	}, function()
		Modules.GrabTools.Config.GrabFromChars = not Modules.GrabTools.Config.GrabFromChars
		DoNotif("GrabTools grab from chars: " .. (Modules.GrabTools.Config.GrabFromChars and "ON" or "OFF"), 2)
	end)
	RegisterCommand({
		Name = "grabverbose",
		Aliases = { "gtv" },
		Description = "Toggle per-tool grab notifications",
	}, function()
		Modules.GrabTools.Config.VerboseNotify = not Modules.GrabTools.Config.VerboseNotify
		DoNotif("GrabTools verbose: " .. (Modules.GrabTools.Config.VerboseNotify and "ON" or "OFF"), 2)
	end)
end
Modules.AdminSpoofDemonstration = {
	State = {
		IsSpoofing = false,
		SpoofedId = -1,
		SpoofedName = nil,
		SpoofedDisplayName = nil,
		OriginalIndex = nil,
		OriginalNamecall = nil,
		PlayerMetatable = nil,
		GameMetatable = nil,
		HookEnabled = true,
		OriginalUserId = nil,
		OriginalName = nil,
		OriginalDisplayName = nil,
		Stats = {
			InterceptedCalls = 0,
			LastSpoof = 0,
		},
	},
	Dependencies = { "Players" },
	Config = {
		SpoofName = true,
		SpoofDisplayName = true,
		InterceptRemoteCalls = true,
		StealthMode = true,
		DebugMode = false,
		AllowedProperties = {
			"UserId",
			"Name",
			"DisplayName",
			"AccountAge",
		},
	},
}
local function debugLog(message)
	if Modules.AdminSpoofDemonstration.Config.DebugMode then
		print("[AdminSpoof Debug]", message)
	end
end
local function fetchUserInfo(userId)
	local success, result = pcall(function()
		local HttpService = game:GetService("HttpService")
		local url = "https://users.roblox.com/v1/users/" .. userId
		if request then
			local response = request({
				Url = url,
				Method = "GET",
			})
			if response.StatusCode == 200 then
				return HttpService:JSONDecode(response.Body)
			end
		end
		local data = game:HttpGet(url)
		return HttpService:JSONDecode(data)
	end)
	if success and result then
		return {
			name = result.name,
			displayName = result.displayName,
			id = result.id,
		}
	end
	return nil
end
function Modules.AdminSpoofDemonstration:Enable(targetId, targetName, targetDisplayName)
	if self.State.IsSpoofing then
		DoNotif("Already spoofing. Reset first with ;spoofid reset", 3)
		return false
	end
	local localPlayer = self.Services.Players.LocalPlayer
	if not localPlayer then
		DoNotif("Error: LocalPlayer not found", 3)
		return false
	end
	self.State.OriginalUserId = localPlayer.UserId
	self.State.OriginalName = localPlayer.Name
	self.State.OriginalDisplayName = localPlayer.DisplayName
	self.State.SpoofedId = tonumber(targetId) or -1
	if self.State.SpoofedId <= 0 then
		DoNotif("Invalid UserId. Must be positive.", 3)
		return false
	end
	if not targetName or not targetDisplayName then
		DoNotif("Fetching user info...", 2)
		local userInfo = fetchUserInfo(self.State.SpoofedId)
		if userInfo then
			targetName = userInfo.name
			targetDisplayName = userInfo.displayName
			debugLog("Fetched info: " .. targetName .. " | " .. targetDisplayName)
		else
			debugLog("Failed to fetch user info, using defaults")
			targetName = targetName or "Player" .. self.State.SpoofedId
			targetDisplayName = targetDisplayName or targetName
		end
	end
	self.State.SpoofedName = targetName
	self.State.SpoofedDisplayName = targetDisplayName
	local success, playerMetatable = pcall(getrawmetatable, localPlayer)
	if not success or typeof(playerMetatable) ~= "table" then
		DoNotif("Error: Could not access player metatable", 4)
		return false
	end
	self.State.PlayerMetatable = playerMetatable
	self.State.OriginalIndex = playerMetatable.__index
	self.State.OriginalNamecall = playerMetatable.__namecall
	local originalIndexCache = self.State.OriginalIndex
	local originalNamecallCache = self.State.OriginalNamecall
	pcall(setreadonly, playerMetatable, false)
	playerMetatable.__index = newcclosure(function(self, key)
		if
			Modules.AdminSpoofDemonstration.State.IsSpoofing
			and Modules.AdminSpoofDemonstration.State.HookEnabled
			and self == localPlayer
		then
			if key == "UserId" then
				Modules.AdminSpoofDemonstration.State.Stats.InterceptedCalls = Modules.AdminSpoofDemonstration.State.Stats.InterceptedCalls
					+ 1
				debugLog("Intercepted UserId access for LocalPlayer")
				return Modules.AdminSpoofDemonstration.State.SpoofedId
			elseif key == "Name" and Modules.AdminSpoofDemonstration.Config.SpoofName then
				Modules.AdminSpoofDemonstration.State.Stats.InterceptedCalls = Modules.AdminSpoofDemonstration.State.Stats.InterceptedCalls
					+ 1
				debugLog("Intercepted Name access for LocalPlayer")
				return Modules.AdminSpoofDemonstration.State.SpoofedName
			elseif key == "DisplayName" and Modules.AdminSpoofDemonstration.Config.SpoofDisplayName then
				Modules.AdminSpoofDemonstration.State.Stats.InterceptedCalls = Modules.AdminSpoofDemonstration.State.Stats.InterceptedCalls
					+ 1
				debugLog("Intercepted DisplayName access for LocalPlayer")
				return Modules.AdminSpoofDemonstration.State.SpoofedDisplayName
			end
		end
		if typeof(originalIndexCache) == "function" then
			return originalIndexCache(self, key)
		else
			return originalIndexCache[key]
		end
	end)
	if self.Config.InterceptRemoteCalls then
		playerMetatable.__namecall = newcclosure(function(self, ...)
			local args = { ... }
			local method = getnamecallmethod()
			if
				Modules.AdminSpoofDemonstration.State.IsSpoofing
				and (method == "FireServer" or method == "InvokeServer")
			then
				for i, arg in ipairs(args) do
					if arg == Modules.AdminSpoofDemonstration.State.OriginalUserId then
						args[i] = Modules.AdminSpoofDemonstration.State.SpoofedId
						debugLog("Spoofed UserId in remote call")
					elseif
						arg == Modules.AdminSpoofDemonstration.State.OriginalName
						and Modules.AdminSpoofDemonstration.Config.SpoofName
					then
						args[i] = Modules.AdminSpoofDemonstration.State.SpoofedName
						debugLog("Spoofed Name in remote call")
					elseif
						arg == Modules.AdminSpoofDemonstration.State.OriginalDisplayName
						and Modules.AdminSpoofDemonstration.Config.SpoofDisplayName
					then
						args[i] = Modules.AdminSpoofDemonstration.State.SpoofedDisplayName
						debugLog("Spoofed DisplayName in remote call")
					elseif arg == localPlayer then
						debugLog("LocalPlayer instance passed in remote - hooks will handle properties")
					end
				end
			end
			return originalNamecallCache(self, unpack(args))
		end)
	end
	pcall(setreadonly, playerMetatable, true)
	self.State.IsSpoofing = true
	self.State.Stats.LastSpoof = tick()
	DoNotif(
		string.format(
			"Spoofing enabled:\nUserId: %d\nName: %s\nDisplay: %s",
			self.State.SpoofedId,
			self.State.SpoofedName,
			self.State.SpoofedDisplayName
		),
		4
	)
	debugLog("Spoof enabled successfully for LocalPlayer only")
	return true
end
function Modules.AdminSpoofDemonstration:Disable()
	if not self.State.IsSpoofing then
		DoNotif("Not currently spoofing", 2)
		return false
	end
	if self.State.PlayerMetatable then
		pcall(setreadonly, self.State.PlayerMetatable, false)
		if self.State.OriginalIndex then
			self.State.PlayerMetatable.__index = self.State.OriginalIndex
		end
		if self.State.OriginalNamecall then
			self.State.PlayerMetatable.__namecall = self.State.OriginalNamecall
		end
		pcall(setreadonly, self.State.PlayerMetatable, true)
	end
	local interceptCount = self.State.Stats.InterceptedCalls
	self.State.IsSpoofing = false
	self.State.SpoofedId = -1
	self.State.SpoofedName = nil
	self.State.SpoofedDisplayName = nil
	self.State.OriginalIndex = nil
	self.State.OriginalNamecall = nil
	self.State.PlayerMetatable = nil
	self.State.OriginalUserId = nil
	self.State.OriginalName = nil
	self.State.OriginalDisplayName = nil
	self.State.Stats.InterceptedCalls = 0
	DoNotif(string.format("Spoof disabled. Intercepted %d calls.", interceptCount), 3)
	debugLog("Spoof disabled, cleaned up hooks")
	return true
end
function Modules.AdminSpoofDemonstration:Toggle()
	if self.State.IsSpoofing then
		self:Disable()
	else
		DoNotif("Usage: ;spoofid <userid> or ;spoofid <username>", 3)
	end
end
function Modules.AdminSpoofDemonstration:ToggleHook(enabled)
	self.State.HookEnabled = enabled
	DoNotif("Spoof hook " .. (enabled and "enabled" or "disabled"), 2)
end
function Modules.AdminSpoofDemonstration:GetStats()
	return {
		IsSpoofing = self.State.IsSpoofing,
		SpoofedId = self.State.SpoofedId,
		SpoofedName = self.State.SpoofedName,
		InterceptedCalls = self.State.Stats.InterceptedCalls,
		Uptime = self.State.IsSpoofing and (tick() - self.State.Stats.LastSpoof) or 0,
	}
end
function Modules.AdminSpoofDemonstration:SpoofByUsername(username)
	local success, result = pcall(function()
		local Players = game:GetService("Players")
		return Players:GetUserIdFromNameAsync(username)
	end)
	if success and result then
		return self:Enable(result)
	else
		DoNotif("Failed to find user: " .. username, 3)
		return false
	end
end
function Modules.AdminSpoofDemonstration:Initialize()
	local module = self
	module.Services = {}
	for _, serviceName in ipairs(module.Dependencies or {}) do
		module.Services[serviceName] = game:GetService(serviceName)
	end
	RegisterCommand({
		Name = "spoofid",
		Aliases = { "setid", "fakeid", "adminspoof" },
		Description = "Spoofs your UserId/Name for vulnerable admin scripts.",
	}, function(args)
		local argument = args[1]
		if not argument then
			return DoNotif("Usage: ;spoofid <userid|username|reset>", 3)
		end
		if argument:lower() == "reset" or argument:lower() == "clear" or argument:lower() == "off" then
			module:Disable()
		elseif argument:lower() == "stats" then
			local stats = module:GetStats()
			print("=== Admin Spoof Stats ===")
			print("Spoofing:", stats.IsSpoofing)
			print("Spoofed ID:", stats.SpoofedId)
			print("Spoofed Name:", stats.SpoofedName or "N/A")
			print("Intercepted Calls:", stats.InterceptedCalls)
			print("Uptime:", string.format("%.1f", stats.Uptime) .. "s")
		elseif argument:lower() == "toggle" then
			module:Toggle()
		else
			local targetId = tonumber(argument)
			if targetId and targetId > 0 then
				module:Enable(targetId)
			else
				module:SpoofByUsername(argument)
			end
		end
	end)
	RegisterCommand({
		Name = "spoofname",
		Aliases = { "fakename" },
		Description = "Toggle name spoofing on/off.",
	}, function(args)
		module.Config.SpoofName = not module.Config.SpoofName
		DoNotif("Name spoofing: " .. (module.Config.SpoofName and "ON" or "OFF"), 2)
	end)
	RegisterCommand({
		Name = "spoofdisplay",
		Aliases = { "fakedisplay" },
		Description = "Toggle display name spoofing on/off.",
	}, function(args)
		module.Config.SpoofDisplayName = not module.Config.SpoofDisplayName
		DoNotif("Display name spoofing: " .. (module.Config.SpoofDisplayName and "ON" or "OFF"), 2)
	end)
	RegisterCommand({
		Name = "spoofstats",
		Aliases = { "spoofinfo" },
		Description = "Shows spoofing statistics.",
	}, function(args)
		local stats = module:GetStats()
		print("=== Admin Spoof Stats ===")
		print("Active:", stats.IsSpoofing)
		if stats.IsSpoofing then
			print("Spoofed ID:", stats.SpoofedId)
			print("Spoofed Name:", stats.SpoofedName)
			print("Intercepted:", stats.InterceptedCalls)
			print("Uptime:", string.format("%.1fs", stats.Uptime))
		end
	end)
end
Modules.ForceCamera = {
	State = {
		IsEnabled = false,
		Connections = {},
	},
	Config = {
		Distance = 12,
		Height = 5,
		LerpAlpha = 0.15,
		LockPitch = false,
	},
}
function Modules.ForceCamera:Enable()
	if self.State.IsEnabled then
		return
	end
	self.State.IsEnabled = true
	local cam = workspace.CurrentCamera
	pcall(function()
		cam.CameraType = Enum.CameraType.Scriptable
	end)
	self.State.Connections.TypeGuard = cam:GetPropertyChangedSignal("CameraType"):Connect(function()
		if self.State.IsEnabled and cam.CameraType ~= Enum.CameraType.Scriptable then
			pcall(function()
				cam.CameraType = Enum.CameraType.Scriptable
			end)
		end
	end)
	self.State.Connections.CameraSwap = workspace:GetPropertyChangedSignal("CurrentCamera"):Connect(function()
		local newCam = workspace.CurrentCamera
		if newCam and self.State.IsEnabled then
			pcall(function()
				newCam.CameraType = Enum.CameraType.Scriptable
			end)
			if self.State.Connections.TypeGuard then
				pcall(function()
					self.State.Connections.TypeGuard:Disconnect()
				end)
			end
			self.State.Connections.TypeGuard = newCam:GetPropertyChangedSignal("CameraType"):Connect(function()
				if self.State.IsEnabled and newCam.CameraType ~= Enum.CameraType.Scriptable then
					pcall(function()
						newCam.CameraType = Enum.CameraType.Scriptable
					end)
				end
			end)
		end
	end)
	self.State.Connections.Heartbeat = RunService.Heartbeat:Connect(function()
		local char = LocalPlayer.Character
		if not char then
			return
		end
		local hrp = char:FindFirstChild("HumanoidRootPart")
		if not hrp then
			return
		end
		local currentCam = workspace.CurrentCamera
		if not currentCam then
			return
		end
		local cfg = self.Config
		local hrpCF = hrp.CFrame
		local flatLook = Vector3.new(hrpCF.LookVector.X, 0, hrpCF.LookVector.Z)
		if flatLook.Magnitude < 0.01 then
			flatLook = Vector3.new(0, 0, -1)
		else
			flatLook = flatLook.Unit
		end
		local origin = hrp.Position + Vector3.new(0, cfg.Height, 0)
		local camPos = origin - flatLook * cfg.Distance
		local targetCF = CFrame.lookAt(camPos, origin)
		currentCam.CFrame = currentCam.CFrame:Lerp(targetCF, cfg.LerpAlpha)
	end)
	DoNotif("Force Camera: ENABLED  [camera locked behind player]", 3)
end
function Modules.ForceCamera:Disable()
	if not self.State.IsEnabled then
		return
	end
	self.State.IsEnabled = false
	for key, conn in pairs(self.State.Connections) do
		pcall(function()
			conn:Disconnect()
		end)
		self.State.Connections[key] = nil
	end
	pcall(function()
		workspace.CurrentCamera.CameraType = Enum.CameraType.Custom
	end)
	DoNotif("Force Camera: DISABLED  [camera restored]", 2)
end
function Modules.ForceCamera:Toggle()
	if self.State.IsEnabled then
		self:Disable()
	else
		self:Enable()
	end
end
RegisterCommand({
	Name = "forcecam",
	Aliases = { "lockcam", "behindcam" },
	Description = "Locks the camera behind your character at all times, overriding game camera scripts.",
}, function()
	Modules.ForceCamera:Toggle()
end)
RegisterCommand({
	Name = "forcecamdist",
	Aliases = { "fcdist" },
	Description = "Set forced camera distance in studs. Usage: ;forcecamdist <studs>",
}, function(args)
	if not args[1] then
		DoNotif("Distance: " .. Modules.ForceCamera.Config.Distance, 2)
		return
	end
	local v = tonumber(args[1])
	if not v then
		DoNotif("Invalid number", 3)
		return
	end
	Modules.ForceCamera.Config.Distance = math.clamp(v, 1, 100)
	DoNotif("Camera distance: " .. Modules.ForceCamera.Config.Distance, 2)
end)
RegisterCommand({
	Name = "forcecamheight",
	Aliases = { "fcheight" },
	Description = "Set forced camera height offset. Usage: ;forcecamheight <studs>",
}, function(args)
	if not args[1] then
		DoNotif("Height: " .. Modules.ForceCamera.Config.Height, 2)
		return
	end
	local v = tonumber(args[1])
	if not v then
		DoNotif("Invalid number", 3)
		return
	end
	Modules.ForceCamera.Config.Height = v
	DoNotif("Camera height: " .. Modules.ForceCamera.Config.Height, 2)
end)
RegisterCommand({
	Name = "forcecamsmooth",
	Aliases = { "fcsmooth" },
	Description = "Set camera lerp smoothing (0.05 floaty → 1.0 instant). Usage: ;forcecamsmooth <0.05-1>",
}, function(args)
	if not args[1] then
		DoNotif("Smoothing: " .. Modules.ForceCamera.Config.LerpAlpha, 2)
		return
	end
	local v = tonumber(args[1])
	if not v then
		DoNotif("Invalid number", 3)
		return
	end
	Modules.ForceCamera.Config.LerpAlpha = math.clamp(v, 0.01, 1)
	DoNotif("Camera smoothing: " .. Modules.ForceCamera.Config.LerpAlpha, 2)
end)
