	button.Font = Enum.Font.Gotham
	button.Text = props.Text or ""
	button.TextColor3 = T.TEXT_MAIN
	button.TextSize = props.TextSize or 12
	button.ZIndex = props.ZIndex or 2
	applyCorner(button, 3)
	applyStroke(button, props.Accent and T.STROKE_ACCENT or T.STROKE_BTN, 1)
	button.MouseEnter:Connect(function()
		self.Services.TweenService:Create(button, TweenInfo.new(0.1), { BackgroundColor3 = T.BG_BTN_HOV }):Play()
	end)
	button.MouseLeave:Connect(function()
		self.Services.TweenService:Create(button, TweenInfo.new(0.1), { BackgroundColor3 = T.BG_BTN }):Play()
	end)
	button.MouseButton1Down:Connect(function()
		self.Services.TweenService:Create(button, TweenInfo.new(0.06), { BackgroundColor3 = T.BG_DEEP }):Play()
	end)
	button.MouseButton1Up:Connect(function()
		self.Services.TweenService:Create(button, TweenInfo.new(0.06), { BackgroundColor3 = T.BG_BTN_HOV }):Play()
	end)
	if props.Callback then
		button.MouseButton1Click:Connect(props.Callback)
	end
	return button
end
