		local dot = Instance.new("Frame", resizeHandle)
		dot.Size = UDim2.fromOffset(3, 3)
		dot.Position = UDim2.fromOffset(4 + i * 4, 10 - i * 4)
		dot.BackgroundColor3 = T.STROKE_BTN
		dot.BorderSizePixel = 0
		dot.ZIndex = 11
		applyCorner(dot, 1)
	end
