function Modules.NPCShield:_isValidNPC(model)
	if not model or not model.Parent then
		return false
	end
	for _, plr in ipairs(Players:GetPlayers()) do
		if plr.Character == model then
			return false
		end
	end
	return model:FindFirstChild("HumanoidRootPart") ~= nil
end
function Modules.NPCShield:_setupNPCBring(model)
	local tRoot = model:FindFirstChild("HumanoidRootPart")
	if not tRoot then
		return
	end
	local connectionId = "Bring_NPC_" .. model:GetDebugId()
	if self.State.Connections[connectionId] then
		self.State.Connections[connectionId]:Disconnect()
	end
	local connection = RunService.Heartbeat:Connect(function()
		local myChar = Players.LocalPlayer.Character
		local myRoot = myChar and myChar:FindFirstChild("HumanoidRootPart")
		if not self.State.TrackedNPCs[model] then
			if self.State.Connections[connectionId] then
				self.State.Connections[connectionId]:Disconnect()
				self.State.Connections[connectionId] = nil
			end
			return
		end
		if not tRoot.Parent then
			self:_watchForRespawn(model, connectionId)
			return
		end
		if not myRoot then
			return
		end
		tRoot.Velocity = Vector3.new(0, 30.01, 0)
		tRoot.CFrame = myRoot.CFrame * CFrame.new(0, self.Config.VERTICAL_OFFSET, -self.Config.DISTANCE)
	end)
	self.State.Connections[connectionId] = connection
end
function Modules.NPCShield:_watchForRespawn(model, connectionId)
	if self.State.Connections[connectionId] then
		self.State.Connections[connectionId]:Disconnect()
		self.State.Connections[connectionId] = nil
	end
	local watchId = "Watch_" .. connectionId
	local elapsed = 0
	self.State.Connections[watchId] = RunService.Heartbeat:Connect(function(dt)
		elapsed = elapsed + dt
		if not self.State.TrackedNPCs[model] then
			self.State.Connections[watchId]:Disconnect()
			self.State.Connections[watchId] = nil
			return
		end
		if elapsed > 30 then
			self.State.Connections[watchId]:Disconnect()
			self.State.Connections[watchId] = nil
			return
		end
		local hrp = model:FindFirstChild("HumanoidRootPart")
		local humanoid = model:FindFirstChildOfClass("Humanoid")
		if hrp and humanoid and humanoid.Health > 0 then
			self.State.Connections[watchId]:Disconnect()
			self.State.Connections[watchId] = nil
			task.wait(0.1)
			if self.State.TrackedNPCs[model] and self.State.IsEnabled then
				self:_setupNPCBring(model)
				DoNotif(model.Name .. " respawned - re-bringing", 1.5)
			end
		end
	end)
end
function Modules.NPCShield:_trackNPC(model)
	if self.State.TrackedNPCs[model] then
		return
	end
	self.State.TrackedNPCs[model] = true
	self:_setupNPCBring(model)
end
function Modules.NPCShield:_untrackNPC(model)
	self.State.TrackedNPCs[model] = nil
	local connectionId = "Bring_NPC_" .. model:GetDebugId()
	if self.State.Connections[connectionId] then
		self.State.Connections[connectionId]:Disconnect()
		self.State.Connections[connectionId] = nil
	end
	local watchId = "Watch_" .. connectionId
	if self.State.Connections[watchId] then
		self.State.Connections[watchId]:Disconnect()
		self.State.Connections[watchId] = nil
	end
end
function Modules.NPCShield:_gatherNPCs()
	local found = {}
	for _, descendant in ipairs(Workspace:GetDescendants()) do
		if descendant:IsA("Model") and self:_isValidNPC(descendant) then
			local humanoid = descendant:FindFirstChildOfClass("Humanoid")
			if humanoid and humanoid.Health > 0 then
				table.insert(found, descendant)
			end
		end
	end
	return found
end
function Modules.NPCShield:PossessAll()
	if self.State.IsEnabled then
		self:Stop()
	end
	local myChar = Players.LocalPlayer.Character
	if not myChar or not myChar:FindFirstChild("HumanoidRootPart") then
		return DoNotif("Your character not found.", 2)
	end
	local npcs = self:_gatherNPCs()
	if #npcs == 0 then
		return DoNotif("No valid NPCs found in workspace.", 2)
	end
	self.State.IsEnabled = true
	for _, model in ipairs(npcs) do
		self:_trackNPC(model)
	end
	self.State.Connections.DescendantAdded = Workspace.DescendantAdded:Connect(function(descendant)
		if not self.State.IsEnabled then
			return
		end
		task.defer(function()
			if descendant:IsA("Model") and self:_isValidNPC(descendant) and not self.State.TrackedNPCs[descendant] then
				self:_trackNPC(descendant)
				DoNotif("New NPC detected - bringing " .. descendant.Name, 1.5)
			end
		end)
	end)
	DoNotif("NPC Shield Active: " .. #npcs .. " NPC(s)", 2)
end
function Modules.NPCShield:Possess(targetName)
	local found = nil
	local lower = targetName:lower()
	for _, descendant in ipairs(Workspace:GetDescendants()) do
		if descendant:IsA("Model") and self:_isValidNPC(descendant) then
			if descendant.Name:lower():find(lower) then
				found = descendant
				break
			end
		end
	end
	if not found then
		return DoNotif("NPC '" .. targetName .. "' not found.", 2)
	end
	if self.State.IsEnabled then
		self:Stop()
	end
	self.State.IsEnabled = true
	self:_trackNPC(found)
	DoNotif("NPC Shield Active: " .. found.Name .. " (persistent)", 2)
end
function Modules.NPCShield:Initialize()
	local module = self
	RegisterCommand({
		Name = "npcbring",
		Aliases = { "nb", "npcshield" },
		Description = "Brings NPC(s) in front of you persistently. Use 'all' or an NPC name.",
	}, function(args)
		if module.State.IsEnabled then
			module:Stop()
			DoNotif("NPC Shield Released.", 2)
		else
			if #args > 0 then
				if args[1]:lower() == "all" then
					module:PossessAll()
				else
					module:Possess(args[1])
				end
			else
				DoNotif("Usage: ;npcbring [npcname/all]", 3)
			end
		end
	end)
	RegisterCommand({
		Name = "npcrelease",
		Aliases = { "nr" },
		Description = "Releases a specific NPC from the shield.",
	}, function(args)
		if not module.State.IsEnabled then
			return DoNotif("NPC Shield is not active.", 2)
		end
		if not args[1] then
			return DoNotif("Usage: ;npcrelease [npcname]", 3)
		end
		local lower = args[1]:lower()
		local target = nil
		for model in pairs(module.State.TrackedNPCs) do
			if model and model.Parent and model.Name:lower():find(lower) then
				target = model
				break
			end
		end
		if not target then
			return DoNotif("NPC not found in shield list.", 2)
		end
		module:_untrackNPC(target)
		DoNotif("Released: " .. target.Name, 2)
	end)
	RegisterCommand({
		Name = "npclist",
		Aliases = { "nl" },
		Description = "Lists all NPCs currently being brought.",
	}, function()
		if not module.State.IsEnabled then
			return DoNotif("NPC Shield is not active.", 2)
		end
		local count = 0
		print("=== Brought NPCs ===")
		for model in pairs(module.State.TrackedNPCs) do
			if model and model.Parent then
				print("  • " .. model.Name)
				count = count + 1
			end
		end
		print("====================")
		DoNotif("Bringing " .. count .. " NPC(s). Check console (F9)", 2)
	end)
end
Modules.NPCDmgNeutralizer = {
	State = {
		IsEnabled = false,
		Neutralized = {},
		Connections = {},
	},
	Config = {
		DESTROY_DAMAGE_PARTS = false,
		RESCAN_INTERVAL = 1.5,
		STRIP_BODY_TOUCHED = true,
		DAMAGE_PART_NAMES = {
			"damage",
			"hitbox",
			"hit",
			"hurtbox",
			"attack",
			"punch",
			"slash",
			"sword",
			"blade",
			"weapon",
			"hurt",
			"melee",
			"fist",
			"claw",
			"bite",
		},
		BODY_PART_NAMES = {
			"HumanoidRootPart",
			"Torso",
			"UpperTorso",
			"LowerTorso",
			"LeftArm",
			"RightArm",
			"LeftUpperArm",
			"RightUpperArm",
			"LeftLowerArm",
			"RightLowerArm",
			"LeftHand",
			"RightHand",
			"Head",
		},
	},
}
function Modules.NPCDmgNeutralizer:_isValidNPC(model)
	if not model or not model.Parent then
		return false
	end
	if model == LocalPlayer.Character then
		return false
	end
	for _, plr in ipairs(Players:GetPlayers()) do
		if plr.Character == model then
			return false
		end
	end
	return model:FindFirstChild("HumanoidRootPart") ~= nil
end
function Modules.NPCDmgNeutralizer:_isDamagePart(part)
	if not part:IsA("BasePart") then
		return false
	end
	local n = part.Name:lower()
	for _, kw in ipairs(self.Config.DAMAGE_PART_NAMES) do
		if n:find(kw, 1, true) then
			return true
		end
	end
	return false
end
function Modules.NPCDmgNeutralizer:_isBodyPart(part)
	if not part:IsA("BasePart") then
		return false
	end
	if #self.Config.BODY_PART_NAMES == 0 then
		return true
	end
	for _, name in ipairs(self.Config.BODY_PART_NAMES) do
		if part.Name == name then
			return true
		end
	end
	return false
end
function Modules.NPCDmgNeutralizer:_stripTouched(part)
	local count = 0
	if getconnections then
		for _, signal in ipairs({ part.Touched, part.TouchEnded }) do
			local ok, conns = pcall(getconnections, signal)
			if ok and conns then
				for _, conn in ipairs(conns) do
					pcall(function()
						conn:Disable()
						count = count + 1
					end)
				end
			end
		end
	end
	pcall(function()
		part.CanTouch = false
	end)
	return count
end
function Modules.NPCDmgNeutralizer:_neutralize(model)
	if not self:_isValidNPC(model) then
		return
	end
	for _, desc in ipairs(model:GetDescendants()) do
		if self:_isDamagePart(desc) then
			if self.Config.DESTROY_DAMAGE_PARTS then
				pcall(function()
					desc:Destroy()
				end)
			else
				self:_stripTouched(desc)
			end
		elseif self.Config.STRIP_BODY_TOUCHED and self:_isBodyPart(desc) then
			self:_stripTouched(desc)
		end
	end
	model.DescendantAdded:Connect(function(desc)
		if not self.State.IsEnabled then
			return
		end
		task.defer(function()
			if self:_isDamagePart(desc) then
				if self.Config.DESTROY_DAMAGE_PARTS then
					pcall(function()
						desc:Destroy()
					end)
				else
					self:_stripTouched(desc)
				end
			elseif self.Config.STRIP_BODY_TOUCHED and self:_isBodyPart(desc) then
				self:_stripTouched(desc)
			end
		end)
	end)
	self.State.Neutralized[model] = true
end
function Modules.NPCDmgNeutralizer:_scanAll()
	for _, desc in ipairs(Workspace:GetDescendants()) do
		if desc:IsA("Model") and not self.State.Neutralized[desc] and self:_isValidNPC(desc) then
			self:_neutralize(desc)
		end
	end
end
function Modules.NPCDmgNeutralizer:Enable()
	if self.State.IsEnabled then
		return
	end
	self.State.IsEnabled = true
	self.State.Neutralized = {}
	self:_scanAll()
	self.State.Connections.Added = Workspace.DescendantAdded:Connect(function(desc)
		if not self.State.IsEnabled then
			return
		end
		task.defer(function()
			if desc:IsA("Model") and not self.State.Neutralized[desc] and self:_isValidNPC(desc) then
				self:_neutralize(desc)
			end
		end)
	end)
	self.State.Connections.Removing = Workspace.DescendantRemoving:Connect(function(desc)
		if desc:IsA("Model") then
			self.State.Neutralized[desc] = nil
		end
	end)
	task.spawn(function()
		while self.State.IsEnabled do
			task.wait(self.Config.RESCAN_INTERVAL)
			if self.State.IsEnabled then
				self:_scanAll()
			end
		end
	end)
	DoNotif("NPC Dmg Neutralizer: Enabled", 2)
end
function Modules.NPCDmgNeutralizer:Disable()
	if not self.State.IsEnabled then
		return
	end
	self.State.IsEnabled = false
	for _, conn in pairs(self.State.Connections) do
		pcall(function()
			conn:Disconnect()
		end)
	end
	self.State.Connections = {}
	DoNotif("NPC Dmg Neutralizer: Disabled (existing strips remain)", 2)
end
function Modules.NPCDmgNeutralizer:Toggle()
	if self.State.IsEnabled then
		self:Disable()
	else
		self:Enable()
	end
end
function Modules.NPCDmgNeutralizer:Initialize()
	local module = self
	RegisterCommand({
		Name = "npcneutralize",
		Aliases = { "nn", "nodmg", "npcgod" },
		Description = "Strips Touched damage connections from all NPC hitbox/body parts.",
	}, function()
		module:Toggle()
	end)
	RegisterCommand({
		Name = "npcdestroyparts",
		Aliases = { "ndp" },
		Description = "Toggles whether DamageParts are destroyed entirely vs just disconnected.",
	}, function()
		module.Config.DESTROY_DAMAGE_PARTS = not module.Config.DESTROY_DAMAGE_PARTS
		DoNotif("Destroy DamageParts: " .. (module.Config.DESTROY_DAMAGE_PARTS and "ON" or "OFF"), 2)
	end)
end
RegisterCommand({
    Name        = "partcontrol",
    Aliases     = {"partc"},
    Description = "no problem.",
    ArgsDesc    = {},
    Permissions = {},
}, function(args, speaker)
    local CONFIG = {
    	ORBIT_RADIUS = 7,
    	ORBIT_SPEED = 10,
    	VORTEX_HEIGHT = 2.5,
    	PART_CAP = 150,
    	SCAN_RADIUS = 150,
    	FLING_FORCE = 1000000,
    	SIM_RADIUS = 1e9,
    }
    local SessionState = {
    	Active = false,
    	ManagedParts = {},
    	Angle = 0,
    	MainConnection = nil,
    	IsSweeping = false,
    }
    local function GetSafeParent()
    	local success, parent = pcall(function()
    		return gethui() or CoreGui or LocalPlayer:FindFirstChildOfClass("PlayerGui")
    	end)
    	return success and parent or nil
    end
    local function SetHiddenProperty(instance, property, value)
    	pcall(function()
    		if sethiddenproperty then
    			sethiddenproperty(instance, property, value)
    		end
    	end)
    end
    local function ToggleCharacterCollision(state)
    	local char = LocalPlayer.Character
    	if not char then
    		return
    	end
    	for _, part in ipairs(char:GetDescendants()) do
    		if part:IsA("BasePart") then
    			part.CanCollide = state
    		end
    	end
    end
    local function CollectParts()
    	local char = LocalPlayer.Character
    	local hrp = char and char:FindFirstChild("HumanoidRootPart")
    	if not hrp then
    		return {}
    	end
    	local collected = {}
    	local count = 0
    	for _, v in ipairs(Workspace:GetDescendants()) do
    		if count >= CONFIG.PART_CAP then
    			break
    		end
    		if v:IsA("BasePart") and not v.Anchored and not v:IsDescendantOf(char) then
    			if not v.Parent:FindFirstChildOfClass("Humanoid") then
    				local dist = (v.Position - hrp.Position).Magnitude
    				if dist < CONFIG.SCAN_RADIUS then
    					table.insert(collected, v)
    					count = count + 1
    				end
    			end
    		end
    	end
    	return collected
    end
    local function StartPhysicsEngine()
    	if SessionState.MainConnection then
    		SessionState.MainConnection:Disconnect()
    	end
    	SessionState.MainConnection = RunService.Heartbeat:Connect(function(dt)
    		if not SessionState.Active then
    			SessionState.MainConnection:Disconnect()
    			return
    		end
    		local char = LocalPlayer.Character
    		local hrp = char and char:FindFirstChild("HumanoidRootPart")
    		if not hrp then
    			return
    		end
    		SessionState.Angle = SessionState.Angle + (dt * CONFIG.ORBIT_SPEED)
    		ToggleCharacterCollision(false)
    		for part, data in pairs(SessionState.ManagedParts) do
    			if not part.Parent or part.Anchored then
    				pcall(function()
    					data.Vel:Destroy()
    				end)
    				pcall(function()
    					data.Spin:Destroy()
    				end)
    				SessionState.ManagedParts[part] = nil
    				continue
    			end
    			pcall(function()
    				part:SetNetworkOwner(LocalPlayer)
    			end)
    			local s = data.Seed
    			local offset = Vector3.new(
    				math.cos(SessionState.Angle + s) * CONFIG.ORBIT_RADIUS,
    				math.sin(SessionState.Angle * 0.5 + s) * CONFIG.VORTEX_HEIGHT,
    				math.sin(SessionState.Angle + s) * CONFIG.ORBIT_RADIUS
    			)
    			data.Vel.Velocity = ((hrp.Position + offset) - part.Position) * 20
    		end
    	end)
    end
    local function ToggleState(enabled)
    	SessionState.Active = enabled
    	if enabled then
    		local targetParts = CollectParts()
    		for _, part in ipairs(targetParts) do
    			local bv = Instance.new("BodyVelocity")
    			bv.MaxForce = Vector3.new(1, 1, 1) * math.huge
    			bv.Parent = part
    			local bav = Instance.new("BodyAngularVelocity")
    			bav.MaxTorque = Vector3.new(1, 1, 1) * math.huge
    			bav.AngularVelocity = Vector3.new(0, CONFIG.FLING_FORCE, 0)
    			bav.Parent = part
    			SessionState.ManagedParts[part] = {
    				Vel = bv,
    				Spin = bav,
    				Seed = math.random(1, 100),
    			}
    		end
    		StartPhysicsEngine()
    	else
    		for part, data in pairs(SessionState.ManagedParts) do
    			pcall(function()
    				data.Vel:Destroy()
    			end)
    			pcall(function()
    				data.Spin:Destroy()
    			end)
    		end
    		SessionState.ManagedParts = {}
    		ToggleCharacterCollision(true)
    	end
    end
    local function ConstructUI()
    	local parent = GetSafeParent()
    	if not parent then
    		return
    	end
    	local Screen = Instance.new("ScreenGui")
    	Screen.Name = "ArchitectVortex_v4_2"
    	Screen.Parent = parent
    	local Main = Instance.new("Frame")
    	Main.Size = UDim2.fromOffset(200, 80)
    	Main.Position = UDim2.new(0.5, -100, 0.1, 0)
    	Main.BackgroundColor3 = Color3.fromRGB(15, 15, 20)
    	Main.Parent = Screen
    	Instance.new("UICorner", Main).CornerRadius = UDim.new(0, 4)
    	local s = Instance.new("UIStroke", Main)
    	s.Color = Color3.fromRGB(0, 255, 170)
    	s.Thickness = 1.5
    	local ActionBtn = Instance.new("TextButton", Main)
    	ActionBtn.Size = UDim2.new(0.9, 0, 0.6, 0)
    	ActionBtn.Position = UDim2.new(0.05, 0, 0.2, 0)
    	ActionBtn.BackgroundColor3 = Color3.fromRGB(25, 25, 30)
    	ActionBtn.Text = "INITIATE VORTEX"
    	ActionBtn.TextColor3 = Color3.fromRGB(200, 200, 200)
    	ActionBtn.Font = Enum.Font.Code
    	ActionBtn.TextSize = 14
    	ActionBtn.Parent = Main
    	Instance.new("UICorner", ActionBtn)
    	ActionBtn.MouseButton1Click:Connect(function()
    		if not SessionState.Active then
    			ActionBtn.Text = "SHIELD ACTIVE"
    			ActionBtn.TextColor3 = Color3.fromRGB(0, 255, 170)
    			ToggleState(true)
    		else
    			ActionBtn.Text = "INITIATE VORTEX"
    			ActionBtn.TextColor3 = Color3.fromRGB(200, 200, 200)
    			ToggleState(false)
    		end
    	end)
    end
    task.spawn(function()
    	while true do
    		SetHiddenProperty(LocalPlayer, "SimulationRadius", CONFIG.SIM_RADIUS)
    		task.wait(1)
    	end
    end)
    ConstructUI()
end)
Modules.VelocitySpoofer = {
	State = {
		IsEnabled = false,
		RootPart = nil,
		Connections = {},
		Applying = false,
	},
	Config = {
		PoisonVector = Vector3.new(0, -20000, 0),
		PoisonJitter = 120,
		DisableRagdoll = true,
		DisableFallingDown = true,
		RagdollCheckInterval = 0.5,
		StripConstraints = true,
	},
}
function Modules.VelocitySpoofer:_getPoisonVector()
	local cfg = self.Config
	local base = cfg.PoisonVector
	local j = cfg.PoisonJitter
	return Vector3.new(base.X + math.random(-j, j), base.Y, base.Z + math.random(-j, j))
end
function Modules.VelocitySpoofer:_stripAttachedConstraints()
	local hrp = self.State.RootPart
	if not hrp then
		return
	end
	pcall(function()
		for _, c in ipairs(hrp:GetChildren()) do
			if
				c:IsA("LinearVelocity")
				or c:IsA("VectorForce")
				or c:IsA("BodyVelocity")
				or c:IsA("BodyForce")
				or c:IsA("AlignPosition")
				or c:IsA("RocketPropulsion")
			then
				c:Destroy()
			end
		end
		for _, c in ipairs(hrp:GetChildren()) do
			if c:IsA("Attachment") then
				for _, constraint in ipairs(c:GetChildren()) do
					if constraint:IsA("AlignPosition") or constraint:IsA("LinearVelocity") then
						constraint:Destroy()
					end
				end
			end
		end
	end)
end
function Modules.VelocitySpoofer:_applyVelocityChanger()
	if self.Applying then
		return
	end
	local hrp = self.State.RootPart
	if not hrp or not self.State.IsEnabled then
		return
	end
	self.Applying = true
	pcall(function()
		if self.Config.StripConstraints then
			self:_stripAttachedConstraints()
		end
		local real = hrp.AssemblyLinearVelocity
		hrp.AssemblyLinearVelocity = self:_getPoisonVector()
		RunService.RenderStepped:Wait()
		if hrp and hrp.Parent then
			hrp.AssemblyLinearVelocity = real
		end
	end)
	self.Applying = false
end
function Modules.VelocitySpoofer:_disableRagdollStates()
	local conn
	conn = RunService.Heartbeat:Connect(function()
		if not self.State.IsEnabled then
			conn:Disconnect()
			return
		end
		local char = LocalPlayer.Character
		if not char then
			return
		end
		local humanoid = char:FindFirstChildOfClass("Humanoid")
		if not humanoid then
			return
		end
		if self.Config.DisableFallingDown then
			humanoid:SetStateEnabled(Enum.HumanoidStateType.FallingDown, false)
		end
		if self.Config.DisableRagdoll then
			humanoid:SetStateEnabled(Enum.HumanoidStateType.Ragdoll, false)
		end
	end)
	self.State.Connections.RagdollGuard = conn
end
function Modules.VelocitySpoofer:_updateRootPart()
	if LocalPlayer.Character then
		self.State.RootPart = LocalPlayer.Character:FindFirstChild("HumanoidRootPart")
	end
end
function Modules.VelocitySpoofer:Enable()
	if self.State.IsEnabled then
		return
	end
	self.State.IsEnabled = true
	self.Applying = false
	self:_updateRootPart()
	self.State.Connections.Heartbeat = RunService.Heartbeat:Connect(function()
		if not self.State.RootPart and LocalPlayer.Character then
			self:_updateRootPart()
		end
		if self.State.RootPart and self.State.IsEnabled then
			self:_applyVelocityChanger()
		end
	end)
	self.State.Connections.CharacterAdded = LocalPlayer.CharacterAdded:Connect(function()
		task.wait(0.1)
		self:_updateRootPart()
	end)
	self:_disableRagdollStates()
	DoNotif("Velocity Spoofer: ENABLED", 2)
end
function Modules.VelocitySpoofer:Disable()
	if not self.State.IsEnabled then
		return
	end
	self.State.IsEnabled = false
	self.Applying = false
	for _, conn in pairs(self.State.Connections) do
		if conn then
			conn:Disconnect()
		end
	end
	self.State.Connections = {}
	local char = LocalPlayer.Character
	if char then
		local humanoid = char:FindFirstChildOfClass("Humanoid")
		if humanoid then
			humanoid:SetStateEnabled(Enum.HumanoidStateType.FallingDown, true)
			humanoid:SetStateEnabled(Enum.HumanoidStateType.Ragdoll, true)
		end
	end
	self.State.RootPart = nil
	DoNotif("Velocity Spoofer: DISABLED", 2)
end
function Modules.VelocitySpoofer:Toggle()
	if self.State.IsEnabled then
		self:Disable()
	else
		self:Enable()
	end
end
function Modules.VelocitySpoofer:SetPoisonVector(x, y, z)
	self.Config.PoisonVector = Vector3.new(tonumber(x) or 0, tonumber(y) or -10000, tonumber(z) or 0)
	local v = self.Config.PoisonVector
	DoNotif(("Poison Vector: (%.0f, %.0f, %.0f)"):format(v.X, v.Y, v.Z), 2)
end
function Modules.VelocitySpoofer:SetJitter(amount)
	self.Config.PoisonJitter = tonumber(amount) or 120
	DoNotif(("Jitter: ±%d"):format(self.Config.PoisonJitter), 2)
end
function Modules.VelocitySpoofer:ToggleRagdoll()
	self.Config.DisableRagdoll = not self.Config.DisableRagdoll
	DoNotif("Ragdoll Prevention: " .. (self.Config.DisableRagdoll and "ON" or "OFF"), 2)
end
function Modules.VelocitySpoofer:ToggleFallingDown()
	self.Config.DisableFallingDown = not self.Config.DisableFallingDown
	DoNotif("Falling Prevention: " .. (self.Config.DisableFallingDown and "ON" or "OFF"), 2)
end
function Modules.VelocitySpoofer:ToggleConstraintStripping()
	self.Config.StripConstraints = not self.Config.StripConstraints
	DoNotif("Constraint Stripping: " .. (self.Config.StripConstraints and "ON" or "OFF"), 2)
end
function Modules.VelocitySpoofer:Initialize()
	local module = self
	RegisterCommand({
		Name = "velocityspoof",
		Aliases = { "vspoof" },
		Description = "Spoofs velocity to counter aimbot attachment/network kicks.",
	}, function()
		module:Toggle()
	end)
	RegisterCommand({
		Name = "poisonvector",
		Aliases = { "setvector", "spoofvector" },
		Description = "Set the spoof vector. Usage: ;poisonvector <x> <y> <z>",
	}, function(args)
		if #args < 3 then
			local v = module.Config.PoisonVector
			DoNotif(("Current: (%.0f, %.0f, %.0f)"):format(v.X, v.Y, v.Z), 3)
			DoNotif("Usage: ;poisonvector <x> <y> <z>", 2)
			return
		end
		module:SetPoisonVector(args[1], args[2], args[3])
	end)
	RegisterCommand({
		Name = "spooferjitter",
		Aliases = { "vjitter" },
		Description = "Set XZ jitter amount for spoof pattern randomization.",
	}, function(args)
		module:SetJitter(args[1])
	end)
	RegisterCommand({
		Name = "stripconstraints",
		Aliases = { "stripvc" },
		Description = "Toggle automatic removal of LinearVelocity/force constraints.",
	}, function()
		module:ToggleConstraintStripping()
	end)
end
RegisterCommand({
	Name = "antiragdoll2",
	Aliases = {},
	Description = "Toggle ragdoll prevention.",
}, function()
	module:ToggleRagdoll()
end)
RegisterCommand({
	Name = "antifall",
	Aliases = { "nofall" },
	Description = "Toggle falling down state prevention.",
}, function()
	module:ToggleFallingDown()
end)
RegisterCommand({
	Name = "veloptions",
	Aliases = { "vspoofinfo" },
	Description = "Shows current velocity spoofer settings.",
}, function()
	print("=== Velocity Spoofer Settings ===")
	print("Status:", module.State.IsEnabled and "ENABLED" or "DISABLED")
	print(
		"Poison Vector:",
		string.format(
			"(%.0f, %.0f, %.0f)",
			module.Config.PoisonVector.X,
			module.Config.PoisonVector.Y,
			module.Config.PoisonVector.Z
		)
	)
	print("Anti-Ragdoll:", module.Config.DisableRagdoll and "ON" or "OFF")
	print("Anti-Fall:", module.Config.DisableFallingDown and "ON" or "OFF")
end)
RegisterCommand({
    Name        = "netenforcer",
    Aliases     = {"net2"},
    Description = "no problem.",
    ArgsDesc    = {},
    Permissions = {},
}, function(args, speaker)
    if not getgenv().Network then
    	getgenv().Network = {
    		BaseParts = {},
    		FakeConnections = {},
    		Connections = {},
    		Output = {
    			Enabled = true,
    			Prefix = "[NETWORK] ",
    			Send = function(Type, Output, BypassOutput)
    				if
    					typeof(Type) == "function"
    					and (Type == print or Type == warn or Type == error)
    					and typeof(Output) == "string"
    					and (typeof(BypassOutput) == "nil" or typeof(BypassOutput) == "boolean")
    				then
    					if Network["Output"].Enabled or BypassOutput then
    						Type(Network["Output"].Prefix .. Output)
    					end
    				elseif Network["Output"].Enabled then
    					error(Network["Output"].Prefix .. "Output Send Error : Invalid syntax.")
    				end
    			end,
    		},
    		LostParts = {},
    		CharacterRelative = true,
    		LastCharacter = nil,
    		TryKeep = true,
    		PartOwnership = {
    			PreMethodSettings = {},
    			Enabled = false,
    		},
    	}
    	Network["Output"].Send(print, ": Loading.")
    	Network["RetainPart"] = function(Part, Silent, ReturnFakePart)
    		assert(
    			Network["PartOwnership"]["Enabled"],
    			Network["Output"].Prefix .. " RetainPart Error : PartOwnership is Disabled."
    		)
    		assert(
    			typeof(Part) == "Instance" and Part:IsA("BasePart") and not Part:IsGrounded(),
    			Network["Output"].Prefix
    				.. "RetainPart Error : Invalid syntax: Arg1 (Part) must be an ungrounded BasePart which is a descendant of workspace."
    		)
    		if not Part:IsDescendantOf(workspace) then
    			Network["Output"].Send(
    				error,
    				"RetainPart Error : Invalid syntax: Arg1 (Part) must be an ungrounded BasePart which is a descendant of workspace."
    			)
    			local Index = table.find(Network["LostParts"], Part)
    			if Index then
    				table.remove(Network["LostParts"], Index)
    			end
    			return false
    		end
    		assert(
    			typeof(Silent) == "boolean" or typeof(Silent) == "nil",
    			Network["Output"].Prefix .. "RetainPart Error : Invalid syntax: Arg2 (Silent) must be a boolean or nil."
    		)
    		assert(
    			typeof(ReturnFakePart) == "boolean" or typeof(ReturnFakePart) == "nil",
    			Network["Output"].Prefix
    				.. "RetainPart Error : Invalid syntax: Arg3 (ReturnFakePart) must be a boolean or nil."
    		)
    		if not table.find(Network["BaseParts"], Part) and not table.find(Network["LostParts"], Part) then
    			table.insert(Network["BaseParts"], Part)
    			Part.CustomPhysicalProperties = PhysicalProperties.new(0, 0, 0, 0, 0)
    			if not Silent then
    				Network["Output"].Send(
    					print,
    					"PartOwnership Output : PartOwnership applied to BasePart " .. Part:GetFullName() .. "."
    				)
    			end
    			if ReturnFakePart then
    				local workspaceParts = {}
    				return FakePart
    			end
    		else
    			Network["Output"].Send(
    				warn,
    				"RetainPart Warning : PartOwnership not applied to BasePart "
    					.. Part:GetFullName()
    					.. ", as it already active."
    			)
    			return false
    		end
    	end
    	Network["RemovePart"] = function(Part, Silent)
    		assert(
    			typeof(Part) == "Instance" and Part:IsA("BasePart"),
    			Network["Output"].Prefix .. "RemovePart Error : Invalid syntax: Arg1 (Part) must be a BasePart."
    		)
    		local Index1 = table.find(Network["BaseParts"], Part)
    		local Index2 = table.find(Network["LostParts"], Part)
    		if Index1 then
    			table.remove(Network["BaseParts"], Index1)
    		else
    			if not Silent then
    				Network["Output"].Send(
    					warn,
    					"RemovePart Warning : BasePart " .. Part:GetFullName() .. " not found in BaseParts table."
    				)
    			end
    			return
    		end
    		if Index2 then
    			table.remove(Network["LostParts"], Index2)
    		end
    		if not Silent then
    			Network["Output"].Send(
    				print,
    				"RemovePart Output: PartOwnership removed from BasePart " .. Part:GetFullName() .. "."
    			)
    		end
    	end
    	Network["PartOwnership"]["PartCoroutine"] = coroutine.create(function(Part)
    		if Part:IsDescendantOf(workspace) then
    			if Network.CharacterRelative then
    				local Character = Network["LastCharacter"]
    				if not Character.PrimaryPart then
    					for _, Inst in pairs(Character:GetDescendants()) do
    						if Inst:IsA("BasePart") then
    							Character.PrimaryPart = Inst
    							break
    						end
    					end
    				end
    				if Character and Character.PrimaryPart then
    					local Distance = (Character.PrimaryPart.Position - Part.Position).Magnitude
    					if
    						Distance > gethiddenproperty(LocalPlayer, "MaximumSimulationRadius")
    						and not isnetworkowner(Part)
    					then
    						Network["Output"].Send(
    							warn,
    							"PartOwnership Warning : PartOwnership not applied to BasePart "
    								.. Part:GetFullName()
    								.. ", as it is more than "
    								.. gethiddenproperty(LocalPlayer, "MaximumSimulationRadius")
    								.. " studs away."
    						)
    						Network["RemovePart"](Part)
    						if not Part:IsGrounded() then
    							table.insert(Network["LostParts"], Part)
    						else
    							Network["Output"].Send(
    								warn,
    								"PartOwnership Warning : PartOwnership not applied to BasePart "
    									.. Part:GetFullName()
    									.. ", as it is grounded."
    							)
    						end
    					end
    				else
    					Network["Output"].Send(
    						warn,
    						"PartOwnership Warning : PartOwnership not applied to BasePart "
    							.. Part:GetFullName()
    							.. ", as the LocalPlayer Character's PrimaryPart does not exist."
    					)
    				end
    			end
    			Part.AssemblyLinearVelocity = (Part.AssemblyLinearVelocity.Unit + Vector3.new(0.01, 0.01, 0.01))
    				* (50 + math.cos(tick() * 10))
    		else
    			Network["RemovePart"](Part)
    		end
    	end)
    	Network["PartOwnership"]["Enable"] = coroutine.create(function()
    		if not Network["PartOwnership"]["Enabled"] then
    			Network["PartOwnership"]["Enabled"] = true
    			Network["PartOwnership"]["PreMethodSettings"].ReplicationFocus = LocalPlayer.ReplicationFocus
    			LocalPlayer.ReplicationFocus = workspace
    			Network["PartOwnership"]["PreMethodSettings"].SimulationRadius =
    				gethiddenproperty(LocalPlayer, "SimulationRadius")
    			Network["PartOwnership"]["Connection"] = RunService.Stepped:Connect(function()
    				Network["LastCharacter"] = pcall(function()
    					return LocalPlayer.Character
    				end) or Network["LastCharacter"]
    				sethiddenproperty(LocalPlayer, "SimulationRadius", 1 / 0)
    				coroutine.wrap(function()
    					for _, Part in pairs(Network["BaseParts"]) do
    						coroutine.resume(Network["PartOwnership"]["PartCoroutine"], Part)
    					end
    				end)()
    				coroutine.wrap(function()
    					for _, Part in pairs(Network["LostParts"]) do
    						Network.RetainPart(Part, true)
    					end
    				end)()
    			end)
    			Network["Output"].Send(print, "PartOwnership Output : PartOwnership enabled.")
    		else
    			Network["Output"].Send(warn, "PartOwnership Output : PartOwnership already enabled.")
    		end
    	end)
    	Network["PartOwnership"]["Disable"] = coroutine.create(function()
    		if Network["PartOwnership"]["Connection"] then
    			Network["PartOwnership"]["Connection"]:Disconnect()
    			LocalPlayer.ReplicationFocus = Network["PartOwnership"]["PreMethodSettings"].ReplicationFocus
    			sethiddenproperty(
    				LocalPlayer,
    				"SimulationRadius",
    				Network["PartOwnership"]["PreMethodSettings"].SimulationRadius
    			)
    			Network["PartOwnership"]["PreMethodSettings"] = {}
    			for _, Part in pairs(Network["BaseParts"]) do
    				Network["RemovePart"](Part)
    			end
    			for Index, Part in pairs(Network["LostParts"]) do
    				table.remove(Network["LostParts"], Index)
    			end
    			Network["PartOwnership"]["Enabled"] = false
    			Network["Output"].Send(print, "PartOwnership Output : PartOwnership disabled.")
    		else
    			Network["Output"].Send(warn, "PartOwnership Output : PartOwnership already disabled.")
    		end
    	end)
    	Network["Output"].Send(print, ": Loaded.")
    end
    coroutine.resume(Network["PartOwnership"]["Enable"])
end)

RegisterCommand({
    Name        = "punch",
    Aliases     = {"pu"},
    Description = "punch a nigga",
    ArgsDesc    = {},
    Permissions = {},
}, function(args, speaker)
    PunchTime = 30
    Power = 50
    Damage = 50
    Closed = false
    RunService = game:GetService("RunService")
    Player = game.Players.LocalPlayer
    function DoTheThing()
    	local Character = Player.Character
    	local RightArm = (Character:WaitForChild("Right Arm",1) or Character:WaitForChild("RightLowerArm"))
    	local RigType = Character:WaitForChild("Humanoid").RigType
    	local  PunchTool = Instance.new("Tool",Player.Backpack)
    	PunchTool.RequiresHandle = false
    	PunchTool.Name = "Punch"
    	PunchTool.ToolTip = "Punch anything really"
    	local Punching = false
    	local Anim = Instance.new("Animation", PunchTool)
    	if RigType == Enum.HumanoidRigType.R6 then
    		Anim.AnimationId = "rbxassetid://28156406"
    	else
    		Anim.AnimationId = "rbxassetid://10717116749"
    	end
    	local Track = Character:WaitForChild("Humanoid"):LoadAnimation(Anim)
    	PunchTool.Activated:Connect(function()
    		if not Punching then
    			Punching = true
    			Track:Play()
    			if RigType == Enum.HumanoidRigType.R6 then
    				task.wait(0.2)
    				Track:AdjustSpeed(3)
    			else
    				Track.TimePosition = 1.65
    				Track.Looped = false
    				Track:AdjustSpeed(1.1)
    			end
    			local Times = 0
    			RightArm.CanCollide = true
    			for Num, Part in RightArm:GetTouchingParts() do
    				if Part.Parent:FindFirstChildWhichIsA("Humanoid") and not Part:FindFirstAncestor(Player.Name) and game.Players:GetPlayerFromCharacter(Part.Parent) == nil then
    					local Humanoid = Part.Parent:WaitForChild("Humanoid")
    					Humanoid.Health -= Damage
    					Humanoid.HealthDisplayType = Enum.HumanoidHealthDisplayType.AlwaysOn
    					print(Humanoid.Health.."/"..Humanoid.MaxHealth)
    				end
    			end 
    			repeat RunService.Heartbeat:Wait()
    				RightArm.CanCollide = true
    				Times += 1
    				local root = Character:WaitForChild("HumanoidRootPart")
    				local vel, movel = nil, 0.1
    				while not (Character and Character.Parent and root and root.Parent) do
    					RunService.Heartbeat:Wait()
    					root = Character:WaitForChild("HumanoidRootPart")
    				end
    				vel = root.Velocity
    				root.Velocity = vel * Power + Vector3.new(0, Power, 0)
    				RunService.RenderStepped:Wait()
    				if Character and Character.Parent and root and root.Parent then
    					root.Velocity = vel
    				end
    				RunService.Stepped:Wait()
    				if Character and Character.Parent and root and root.Parent then
    					root.Velocity = vel + Vector3.new(0, movel, 0)
    					movel = movel * -1
    				end
    			until Times == PunchTime
    			Punching = false
    			game:GetService("UserInputService").InputBegan:Connect(function(Input, Processed)
    				if Processed then return end
    				if Input.KeyCode == Enum.KeyCode.Backspace then
    					PunchTool:Destroy()
    					print("Closed")
    					Closed = true
    					script:Destroy()
    				end
    			end)
    		end
    	end)
    end
    while not Player.Character do task.wait(0.1) end
    DoTheThing()
    Player.CharacterAdded:Connect(function()	
    	if not Closed then
    		DoTheThing()
    	end
    end)
end)
Modules.BadgeSpoofer = {
	State = {
		SpoofedBadges = {},
		IsHooked = false,
		OriginalFunctions = {},
		BadgeRemotes = {},
	},
}
function Modules.BadgeSpoofer:_findBadgeRemotes()
	self.State.BadgeRemotes = {}
	local function scan(container)
		for _, child in ipairs(container:GetDescendants()) do
			if child:IsA("RemoteEvent") or child:IsA("RemoteFunction") then
				local name = child.Name:lower()
				if name:find("badge") or name:find("award") or name:find("unlock") then
					table.insert(self.State.BadgeRemotes, child)
				end
			end
		end
	end
	scan(game:GetService("ReplicatedStorage"))
	scan(game:GetService("ReplicatedFirst"))
	return #self.State.BadgeRemotes
end
function Modules.BadgeSpoofer:_hookBadgeService()
	if self.State.IsHooked then
		return
	end
	local BadgeService = game:GetService("BadgeService")
	local mt = getrawmetatable(game)
	if not mt then
		DoNotif("Failed to get metatable", 3)
		return false
	end
	pcall(function()
		if setreadonly then
			setreadonly(mt, false)
		end
	end)
	local oldNamecall = mt.__namecall
	mt.__namecall = newcclosure(function(self, ...)
		local method = getnamecallmethod()
		local args = { ... }
		if method == "UserHasBadgeAsync" then
			local userId = args[1]
			local badgeId = args[2]
			if userId == LocalPlayer.UserId and Modules.BadgeSpoofer.State.SpoofedBadges[badgeId] then
				return true
			end
		end
		if method == "AwardBadge" then
			local userId = args[1]
			local badgeId = args[2]
			if userId == LocalPlayer.UserId then
				Modules.BadgeSpoofer.State.SpoofedBadges[badgeId] = true
				return true
			end
		end
		return oldNamecall(self, ...)
	end)
	pcall(function()
		if setreadonly then
			setreadonly(mt, true)
		end
	end)
	self.State.IsHooked = true
	return true
end
function Modules.BadgeSpoofer:_findGameBadges()
	local badges = {}
	local function searchForBadgeIds(container)
		for _, obj in ipairs(container:GetDescendants()) do
			if obj:IsA("IntValue") or obj:IsA("NumberValue") then
				if obj.Name:lower():find("badge") then
					local badgeId = obj.Value
					if badgeId > 0 then
						table.insert(badges, {
							Id = badgeId,
							Source = obj:GetFullName(),
						})
					end
				end
			end
			if obj:IsA("StringValue") then
				local str = obj.Value
				local badgeId = tonumber(str:match("(%d+)"))
				if badgeId and badgeId > 1000000 then
					table.insert(badges, {
						Id = badgeId,
						Source = obj:GetFullName(),
					})
				end
			end
			if obj:IsA("ModuleScript") then
				local success, source = pcall(function()
					return obj.Source
				end)
				if success and source then
					for badgeId in source:gmatch("(%d%d%d%d%d%d%d+)") do
						local id = tonumber(badgeId)
						if id then
							table.insert(badges, {
								Id = id,
								Source = obj.Name,
							})
						end
					end
				end
			end
		end
	end
	searchForBadgeIds(game:GetService("ReplicatedStorage"))
	searchForBadgeIds(game:GetService("ReplicatedFirst"))
	return badges
end
function Modules.BadgeSpoofer:SpoofBadge(badgeId)
	if not self.State.IsHooked then
		self:_hookBadgeService()
	end
	badgeId = tonumber(badgeId)
	if not badgeId then
		DoNotif("Invalid badge ID", 3)
		return
	end
	self.State.SpoofedBadges[badgeId] = true
	DoNotif(string.format("Spoofed badge: %d", badgeId), 2)
end
function Modules.BadgeSpoofer:SpoofAllFoundBadges()
	if not self.State.IsHooked then
		self:_hookBadgeService()
	end
	local badges = self:_findGameBadges()
	local count = 0
	for _, badgeData in ipairs(badges) do
		if not self.State.SpoofedBadges[badgeData.Id] then
			self.State.SpoofedBadges[badgeData.Id] = true
			count = count + 1
		end
	end
	DoNotif(string.format("Spoofed %d badges", count), 2)
end
function Modules.BadgeSpoofer:ListFoundBadges()
	local badges = self:_findGameBadges()
	print("\n=== FOUND BADGES ===")
	for i, badgeData in ipairs(badges) do
		print(string.format("%d. Badge ID: %d (from %s)", i, badgeData.Id, badgeData.Source))
	end
	print(string.format("\nTotal: %d badges", #badges))
	DoNotif(string.format("Found %d badges (check console)", #badges), 2)
end
function Modules.BadgeSpoofer:RemoveSpoof(badgeId)
	badgeId = tonumber(badgeId)
	if not badgeId then
		DoNotif("Invalid badge ID", 3)
		return
	end
	self.State.SpoofedBadges[badgeId] = nil
	DoNotif(string.format("Removed spoof: %d", badgeId), 2)
end
function Modules.BadgeSpoofer:ClearAllSpoofs()
	local count = 0
	for _ in pairs(self.State.SpoofedBadges) do
		count = count + 1
	end
	self.State.SpoofedBadges = {}
	DoNotif(string.format("Cleared %d spoofed badges", count), 2)
end
function Modules.BadgeSpoofer:ListSpoofedBadges()
	print("\n=== SPOOFED BADGES ===")
	local count = 0
	for badgeId, _ in pairs(self.State.SpoofedBadges) do
		count = count + 1
		print(string.format("%d. Badge ID: %d", count, badgeId))
	end
	print(string.format("\nTotal: %d spoofed", count))
	DoNotif(string.format("%d badges spoofed (check console)", count), 2)
end
function Modules.BadgeSpoofer:FireBadgeRemotes(badgeId)
	badgeId = tonumber(badgeId)
	if not badgeId then
		DoNotif("Invalid badge ID", 3)
		return
	end
	if #self.State.BadgeRemotes == 0 then
		self:_findBadgeRemotes()
	end
	local attempts = 0
	for _, remote in ipairs(self.State.BadgeRemotes) do
		pcall(function()
			if remote:IsA("RemoteEvent") then
				remote:FireServer(badgeId)
				remote:FireServer({ BadgeId = badgeId })
				remote:FireServer("Award", badgeId)
			elseif remote:IsA("RemoteFunction") then
				remote:InvokeServer(badgeId)
				remote:InvokeServer({ BadgeId = badgeId })
			end
			attempts = attempts + 1
		end)
		task.wait(0.05)
	end
	DoNotif(string.format("Fired %d badge remotes", attempts), 2)
end
function Modules.BadgeSpoofer:BruteForceUnlock(itemName)
	DoNotif("Brute forcing unlock for: " .. itemName, 2)
	local unlockRemotes = {}
	local function findUnlockRemotes(container)
		for _, remote in ipairs(container:GetDescendants()) do
			if remote:IsA("RemoteEvent") or remote:IsA("RemoteFunction") then
				local name = remote.Name:lower()
				if
					name:find("unlock")
					or name:find("equip")
					or name:find("purchase")
					or name:find("buy")
					or name:find("claim")
				then
					table.insert(unlockRemotes, remote)
				end
			end
		end
	end
	findUnlockRemotes(game:GetService("ReplicatedStorage"))
	local patterns = {
		itemName,
		{ Item = itemName },
		{ Name = itemName },
		{ ItemName = itemName },
		"Unlock",
		itemName,
		"Equip",
		itemName,
	}
	local attempts = 0
	for _, remote in ipairs(unlockRemotes) do
		for _, pattern in ipairs(patterns) do
			pcall(function()
				if remote:IsA("RemoteEvent") then
					remote:FireServer(pattern)
				else
					remote:InvokeServer(pattern)
				end
			end)
			attempts = attempts + 1
			task.wait(0.02)
		end
	end
	DoNotif(string.format("Tried %d unlock attempts", attempts), 2)
end
