Modules.AntiSlapGear = {
	State = {
		IsEnabled = false,
		SteppedConnection = nil,
		DescendantConn = nil,
		CharacterConn = nil,
		TouchConnections = {},
		LastSafePosition = nil,
		LastSafeTime = 0,
	},
	Config = {
		MAX_VELOCITY = 80,
		MAX_DELTA_STUDS = 25,
		ANCHOR_DURATION = 0.15,
		PHYSICS_TYPES = {
			"BodyVelocity",
			"BodyForce",
			"BodyThrust",
			"LinearVelocity",
			"VectorForce",
		},
		SLAP_PATTERNS = {
			"slap",
			"hand",
			"fling",
			"launch",
			"yeet",
			"smack",
			"punch",
			"whack",
			"slam",
		},
	},
}
function Modules.AntiSlapGear:_getHRP()
	local char = LocalPlayer.Character
	return char and char:FindFirstChild("HumanoidRootPart")
end
function Modules.AntiSlapGear:_isSlappy(name)
	local low = name:lower()
	for _, pat in ipairs(self.Config.SLAP_PATTERNS) do
		if low:find(pat, 1, true) then
			return true
		end
	end
	return false
end
function Modules.AntiSlapGear:_momentaryAnchor()
	local hrp = self:_getHRP()
	if not hrp or hrp.Anchored then
		return
	end
	hrp.Anchored = true
	hrp.AssemblyLinearVelocity = Vector3.zero
	hrp.AssemblyAngularVelocity = Vector3.zero
	task.delay(self.Config.ANCHOR_DURATION, function()
		local h = self:_getHRP()
		if h and self.State.IsEnabled then
			h.Anchored = false
		end
	end)
end
function Modules.AntiSlapGear:_enforceVelocity()
	local hrp = self:_getHRP()
	if not hrp or hrp.Anchored then
		return
	end
	local vel = hrp.AssemblyLinearVelocity
	if vel.Magnitude > self.Config.MAX_VELOCITY then
		hrp.AssemblyLinearVelocity = Vector3.zero
		hrp.AssemblyAngularVelocity = Vector3.zero
	end
	local pos = hrp.Position
	local now = tick()
	local safe = self.State.LastSafePosition
	if safe and (now - self.State.LastSafeTime) < 0.5 then
		local delta = (pos - safe).Magnitude
		if delta > self.Config.MAX_DELTA_STUDS then
			hrp.CFrame = CFrame.new(safe) * (hrp.CFrame - hrp.CFrame.Position)
			hrp.AssemblyLinearVelocity = Vector3.zero
			hrp.AssemblyAngularVelocity = Vector3.zero
			return
		end
	end
	if vel.Magnitude < 60 then
		self.State.LastSafePosition = pos
		self.State.LastSafeTime = now
	end
end
function Modules.AntiSlapGear:_watchDescendants(character)
	if self.State.DescendantConn then
		self.State.DescendantConn:Disconnect()
		self.State.DescendantConn = nil
	end
	self.State.DescendantConn = character.DescendantAdded:Connect(function(obj)
		if not self.State.IsEnabled then
			return
		end
		for _, t in ipairs(self.Config.PHYSICS_TYPES) do
			if obj:IsA(t) then
				task.defer(function()
					if obj and obj.Parent then
						pcall(function()
							obj:Destroy()
						end)
					end
				end)
				local hrp = self:_getHRP()
				if hrp then
					hrp.AssemblyLinearVelocity = Vector3.zero
					hrp.AssemblyAngularVelocity = Vector3.zero
				end
				return
			end
		end
	end)
end
function Modules.AntiSlapGear:_setupTouchGuards(character)
	for _, conn in pairs(self.State.TouchConnections) do
		pcall(function()
			conn:Disconnect()
		end)
	end
	self.State.TouchConnections = {}
	for _, part in ipairs(character:GetDescendants()) do
		if part:IsA("BasePart") then
			local conn = part.Touched:Connect(function(hit)
				if not self.State.IsEnabled then
					return
				end
				local suspect = hit
				local tool = hit:FindFirstAncestorOfClass("Tool") or hit:FindFirstAncestorOfClass("Model")
				if tool then
					suspect = tool
				end
				if self:_isSlappy(suspect.Name) or self:_isSlappy(hit.Name) then
					self:_momentaryAnchor()
				end
			end)
			self.State.TouchConnections[part] = conn
		end
	end
	character.DescendantAdded:Connect(function(obj)
		if not self.State.IsEnabled then
			return
		end
		if obj:IsA("BasePart") then
			task.wait()
			local conn = obj.Touched:Connect(function(hit)
				if not self.State.IsEnabled then
					return
				end
				local suspect = hit
				local tool = hit:FindFirstAncestorOfClass("Tool") or hit:FindFirstAncestorOfClass("Model")
				if tool then
					suspect = tool
				end
				if self:_isSlappy(suspect.Name) or self:_isSlappy(hit.Name) then
					self:_momentaryAnchor()
				end
			end)
			self.State.TouchConnections[obj] = conn
		end
	end)
end
function Modules.AntiSlapGear:_onCharacter(character)
	character:WaitForChild("HumanoidRootPart", 5)
	self.State.LastSafePosition = nil
	self:_watchDescendants(character)
	self:_setupTouchGuards(character)
end
function Modules.AntiSlapGear:Enable()
	if self.State.IsEnabled then
		return
	end
	self.State.IsEnabled = true
	if LocalPlayer.Character then
		self:_onCharacter(LocalPlayer.Character)
	end
	self.State.CharacterConn = LocalPlayer.CharacterAdded:Connect(function(char)
		if self.State.IsEnabled then
			self:_onCharacter(char)
		end
	end)
	self.State.SteppedConnection = RunService.Stepped:Connect(function()
		if self.State.IsEnabled then
			self:_enforceVelocity()
		end
	end)
	DoNotif("Anti Slap Gear: ENABLED", 2)
end
function Modules.AntiSlapGear:Disable()
	if not self.State.IsEnabled then
		return
	end
	self.State.IsEnabled = false
	if self.State.SteppedConnection then
		self.State.SteppedConnection:Disconnect()
		self.State.SteppedConnection = nil
	end
	if self.State.DescendantConn then
		self.State.DescendantConn:Disconnect()
		self.State.DescendantConn = nil
	end
	if self.State.CharacterConn then
		self.State.CharacterConn:Disconnect()
		self.State.CharacterConn = nil
	end
	for _, conn in pairs(self.State.TouchConnections) do
		pcall(function()
			conn:Disconnect()
		end)
	end
	self.State.TouchConnections = {}
	local hrp = self:_getHRP()
	if hrp then
		hrp.Anchored = false
	end
	DoNotif("Anti Slap Gear: DISABLED", 2)
end
function Modules.AntiSlapGear:Toggle()
	if self.State.IsEnabled then
		self:Disable()
	else
		self:Enable()
	end
end
RegisterCommand({
	Name = "antislapgear",
	Aliases = { "antislap", "nolaunch", "noslap" },
	Description = "Toggle anti slap gear — blocks velocity, physics objects, touch launches and CFrame teleports from slap gears",
}, function()
	Modules.AntiSlapGear:Toggle()
end)
Modules.PlayerLeech = {
	State = {
		IsLeeching = false,
		TargetPlayer = nil,
		Connections = {},
		LastTargetPos = nil,
		UI = nil,
	},
	Config = {
		OffsetX = 0,
		OffsetY = 1.5,
		OffsetZ = 3,
		RotationX = 0,
		RotationY = 180,
		RotationZ = 0,
		UseVelocitySpoof = false,
		SpoofVector = Vector3.new(0, -50000, 0),
		SpoofInterval = 0,
		FollowMode = "attach",
		StayBehind = true,
		EnableStrafing = false,
		StrafeSpeed = 2,
		StrafeRadius = 3,
		UpdateRate = 0.05,
	},
}
local RunService = game:GetService("RunService")
local Players = game:GetService("Players")
local LocalPlayer = Players.LocalPlayer
function Modules.PlayerLeech:_spoofVelocity()
	if not self.Config.UseVelocitySpoof then
		return
	end
	local character = LocalPlayer.Character
	if not character then
		return
	end
	local hrp = character:FindFirstChild("HumanoidRootPart")
	if not hrp then
		return
	end
	pcall(function()
		local realVelocity = hrp.AssemblyLinearVelocity
		hrp.AssemblyLinearVelocity = self.Config.SpoofVector
		task.wait()
		if hrp and hrp.Parent then
			hrp.AssemblyLinearVelocity = realVelocity
		end
	end)
end
function Modules.PlayerLeech:_calculatePosition(targetHRP)
	if not targetHRP then
		return nil
	end
	local offset = Vector3.new(self.Config.OffsetX, self.Config.OffsetY, self.Config.OffsetZ)
	local rotation =
		CFrame.Angles(math.rad(self.Config.RotationX), math.rad(self.Config.RotationY), math.rad(self.Config.RotationZ))
	if self.Config.StayBehind then
		return targetHRP.CFrame * CFrame.new(offset) * rotation
	else
		return CFrame.new(targetHRP.Position + offset) * rotation
	end
end
function Modules.PlayerLeech:_attachMode()
	local character = LocalPlayer.Character
	if not character or not character.Parent then
		return
	end
	local hrp = character:FindFirstChild("HumanoidRootPart")
	if not hrp or not hrp.Parent then
		return
	end
	local targetChar = self.State.TargetPlayer and self.State.TargetPlayer.Character
	if not targetChar or not targetChar.Parent then
		return
	end
	local targetHRP = targetChar:FindFirstChild("HumanoidRootPart")
	if not targetHRP or not targetHRP.Parent then
		return
	end
	pcall(function()
		local baseCFrame = self:_calculatePosition(targetHRP)
		if self.Config.EnableStrafing then
			local time = tick() * self.Config.StrafeSpeed
			local strafeOffset =
				Vector3.new(math.sin(time) * self.Config.StrafeRadius, 0, math.cos(time) * self.Config.StrafeRadius)
			baseCFrame = baseCFrame * CFrame.new(strafeOffset)
		end
		hrp.CFrame = baseCFrame
		hrp.AssemblyLinearVelocity = Vector3.zero
		hrp.AssemblyAngularVelocity = Vector3.zero
	end)
end
function Modules.PlayerLeech:_teleportMode()
	local character = LocalPlayer.Character
	if not character or not character.Parent then
		return
	end
	local hrp = character:FindFirstChild("HumanoidRootPart")
	if not hrp or not hrp.Parent then
		return
	end
	local targetChar = self.State.TargetPlayer and self.State.TargetPlayer.Character
	if not targetChar or not targetChar.Parent then
		return
	end
	local targetHRP = targetChar:FindFirstChild("HumanoidRootPart")
	if not targetHRP or not targetHRP.Parent then
		return
	end
	local currentPos = targetHRP.Position
	if self.State.LastTargetPos then
		local distance = (currentPos - self.State.LastTargetPos).Magnitude
		if distance < 5 then
			return
		end
	end
	self.State.LastTargetPos = currentPos
	pcall(function()
		local targetCFrame = self:_calculatePosition(targetHRP)
		hrp.CFrame = targetCFrame
	end)
end
function Modules.PlayerLeech:Start(playerName)
	if self.State.IsLeeching then
		print("⚠ Already leeching someone")
		return
	end
	local targetPlayer = Utilities.findPlayer(playerName)
	if not targetPlayer then
		print("✗ Player not found: " .. playerName)
		return
	end
	if targetPlayer == LocalPlayer then
		print("✗ Cannot leech yourself")
		return
	end
	self.State.TargetPlayer = targetPlayer
	self.State.IsLeeching = true
	self.State.LastTargetPos = nil
	local character = LocalPlayer.Character
	if character then
		local humanoid = character:FindFirstChild("Humanoid")
		if humanoid then
			pcall(function()
				humanoid:SetStateEnabled(Enum.HumanoidStateType.FallingDown, false)
				humanoid:SetStateEnabled(Enum.HumanoidStateType.Ragdoll, false)
				humanoid:SetStateEnabled(Enum.HumanoidStateType.Physics, false)
			end)
		end
	end
	self.State.Connections.LeechLoop = RunService.Heartbeat:Connect(function()
		if not self.State.IsLeeching then
			return
		end
		if not self.State.TargetPlayer or not self.State.TargetPlayer.Parent then
			print("✗ Target left game")
			self:Stop()
			return
		end
		if not self.State.TargetPlayer.Character then
			return
		end
		pcall(function()
			if self.Config.FollowMode == "attach" then
				self:_attachMode()
			else
				self:_teleportMode()
			end
		end)
		task.wait(self.Config.UpdateRate)
	end)
	print(string.format("✓ Leeching: %s (%s mode)", targetPlayer.DisplayName, self.Config.FollowMode))
end
function Modules.PlayerLeech:Stop()
	if not self.State.IsLeeching then
		return
	end
	self.State.IsLeeching = false
	self.State.TargetPlayer = nil
	self.State.LastTargetPos = nil
	for _, conn in pairs(self.State.Connections) do
		if conn then
			pcall(function()
				conn:Disconnect()
			end)
		end
	end
	self.State.Connections = {}
	local character = LocalPlayer.Character
	if character then
		local hrp = character:FindFirstChild("HumanoidRootPart")
		if hrp then
			pcall(function()
				sethiddenproperty(hrp, "PhysicsRepRootPart", nil)
			end)
		end
		local humanoid = character:FindFirstChild("Humanoid")
		if humanoid then
			pcall(function()
				humanoid:SetStateEnabled(Enum.HumanoidStateType.FallingDown, true)
				humanoid:SetStateEnabled(Enum.HumanoidStateType.Ragdoll, true)
