			rl.VerticalAlignment = Enum.VerticalAlignment.Center
			local down = mkSliderBtn(row, "−")
			local bar = Instance.new("Frame", row)
			bar.Size = UDim2.new(1, -2 * (28 + 6), 1, 0)
			bar.BackgroundColor3 = Color3.fromRGB(30, 30, 45)
