		then
			local d = input.Position - self.State.DragStart
			win.Position = UDim2.new(
				self.State.StartPos.X.Scale,
				self.State.StartPos.X.Offset + d.X,
				self.State.StartPos.Y.Scale,
				self.State.StartPos.Y.Offset + d.Y
			)
		end
	end)
