			[[for _, v in ipairs(game:GetService("ReplicatedStorage"):GetDescendants()) do if v:IsA("Tool") then v:Clone().Parent = game.Players.LocalPlayer.Backpack end end]],
		},
		SuspiciousRequirePatterns = {
