RegisterCommand({
	Name = "ownlocal",
	Aliases = { "netlocal" },
	Description = "fuck if i know idc anymore",
	ArgsDesc = {},
	Permissions = {},
}, function(args, speaker)
	if not getgenv().SovereigntyEngine then
		getgenv().SovereigntyEngine = {
			Enabled = true,
			MaxRadius = math.huge,
			VelocityLock = true,
			AntiSleep = true,
			CharacterAuthority = true,
		}
	end
	local Players = game:GetService("Players")
	local RunService = game:GetService("RunService")
	local Settings = settings()
	local LocalPlayer = Players.LocalPlayer
	local hasHiddenProp = (sethiddenproperty ~= nil)
	local function getChar()
		return LocalPlayer.Character
	end
	task.spawn(function()
		while getgenv().SovereigntyEngine.Enabled do
			if hasHiddenProp then
				sethiddenproperty(LocalPlayer, "SimulationRadius", 1000)
				sethiddenproperty(LocalPlayer, "MaxSimulationRadius", 1000)
			end
			if getgenv().SovereigntyEngine.AntiSleep then
				Settings.Physics.AllowSleep = false
			end
			task.wait(0.1)
		end
	end)
	RunService.Stepped:Connect(function()
		if not getgenv().SovereigntyEngine.Enabled or not getgenv().SovereigntyEngine.CharacterAuthority then
			return
		end
		local char = getChar()
		if char then
			local root = char:FindFirstChild("HumanoidRootPart")
			local hum = char:FindFirstChildOfClass("Humanoid")
			if root then
				root.Anchored = false
				if hum then
					hum.PlatformStand = false
					hum:SetStateEnabled(Enum.HumanoidStateType.FallingDown, false)
					hum:SetStateEnabled(Enum.HumanoidStateType.Ragdoll, false)
				end
				if getgenv().SovereigntyEngine.VelocityLock then
					local currentVel = root.Velocity
					root.Velocity = currentVel + Vector3.new(0, 0.01, 0)
				end
			end
			for _, part in ipairs(char:GetDescendants()) do
				if part:IsA("BasePart") then
					part.CanCollide = true
				end
			end
		end
	end)
	local oldIndex
	oldIndex = hookmetamethod(game, "__index", function(self, key)
		if not checkcaller() and getgenv().SovereigntyEngine.Enabled then
			if key == "SimulationRadius" and self == LocalPlayer then
				return 1000
			end
		end
		return oldIndex(self, key)
	end)
	LocalPlayer.CharacterAdded:Connect(function(newChar)
		task.wait(0.5)
		print("[CALLUM] Re-establishing Sovereignty on new character...")
	end)
end)
RegisterCommand({
	Name = "noabuse",
	Aliases = { "nohd" },
	Description = "fuck you abuser noobs",
	ArgsDesc = {},
	Permissions = {},
}, function(args, speaker)
	if not getgenv().CallumShield then
		getgenv().CallumShield = {
			Enabled = true,
			AntiExplosion = true,
			AntiFling = true,
			AntiVisuals = true,
			AntiGUI = true,
			AntiSit = true,
			AntiAnchor = true,
			GodModeFallback = true,
		}
	end
	local Players = game:GetService("Players")
	local RunService = game:GetService("RunService")
	local LocalPlayer = Players.LocalPlayer
	local PlayerGui = LocalPlayer:WaitForChild("PlayerGui")
	local function getChar()
		return LocalPlayer.Character
	end
	local function notify(msg)
		print("[CALLUM] " .. msg)
	end
	local oldInstanceNew
	oldInstanceNew = hookfunction(Instance.new, function(className, parent)
		if not checkcaller() and getgenv().CallumShield.Enabled then
			if className == "Explosion" and getgenv().CallumShield.AntiExplosion then
				notify("Blocked an Explosion attempt.")
				return nil
			end
			local visualClasses =
				{ "Fire", "Smoke", "Sparkles", "ParticleEmitter", "SelectionBox", "SelectionHighlight" }
			if getgenv().CallumShield.AntiVisuals then
				for _, name in ipairs(visualClasses) do
					if className == name then
						if parent and (parent:IsDescendantOf(getChar()) or parent == getChar()) then
							notify("Blocked visual abuse: " .. className)
							return nil
						end
					end
				end
			end
		end
		return oldInstanceNew(className, parent)
	end)
	PlayerGui.ChildAdded:Connect(function(child)
		if getgenv().CallumShield.AntiGUI and not checkcaller() then
			task.wait(0.1)
			local name = child.Name:lower()
			local keywords = { "blind", "effect", "message", "hint", "jail", "scare", "gui" }
			for _, word in ipairs(keywords) do
				if name:find(word) then
					child:Destroy()
					notify("Destroyed malicious GUI: " .. name)
					break
				end
			end
		end
	end)
	RunService.Heartbeat:Connect(function()
		if not getgenv().CallumShield.Enabled then
			return
		end
		local char = getChar()
		if not char then
			return
		end
		local root = char:FindFirstChild("HumanoidRootPart")
		local hum = char:FindFirstChildOfClass("Humanoid")
		if root and hum then
			if getgenv().CallumShield.AntiFling then
				if root.Velocity.Magnitude > 100 or root.RotVelocity.Magnitude > 100 then
					root.Velocity = Vector3.new(0, 0, 0)
					root.RotVelocity = Vector3.new(0, 0, 0)
				end
			end
			if getgenv().CallumShield.AntiSit and hum.Sit then
				hum.Sit = false
			end
			if getgenv().CallumShield.AntiAnchor and root.Anchored then
				root.Anchored = false
			end
			if getgenv().CallumShield.AntiFling then
				for _, v in ipairs(root:GetChildren()) do
					if v:IsA("BodyMover") or v:IsA("ForceSite") then
						v:Destroy()
					end
				end
			end
		end
	end)
	if getChar() then
		getChar().ChildAdded:Connect(function(child)
			if not getgenv().CallumShield.Enabled then
				return
			end
			task.wait(0.1)
			if child:IsA("BasePart") and child.Name ~= "HumanoidRootPart" and not child:IsDescendantOf(getChar()) then
				if not child:FindFirstChildOfClass("Weld") and not child:FindFirstChildOfClass("Motor6D") then
					child:Destroy()
					notify("Removed attached admin object.")
				end
			end
		end)
	end
	notify("Shield Fully Charged. Explode and Fling protections are ACTIVE.")
end)
