function Modules.PlayerLookup:_createInfoRows()
	local C = self.Config.Colors
	local Card = self.State.UI.Card
	local function makeRow(icon, label, yOff, copyable)
		local row = make("Frame", {
			Size = UDim2.new(1, -24, 0, 28),
			Position = UDim2.fromOffset(12, yOff),
			BackgroundColor3 = C.RAISED,
			BorderSizePixel = 0,
		}, Card)
		corner(6, row)
		make("TextLabel", {
			Size = UDim2.fromOffset(22, 28),
			Position = UDim2.fromOffset(6, 0),
			BackgroundTransparency = 1,
			Text = icon,
			TextColor3 = C.ACCENT,
			TextSize = 12,
			Font = Enum.Font.Gotham,
		}, row)
		make("TextLabel", {
			Size = UDim2.fromOffset(76, 28),
			Position = UDim2.fromOffset(26, 0),
			BackgroundTransparency = 1,
			Text = label,
			TextColor3 = C.MUTED,
			TextSize = 10,
			Font = Enum.Font.GothamBold,
			TextXAlignment = Enum.TextXAlignment.Left,
		}, row)
		local val = make("TextLabel", {
			Size = UDim2.new(1, copyable and -136 or -110, 1, 0),
			Position = UDim2.fromOffset(104, 0),
			BackgroundTransparency = 1,
			Text = "—",
			TextColor3 = C.TEXT,
			TextSize = 11,
			Font = Enum.Font.Gotham,
			TextXAlignment = Enum.TextXAlignment.Left,
			TextTruncate = Enum.TextTruncate.AtEnd,
		}, row)
		if copyable then
			local cp = make("TextButton", {
				Size = UDim2.fromOffset(34, 18),
				Position = UDim2.new(1, -38, 0.5, -9),
				BackgroundColor3 = C.BORDER,
				BorderSizePixel = 0,
				Text = "copy",
				TextColor3 = C.MUTED,
				TextSize = 9,
				Font = Enum.Font.GothamBold,
				AutoButtonColor = false,
			}, row)
			corner(0, cp)
			cp.MouseButton1Click:Connect(function()
				copyToClipboard(val.Text)
				tw(cp, { BackgroundColor3 = C.GREEN, TextColor3 = Color3.new(0, 0, 0) }, 0.1)
				task.wait(0.9)
				tw(cp, { BackgroundColor3 = C.BORDER, TextColor3 = C.MUTED }, 0.15)
			end)
		end
		return val
	end
	self.State.UI.InfoRows = {
		id = makeRow("#", "USER ID", 84, true),
		url = makeRow("⎘", "PROFILE URL", 118, true),
		age = makeRow("⏱", "ACCT AGE", 152, false),
		joined = makeRow("📅", "JOINED", 186, false),
		inSrv = makeRow("◉", "IN SERVER", 220, false),
	}
end
function Modules.PlayerLookup:_setupEventHandlers()
	local GoBtn = self.State.UI.GoBtn
	local SearchInput = self.State.UI.SearchInput
	GoBtn.MouseButton1Click:Connect(function()
		self:_doSearch(SearchInput.Text)
	end)
	SearchInput.FocusLost:Connect(function(enter)
		if enter then
			self:_doSearch(SearchInput.Text)
		end
	end)
	Players.PlayerAdded:Connect(function()
		task.wait(0.5)
		self:_buildPlayerList()
	end)
	Players.PlayerRemoving:Connect(function()
		task.wait(0.1)
		self:_buildPlayerList()
	end)
end
function Modules.PlayerLookup:_clearBadges()
	for _, b in ipairs(self.State.CurrentBadges) do
		pcall(function()
			b:Destroy()
		end)
	end
	self.State.CurrentBadges = {}
end
function Modules.PlayerLookup:_addBadge(text, color)
	local b = make("Frame", {
		Size = UDim2.fromOffset(0, 16),
		BackgroundColor3 = color,
		BorderSizePixel = 0,
		AutomaticSize = Enum.AutomaticSize.X,
	}, self.State.UI.BadgeRow)
	corner(3, b)
	make("TextLabel", {
		Size = UDim2.new(1, 0, 1, 0),
		BackgroundTransparency = 1,
		Text = text,
		TextColor3 = Color3.new(1, 1, 1),
		TextSize = 9,
		Font = Enum.Font.GothamBold,
		AutomaticSize = Enum.AutomaticSize.X,
	}, b)
	make("UIPadding", {
		PaddingLeft = UDim.new(0, 5),
		PaddingRight = UDim.new(0, 5),
	}, b)
	table.insert(self.State.CurrentBadges, b)
end
function Modules.PlayerLookup:_buildPlayerList()
	if not self.State.UI then
		return
	end
	local ListFrame = self.State.UI.ListFrame
	local C = self.Config.Colors
	for _, c in ipairs(ListFrame:GetChildren()) do
		if not c:IsA("UIListLayout") and not c:IsA("UIPadding") then
			c:Destroy()
		end
	end
	local plrs = Players:GetPlayers()
	for _, plr in ipairs(plrs) do
		local card = make("TextButton", {
			Size = UDim2.fromOffset(58, 58),
			BackgroundColor3 = plr == LocalPlayer and C.BORDER or C.RAISED,
			BorderSizePixel = 0,
			Text = "",
			AutoButtonColor = false,
		}, ListFrame)
		corner(8, card)
		stroke(1, plr == LocalPlayer and C.ACCENT or C.BORDER, card)
		local img = make("ImageLabel", {
			Size = UDim2.fromOffset(38, 38),
			Position = UDim2.new(0.5, -19, 0, 4),
			BackgroundColor3 = C.RAISED,
			BackgroundTransparency = 0,
			Image = "",
			ScaleType = Enum.ScaleType.Fit,
		}, card)
		corner(6, img)
		make("TextLabel", {
			Size = UDim2.new(1, -4, 0, 13),
			Position = UDim2.fromOffset(2, 43),
			BackgroundTransparency = 1,
			Text = plr.Name,
			TextColor3 = plr == LocalPlayer and C.TEXT or C.MUTED,
			TextSize = 9,
			Font = Enum.Font.Gotham,
			TextTruncate = Enum.TextTruncate.AtEnd,
		}, card)
		task.spawn(function()
			local ok, thumb = withTimeout(
				6,
				Players.GetUserThumbnailAsync,
				Players,
				plr.UserId,
				Enum.ThumbnailType.HeadShot,
				Enum.ThumbnailSize.Size60x60
			)
			if ok and img and img.Parent then
				img.Image = thumb
			end
		end)
		card.MouseEnter:Connect(function()
			tw(card, { BackgroundColor3 = C.BORDER }, 0.1)
		end)
		card.MouseLeave:Connect(function()
			tw(card, { BackgroundColor3 = plr == LocalPlayer and C.BORDER or C.RAISED }, 0.1)
		end)
		card.MouseButton1Click:Connect(function()
			self:_lookupPlayer(plr)
		end)
	end
	ListFrame.CanvasSize = UDim2.fromOffset(#plrs * 64 + 6, 0)
end
function Modules.PlayerLookup:_lookupPlayer(plr)
	if not plr or not self.State.UI then
		return
	end
	self.State.SearchToken = self.State.SearchToken + 1
	local myToken = self.State.SearchToken
	local C = self.Config.Colors
	local UI = self.State.UI
	local R = UI.InfoRows
	self:_clearBadges()
	UI.AvatarImg.Image = ""
	UI.AvatarLoading.Text = "..."
	UI.Card.Visible = false
	task.spawn(function()
		local tOk, thumb = withTimeout(
			6,
			Players.GetUserThumbnailAsync,
			Players,
			plr.UserId,
			Enum.ThumbnailType.HeadShot,
			Enum.ThumbnailSize.Size100x100
		)
		if self.State.SearchToken ~= myToken then
			return
		end
		UI.AvatarImg.Image = (tOk and thumb) or "rbxasset://textures/ui/GuiImagePlaceholder.png"
		UI.AvatarLoading.Text = ""
		UI.DisplayNameLbl.Text = plr.DisplayName or plr.Name
		UI.UsernameLbl.Text = "@" .. plr.Name
		if plr == LocalPlayer then
			self:_addBadge("YOU", Color3.fromRGB(139, 92, 246))
		end
		if plr.Name ~= plr.DisplayName then
			self:_addBadge("ALIAS", Color3.fromRGB(16, 185, 129))
		end
		self:_addBadge("IN SERVER", Color3.fromRGB(59, 130, 246))
		R.id.Text = tostring(plr.UserId)
		R.url.Text = "roblox.com/users/" .. plr.UserId .. "/profile"
		R.age.Text = accountAge(plr.AccountAge) .. " (" .. plr.AccountAge .. "d)"
		R.inSrv.Text = "yes"
		R.inSrv.TextColor3 = C.GREEN
		local iOk, info = withTimeout(8, Players.GetPlayerInfoAsync, Players, plr.UserId)
		if self.State.SearchToken ~= myToken then
			return
		end
		if iOk and info and info.JoinDate then
			local dOk, dt = pcall(DateTime.fromUnixTimestamp, info.JoinDate.UnixTimestamp)
			if dOk then
				local t = dt:ToLocalTime()
				R.joined.Text = string.format("%02d/%02d/%04d", t.Month, t.Day, t.Year)
			else
				R.joined.Text = tostring(info.JoinDate)
			end
		else
			R.joined.Text = "unavailable"
			R.joined.TextColor3 = C.MUTED
		end
		UI.Card.BackgroundTransparency = 1
		UI.Card.Visible = true
		tw(UI.Card, { BackgroundTransparency = 0 }, 0.2)
	end)
end
function Modules.PlayerLookup:_doSearch(raw)
	if not self.State.UI then
		return
	end
	raw = raw:match("^%s*(.-)%s*$")
	if raw == "" then
		return
	end
	if raw == self.State.LastSearchText and self.State.SearchDebounce then
		return
	end
	self.State.LastSearchText = raw
	self.State.SearchDebounce = true
	self.State.SearchToken = self.State.SearchToken + 1
	local myToken = self.State.SearchToken
	local asId = tonumber(raw)
	for _, plr in ipairs(Players:GetPlayers()) do
		if plr.Name:lower() == raw:lower() or (asId and plr.UserId == asId) then
			self.State.SearchDebounce = false
			self:_lookupPlayer(plr)
			return
		end
	end
	DoNotif("Searching for: " .. raw, 2)
	task.spawn(function()
		local userId = asId
		if not userId then
			local ok, res = withTimeout(8, Players.GetUserIdFromNameAsync, Players, raw)
			if self.State.SearchToken ~= myToken then
				self.State.SearchDebounce = false
				return
			end
			if not ok or not res then
				DoNotif("Player not found: " .. raw, 3)
				self.State.SearchDebounce = false
				return
			end
			userId = res
		end
		local infoResult, thumbResult = nil, nil
		local infoDone, thumbDone = false, false
		task.spawn(function()
			local ok, res = withTimeout(8, Players.GetPlayerInfoAsync, Players, userId)
			infoResult = { ok = ok, data = res }
			infoDone = true
		end)
		task.spawn(function()
			local ok, res = withTimeout(
				6,
				Players.GetUserThumbnailAsync,
				Players,
				userId,
				Enum.ThumbnailType.HeadShot,
				Enum.ThumbnailSize.Size100x100
			)
			thumbResult = { ok = ok, data = res }
			thumbDone = true
		end)
		local waited = 0
		while (not infoDone or not thumbDone) and waited < 10 do
			task.wait(0.05)
			waited = waited + 0.05
		end
		if self.State.SearchToken ~= myToken then
			self.State.SearchDebounce = false
			return
		end
		local info = infoResult and infoResult.ok and infoResult.data
		local thumb = thumbResult and thumbResult.ok and thumbResult.data
		local UI = self.State.UI
		local R = UI.InfoRows
		local C = self.Config.Colors
		self:_clearBadges()
		UI.AvatarImg.Image = thumb or "rbxasset://textures/ui/GuiImagePlaceholder.png"
		UI.AvatarLoading.Text = ""
		UI.DisplayNameLbl.Text = (info and info.DisplayName) or tostring(userId)
		UI.UsernameLbl.Text = "@" .. ((info and info.Username) or tostring(userId))
		self:_addBadge("NOT IN SERVER", Color3.fromRGB(107, 114, 128))
		R.id.Text = tostring(userId)
		R.url.Text = "roblox.com/users/" .. userId .. "/profile"
		R.age.Text = "unavailable"
		R.inSrv.Text = "no"
		R.inSrv.TextColor3 = C.RED
		if info and info.JoinDate then
			local dOk, dt = pcall(DateTime.fromUnixTimestamp, info.JoinDate.UnixTimestamp)
			if dOk then
				local t = dt:ToLocalTime()
				R.joined.Text = string.format("%02d/%02d/%04d", t.Month, t.Day, t.Year)
			else
				R.joined.Text = "unavailable"
			end
		else
			R.joined.Text = "unavailable"
		end
		UI.Card.BackgroundTransparency = 1
		UI.Card.Visible = true
		tw(UI.Card, { BackgroundTransparency = 0 }, 0.2)
		self.State.SearchDebounce = false
	end)
end
function Modules.PlayerLookup:Open()
	if self.State.IsOpen then
		return
	end
	self.State.IsOpen = true
	self:_createUI()
	DoNotif("Player Lookup opened", 2)
end
function Modules.PlayerLookup:Close()
	if not self.State.IsOpen or not self.State.UI then
		return
	end
	self.State.IsOpen = false
	local Main = self.State.UI.Main
	tw(Main, { BackgroundTransparency = 1, Position = UDim2.new(0.5, -180, 0.5, -225) }, 0.18)
	task.wait(0.2)
	if self.State.UI and self.State.UI.ScreenGui then
		self.State.UI.ScreenGui:Destroy()
	end
	self.State.UI = nil
	DoNotif("Player Lookup closed", 2)
end
function Modules.PlayerLookup:Toggle()
	if self.State.IsOpen then
		self:Close()
	else
		self:Open()
	end
end
function Modules.PlayerLookup:LookupUsername(username)
	if not self.State.IsOpen then
		self:Open()
		task.wait(0.4)
	end
	if self.State.UI and self.State.UI.SearchInput then
		self.State.UI.SearchInput.Text = username
		self:_doSearch(username)
	end
end
function Modules.PlayerLookup:LookupUserId(userId)
	if not self.State.IsOpen then
		self:Open()
		task.wait(0.4)
	end
	if self.State.UI and self.State.UI.SearchInput then
		self.State.UI.SearchInput.Text = tostring(userId)
		self:_doSearch(tostring(userId))
	end
end
function Modules.PlayerLookup:Initialize()
	local module = self
	RegisterCommand({
		Name = "lookup",
		Aliases = { "plookup", "playerinfo", "whois" },
		Description = "Opens player lookup GUI or searches for a player.",
	}, function(args)
		if not args[1] then
			module:Toggle()
		else
			local search = table.concat(args, " ")
			module:LookupUsername(search)
		end
	end)
	RegisterCommand({
		Name = "lookupid",
		Aliases = { "plookupid" },
		Description = "Lookup a player by their User ID.",
	}, function(args)
		if not args[1] then
			return DoNotif("Usage: ;lookupid <userid>", 3)
		end
		local userId = tonumber(args[1])
		if not userId then
			return DoNotif("Invalid User ID", 3)
		end
		module:LookupUserId(userId)
	end)
end
Modules.NetworkClaim = {
	State = {
		IsEnabled = false,
		ClaimedObjects = {},
		SelectedObject = nil,
		UI = nil,
		Connections = {},
		AutoClaim = false,
	},
	Config = {
		HighlightColor = Color3.fromRGB(255, 100, 0),
		ClaimMethod = "ownership",
		UpdateRate = 0.03,
		ShowVisuals = true,
	},
}
local TweenService = game:GetService("TweenService")
local RunService = game:GetService("RunService")
local Players = game:GetService("Players")
local LocalPlayer = Players.LocalPlayer
function Modules.NetworkClaim:_createUI()
	local screenGui = Instance.new("ScreenGui")
	screenGui.Name = "NetworkClaim_Zuka"
	screenGui.ResetOnSpawn = false
	screenGui.ZIndexBehavior = Enum.ZIndexBehavior.Global
	self.State.UI = screenGui
	local mainFrame = Instance.new("Frame")
	mainFrame.Name = "MainFrame"
	mainFrame.Size = UDim2.fromOffset(380, 560)
	mainFrame.Position = UDim2.new(1, -390, 0.5, -280)
	mainFrame.BackgroundColor3 = Color3.fromRGB(25, 25, 35)
	mainFrame.BorderSizePixel = 0
	mainFrame.Parent = screenGui
	Instance.new("UICorner", mainFrame).CornerRadius = UDim.new(0, 8)
	local stroke = Instance.new("UIStroke", mainFrame)
	stroke.Color = Color3.fromRGB(255, 100, 0)
	stroke.Thickness = 2
	local glowTween =
		TweenService:Create(stroke, TweenInfo.new(1, Enum.EasingStyle.Sine, Enum.EasingDirection.InOut, -1, true), {
			Thickness = 3,
		})
	glowTween:Play()
	local titleBar = Instance.new("Frame", mainFrame)
	titleBar.Name = "TitleBar"
	titleBar.Size = UDim2.new(1, 0, 0, 35)
	titleBar.BackgroundColor3 = Color3.fromRGB(20, 20, 30)
	titleBar.BorderSizePixel = 0
	Instance.new("UICorner", titleBar).CornerRadius = UDim.new(0, 8)
	local title = Instance.new("TextLabel", titleBar)
	title.Size = UDim2.new(1, -90, 1, 0)
	title.Position = UDim2.fromOffset(10, 0)
	title.BackgroundTransparency = 1
	title.Font = Enum.Font.Code
	title.Text = "▸ NETWORK CLAIM"
	title.TextColor3 = Color3.fromRGB(255, 100, 0)
	title.TextSize = 16
	title.TextXAlignment = Enum.TextXAlignment.Left
	local statusIndicator = Instance.new("TextLabel", titleBar)
	statusIndicator.Name = "StatusIndicator"
	statusIndicator.Size = UDim2.fromOffset(90, 20)
	statusIndicator.Position = UDim2.new(1, -160, 0.5, -10)
	statusIndicator.BackgroundColor3 = Color3.fromRGB(50, 50, 50)
	statusIndicator.BorderSizePixel = 0
	statusIndicator.Font = Enum.Font.GothamBold
	statusIndicator.Text = "0 CLAIMED"
	statusIndicator.TextColor3 = Color3.fromRGB(200, 200, 200)
	statusIndicator.TextSize = 10
	Instance.new("UICorner", statusIndicator).CornerRadius = UDim.new(0, 4)
	local closeBtn = Instance.new("TextButton", titleBar)
	closeBtn.Size = UDim2.fromOffset(30, 30)
	closeBtn.Position = UDim2.new(1, -32, 0, 2)
	closeBtn.BackgroundColor3 = Color3.fromRGB(255, 50, 100)
	closeBtn.BorderSizePixel = 0
	closeBtn.Text = "×"
	closeBtn.TextColor3 = Color3.new(1, 1, 1)
	closeBtn.Font = Enum.Font.GothamBold
	closeBtn.TextSize = 20
	Instance.new("UICorner", closeBtn).CornerRadius = UDim.new(0, 6)
	closeBtn.MouseButton1Click:Connect(function()
		self:Disable()
	end)
	local dragStart, startPos
	titleBar.InputBegan:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1 then
			dragStart = input.Position
			startPos = mainFrame.Position
			local moveConn, endConn
			moveConn = game:GetService("UserInputService").InputChanged:Connect(function(moveInput)
				if moveInput.UserInputType == Enum.UserInputType.MouseMovement then
					local delta = moveInput.Position - dragStart
					mainFrame.Position = UDim2.new(
						startPos.X.Scale,
						startPos.X.Offset + delta.X,
						startPos.Y.Scale,
						startPos.Y.Offset + delta.Y
					)
				end
			end)
			endConn = game:GetService("UserInputService").InputEnded:Connect(function(endInput)
				if endInput.UserInputType == Enum.UserInputType.MouseButton1 then
					moveConn:Disconnect()
					endConn:Disconnect()
				end
			end)
		end
	end)
	local content = Instance.new("Frame", mainFrame)
	content.Name = "Content"
	content.Size = UDim2.new(1, -20, 1, -45)
	content.Position = UDim2.fromOffset(10, 40)
	content.BackgroundTransparency = 1
	local selectionLabel = Instance.new("TextLabel", content)
	selectionLabel.Name = "SelectionLabel"
	selectionLabel.Size = UDim2.new(1, 0, 0, 35)
	selectionLabel.BackgroundColor3 = Color3.fromRGB(35, 35, 45)
	selectionLabel.BorderSizePixel = 0
	selectionLabel.Font = Enum.Font.GothamMedium
	selectionLabel.Text = "Click an object to select"
	selectionLabel.TextColor3 = Color3.fromRGB(200, 200, 200)
	selectionLabel.TextSize = 12
	Instance.new("UICorner", selectionLabel).CornerRadius = UDim.new(0, 6)
	local methodLabel = Instance.new("TextLabel", content)
	methodLabel.Size = UDim2.new(1, 0, 0, 20)
	methodLabel.Position = UDim2.fromOffset(0, 45)
	methodLabel.BackgroundTransparency = 1
	methodLabel.Font = Enum.Font.GothamBold
	methodLabel.Text = "Claim Method:"
	methodLabel.TextColor3 = Color3.new(1, 1, 1)
	methodLabel.TextSize = 13
	methodLabel.TextXAlignment = Enum.TextXAlignment.Left
	local methodButtons = {}
	local methods = {
		{ id = "ownership", name = "OWNERSHIP", desc = "Set network owner" },
		{ id = "velocity", name = "VELOCITY", desc = "Spam velocity changes" },
		{ id = "cframe", name = "CFRAME", desc = "Spam CFrame updates" },
	}
	for i, method in ipairs(methods) do
		local btn = Instance.new("TextButton", content)
		btn.Name = method.id .. "Btn"
		btn.Size = UDim2.fromOffset(110, 30)
		btn.Position = UDim2.fromOffset((i - 1) * 120, 70)
		btn.BackgroundColor3 = method.id == "ownership" and Color3.fromRGB(255, 100, 0) or Color3.fromRGB(50, 50, 65)
		btn.BorderSizePixel = 0
		btn.Font = Enum.Font.GothamSemibold
		btn.Text = method.name
		btn.TextColor3 = Color3.new(1, 1, 1)
		btn.TextSize = 10
		Instance.new("UICorner", btn).CornerRadius = UDim.new(0, 6)
		methodButtons[method.id] = btn
		btn.MouseButton1Click:Connect(function()
			self.Config.ClaimMethod = method.id
			for m, b in pairs(methodButtons) do
				b.BackgroundColor3 = m == method.id and Color3.fromRGB(255, 100, 0) or Color3.fromRGB(50, 50, 65)
			end
			print(string.format("✓ Claim method: %s", method.name))
		end)
		local tooltip = Instance.new("TextLabel", btn)
		tooltip.Size = UDim2.new(1, 0, 0, 15)
		tooltip.Position = UDim2.new(0, 0, 1, 2)
		tooltip.BackgroundTransparency = 1
		tooltip.Font = Enum.Font.Gotham
		tooltip.Text = method.desc
		tooltip.TextColor3 = Color3.fromRGB(150, 150, 150)
		tooltip.TextSize = 8
		tooltip.TextWrapped = true
	end
	local autoClaimToggle = Instance.new("TextButton", content)
	autoClaimToggle.Name = "AutoClaimToggle"
	autoClaimToggle.Size = UDim2.new(1, 0, 0, 35)
	autoClaimToggle.Position = UDim2.fromOffset(0, 120)
	autoClaimToggle.BackgroundColor3 = Color3.fromRGB(50, 50, 65)
	autoClaimToggle.BorderSizePixel = 0
	autoClaimToggle.Font = Enum.Font.GothamBold
	autoClaimToggle.Text = "AUTO-CLAIM: OFF"
	autoClaimToggle.TextColor3 = Color3.new(1, 1, 1)
	autoClaimToggle.TextSize = 12
	Instance.new("UICorner", autoClaimToggle).CornerRadius = UDim.new(0, 6)
	autoClaimToggle.MouseButton1Click:Connect(function()
		self.State.AutoClaim = not self.State.AutoClaim
		autoClaimToggle.Text = "AUTO-CLAIM: " .. (self.State.AutoClaim and "ON" or "OFF")
		autoClaimToggle.BackgroundColor3 = self.State.AutoClaim and Color3.fromRGB(0, 200, 100)
			or Color3.fromRGB(50, 50, 65)
		print(string.format("✓ Auto-claim: %s", self.State.AutoClaim and "ON" or "OFF"))
	end)
