		MinBtn.Text = isMinimized and "+" or "−"
	end)
	track(UIS.InputBegan:Connect(function(i, gp)
		if gp then
			return
		end
		if i.KeyCode == Enum.KeyCode.RightAlt then
			S.BotEnabled = not S.BotEnabled
			botToggleSet(S.BotEnabled)
			DoNotif("Rage Bot: " .. (S.BotEnabled and "ON" or "OFF"), 1)
			updateStatus()
		end
		if i.KeyCode == Enum.KeyCode.RightControl then
			S.EvasionEnabled = not S.EvasionEnabled
			DoNotif("Evasion: " .. (S.EvasionEnabled and "ON" or "OFF"), 1)
			updateStatus()
		end
	end))
	function resetReach(tool)
		tool = tool or equippedTool
		if not tool then
			return
		end
		for _, d in ipairs(tool:GetDescendants()) do
			if d:IsA("BasePart") then
				local o = d:FindFirstChild("__OrigSize")
				if o then
					d.Size = o.Value
					o:Destroy()
				end
			end
		end
		if reachBox then
			reachBox:Destroy()
			reachBox = nil
		end
	end
	function applyBoxReach()
		if not S.BoxReach or not S.SelectedPart or not S.SelectedPart.Parent then
			return
		end
		local p = S.SelectedPart
		if not p:FindFirstChild("__OrigSize") then
			local v = Instance.new("Vector3Value", p)
			v.Name = "__OrigSize"
			v.Value = p.Size
		end
		p.Size = S.BoxSize
		if reachBox then
			reachBox:Destroy()
		end
		reachBox = Instance.new("SelectionBox")
		reachBox.Adornee = p
		reachBox.LineThickness = 0.025
		reachBox.Color3 = T.Accent
		reachBox.SurfaceTransparency = 0.85
		reachBox.SurfaceColor3 = T.Accent
		reachBox.Parent = workspace
	end
	local selectedPartBtn = nil
	function populateParts()
		for _, c in ipairs(partsScroll:GetChildren()) do
			if c:IsA("TextButton") then
				c:Destroy()
			end
		end
		S.SelectedPart = nil
		selectedPartBtn = nil
		if not equippedTool then
			return
		end
		for _, p in ipairs(equippedTool:GetDescendants()) do
			if p:IsA("BasePart") then
				local b = Instance.new("TextButton", partsScroll)
				b.Size = UDim2.new(1, -6, 0, 22)
				b.BackgroundColor3 = T.Btn
				b.Font = T.Font
				b.TextSize = 12
				b.TextColor3 = T.Text
				b.Text = p.Name
				corner(b, 4)
				b.MouseButton1Click:Connect(function()
					resetReach(equippedTool)
					S.SelectedPart = p
					if S.BoxReach then
						applyBoxReach()
					end
					if selectedPartBtn then
						selectedPartBtn.BackgroundColor3 = T.Btn
					end
					b.BackgroundColor3 = T.AccentDim
					selectedPartBtn = b
				end)
			end
		end
	end
	local function cleanCharConns()
		for _, c in ipairs(charConns) do
			pcall(function()
				c:Disconnect()
			end)
		end
		charConns = {}
	end
	local function trackTool(char)
		cleanCharConns()
		resetReach(equippedTool)
		equippedTool = char:FindFirstChildOfClass("Tool")
		populateParts()
		table.insert(
			charConns,
			char.ChildAdded:Connect(function(c)
				if c:IsA("Tool") then
					resetReach(equippedTool)
					equippedTool = c
					populateParts()
				end
			end)
		)
		table.insert(
			charConns,
			char.ChildRemoved:Connect(function(c)
				if c == equippedTool then
					resetReach(equippedTool)
					equippedTool = nil
					populateParts()
				end
			end)
		)
	end
	if LocalPlayer.Character then
		trackTool(LocalPlayer.Character)
	end
	track(LocalPlayer.CharacterAdded:Connect(trackTool))
	local function getChar(p)
		return p and p.Character
	end
	local function getHRP(p)
		local c = getChar(p)
		return c and c:FindFirstChild("HumanoidRootPart")
	end
	local function getHum(p)
		local c = getChar(p)
		return c and c:FindFirstChildOfClass("Humanoid")
	end
	local function isAlive(p)
		local h = getHum(p)
		return h and h.Health > 0
	end
	local function sameTeam(p)
		if not S.TeamFilter then
			return false
		end
		return p.Team == LocalPlayer.Team
	end
	local function distTo(p)
		local myHRP = getHRP(LocalPlayer)
		local tHRP = getHRP(p)
		if not (myHRP and tHRP) then
			return math.huge
		end
		return (myHRP.Position - tHRP.Position).Magnitude
	end
	local function refreshPlayers()
		playerList = {}
		for _, p in ipairs(Players:GetPlayers()) do
			if p ~= LocalPlayer and not sameTeam(p) then
				table.insert(playerList, p)
			end
		end
		table.sort(playerList, function(a, b)
			return distTo(a) < distTo(b)
		end)
		if S.Target and (not isAlive(S.Target) or sameTeam(S.Target)) then
			S.Target = nil
		end
		if not S.Target and #playerList > 0 then
			targetIndex = 1
			S.Target = playerList[1]
		end
		targetBtn.Text = S.Target and S.Target.Name or "No Target"
		updateStatus()
	end
	targetBtn.MouseButton1Click:Connect(function()
		refreshPlayers()
		if #playerList == 0 then
			return
		end
		targetIndex = (targetIndex % #playerList) + 1
		S.Target = playerList[targetIndex]
		targetBtn.Text = S.Target.Name
		updateStatus()
	end)
	local cycleOn = false
	cycleBtn.Text = "Cycle: OFF"
	cycleBtn.MouseButton1Click:Connect(function()
		cycleOn = not cycleOn
		S.AutoCycle = cycleOn
		cycleBtn.Text = "Cycle: " .. (cycleOn and "ON" or "OFF")
		cycleBtn.BackgroundColor3 = cycleOn and T.AccentDim or T.Btn
	end)
	track(Players.PlayerAdded:Connect(refreshPlayers))
	track(Players.PlayerRemoving:Connect(function(p)
		if S.Target == p then
			S.Target = nil
		end
		refreshPlayers()
	end))
	refreshPlayers()
	local lastTargetPos = nil
	local function predictedPos(tHRP, dt)
		local pos = tHRP.Position
		if lastTargetPos then
			local vel = (pos - lastTargetPos) / dt
			table.insert(velHistory, vel)
			if #velHistory > 6 then
				table.remove(velHistory, 1)
			end
			local avgVel = Vector3.new(0, 0, 0)
			for _, v in ipairs(velHistory) do
				avgVel = avgVel + v
			end
			avgVel = avgVel / #velHistory
			lastTargetPos = pos
			return pos + avgVel * (dt * S.PredictSteps)
		end
		lastTargetPos = pos
		return pos
	end
	local evasionTime = 0
	local function applyEvasion(myHRP, dt)
		if not S.EvasionEnabled then
			return
		end
		evasionTime = evasionTime + dt
		local mode = S.EvasionMode
		if mode == "Jitter" or mode == "Combo" then
			local r = S.JitterRadius
			local jx = (math.random() * 2 - 1) * r
			local jz = (math.random() * 2 - 1) * r
			if math.random(1, 3) == 1 then
				myHRP.CFrame = myHRP.CFrame * CFrame.new(jx * dt * 20, 0, jz * dt * 20)
			end
		end
		if mode == "Spin" or mode == "Combo" then
			local spinAngle = evasionTime * S.SpinSpeed
			local pos = myHRP.Position
			myHRP.CFrame = CFrame.new(pos) * CFrame.Angles(0, spinAngle, 0)
		end
		if mode == "Vertical" then
			if math.random(1, 30) == 1 then
				local spike = 8
				myHRP.CFrame = myHRP.CFrame + Vector3.new(0, spike, 0)
				task.delay(0.08, function()
					if myHRP and myHRP.Parent then
						myHRP.CFrame = myHRP.CFrame - Vector3.new(0, spike, 0)
					end
				end)
			end
		end
	end
	local voidFloor = workspace.FallenPartsDestroyHeight or -500
	local baitPhase = "idle"
	local safeReturnPos = nil
	local function findVoidEdge(myPos)
		local dirs = {
			Vector3.new(1, 0, 0),
			Vector3.new(-1, 0, 0),
			Vector3.new(0, 0, 1),
			Vector3.new(0, 0, -1),
			Vector3.new(1, 0, 1).Unit,
			Vector3.new(-1, 0, 1).Unit,
			Vector3.new(1, 0, -1).Unit,
			Vector3.new(-1, 0, -1).Unit,
		}
		local params = RaycastParams.new()
		params.FilterDescendantsInstances = { LocalPlayer.Character }
		params.FilterType = Enum.RaycastFilterType.Exclude
		for _, dir in ipairs(dirs) do
			local probePos = myPos + dir * S.VoidMargin
			local result = workspace:Raycast(probePos, Vector3.new(0, -300, 0), params)
			if not result then
				return probePos, dir
			end
		end
		return nil, nil
	end
	local function applyVoidBait(myHRP, tHRP, dt)
		if not S.VoidBait or not tHRP then
			return
		end
		local myPos = myHRP.Position
		if baitPhase == "idle" then
			local edgePos, edgeDir = findVoidEdge(myPos)
			if edgePos then
				safeReturnPos = myPos
				baitPhase = "approaching"
			end
		elseif baitPhase == "approaching" then
			local edgePos, edgeDir = findVoidEdge(myPos)
			if edgePos then
				local target = edgePos
				local newPos = myPos + (target - myPos).Unit * 20 * dt
				myHRP.CFrame = CFrame.new(newPos, newPos + (target - myPos).Unit)
				if (myPos - edgePos).Magnitude < S.VoidReturnDist then
					baitPhase = "returning"
				end
			else
				baitPhase = "idle"
			end
		elseif baitPhase == "returning" then
			if safeReturnPos then
				myHRP.CFrame = CFrame.new(safeReturnPos)
			end
			baitPhase = "idle"
			safeReturnPos = nil
		end
	end
	task.spawn(function()
		while true do
			task.wait(3)
			if S.AutoCycle and S.BotEnabled then
				refreshPlayers()
				if #playerList > 1 then
					targetIndex = (targetIndex % #playerList) + 1
					S.Target = playerList[targetIndex]
					targetBtn.Text = S.Target.Name
					updateStatus()
				end
			end
		end
	end)
	local lastFrame = tick()
	track(RunService.RenderStepped:Connect(function()
		local now = tick()
		local dt = now - lastFrame
		lastFrame = now
		if S.Target then
			if not isAlive(S.Target) or distTo(S.Target) > S.MaxDistance then
				refreshPlayers()
			end
		end
		local myChar = LocalPlayer.Character
		local myHRP = myChar and myChar:FindFirstChild("HumanoidRootPart")
		local myHum = myChar and myChar:FindFirstChildOfClass("Humanoid")
		if not (myHRP and myHum and myHum.Health > 0) then
			return
		end
		applyEvasion(myHRP, dt)
		if not S.BotEnabled or not S.Target then
			return
		end
		local tChar = S.Target.Character
		local tHRP = tChar and tChar:FindFirstChild("HumanoidRootPart")
		if not tHRP then
			return
		end
		applyVoidBait(myHRP, tHRP, dt)
		local predPos = predictedPos(tHRP, dt)
		local behindVec = -tHRP.CFrame.LookVector
		local goalPos = predPos + behindVec * S.HoverDist
		local goalCF = CFrame.lookAt(goalPos, predPos)
		myHRP.CFrame = myHRP.CFrame:Lerp(goalCF, S.LerpSpeed)
		if S.AutoAttack and equippedTool then
			local interval = 1 / S.AttackCPS
			local jitteredInterval = interval * (0.85 + math.random() * 0.3)
			if now - lastAttack >= jitteredInterval then
				lastAttack = now
				pcall(function()
					equippedTool:Activate()
				end)
			end
		end
	end))
	DoNotif("Rage Bot V2 loaded — RightAlt = toggle bot, RightCtrl = toggle evasion", 4)
	updateStatus()
end)

RegisterCommand({
	Name = "partbring",
	Aliases = { "pb", "sendpart" },
	Description = "WIP Sends unanchored parts to a target",
	ArgsDesc = {},
	Permissions = {},
}, function(args, speaker)
	local TweenService = game:GetService("TweenService")
	local Players = game:GetService("Players")
	local RunService = game:GetService("RunService")
	local UserInputService = game:GetService("UserInputService")
	local Workspace = game:GetService("Workspace")
	local Camera = Workspace.CurrentCamera
	local LocalPlayer = Players.LocalPlayer
	LocalPlayer.ReplicationFocus = Workspace

	pcall(function()
		game:GetService("CoreGui").RobloxGui["CoreScripts/NetworkPause"]:Destroy()
	end)

	-- ── Ownership assertion ───────────────────────────────────────────────
	if not getgenv().Network then
		getgenv().Network = { BaseParts = {} }
		RunService.Heartbeat:Connect(function()
			sethiddenproperty(LocalPlayer, "SimulationRadius", math.huge)
			LocalPlayer.ReplicationFocus = Workspace
		end)
		RunService.RenderStepped:Connect(function()
			sethiddenproperty(LocalPlayer, "SimulationRadius", math.huge)
		end)
	end

	local CONFIG = {
		UPDATE_INTERVAL = 0.01,
		MAX_PARTS = 800,
	}

	local TARGET_PARTS = {}
	local CONNECTIONS = {}
	local sendTarget = nil
	local blackHoleActive = false
	local spectateActive = false
	local targetMode = "Players"
	local cycleIndex = 1
	local cycleConnection = nil
	local spectateMonitorConnection = nil
	local DescendantAddedConnection = nil
	local originalCameraType = nil
	local originalCameraSubject = nil
	local lastUpdate = 0

	local Folder = Instance.new("Folder", Workspace)
	local AnchorPart = Instance.new("Part", Folder)
	local Attachment1 = Instance.new("Attachment", AnchorPart)
	AnchorPart.Anchored = false
	AnchorPart.CanCollide = true
	AnchorPart.Transparency = 1

	local overlapParams = OverlapParams.new()
	overlapParams.FilterType = Enum.RaycastFilterType.Exclude
	overlapParams.MaxParts = 500

	local function getPartsInRadius(centerPos, radius)
		local char = LocalPlayer.Character
		overlapParams.FilterDescendantsInstances = char and { char } or {}
		local parts = Workspace:GetPartBoundsInRadius(centerPos, radius, overlapParams)
		if sendTarget then
			local targetChar = sendTarget.Character
			local targetRoot = targetChar and targetChar:FindFirstChild("HumanoidRootPart")
			if targetRoot then
				local targetParts = Workspace:GetPartBoundsInRadius(targetRoot.Position, CONFIG.RADIUS, overlapParams)
				for _, p in ipairs(targetParts) do
					table.insert(parts, p)
				end
			end
		end
		return parts
	end

	local function releasePart(part)
		local data = TARGET_PARTS[part]
		if not data then
			return
		end
		if data.conn then
			data.conn:Disconnect()
		end
		pcall(function()
			local bv = part:FindFirstChildOfClass("BodyVelocity")
			if bv then
				bv:Destroy()
			end
			if data.alignPos and data.alignPos.Parent then
				data.alignPos:Destroy()
			end
			if data.attachment and data.attachment.Parent then
				data.attachment:Destroy()
			end
			if data.torque and data.torque.Parent then
				data.torque:Destroy()
			end
		end)
		TARGET_PARTS[part] = nil
	end

	local function claimOwnership(part)
		-- direct network ownership claim — multiple methods for executor compatibility
		pcall(function()
			part:SetNetworkOwner(LocalPlayer)
		end)
		pcall(function()
			sethiddenproperty(part, "NetworkOwnershipRule", 0)
		end)
	end

	local function forcePart(part)
		if not part:IsA("BasePart") then
			return
		end
		if TARGET_PARTS[part] then
			return
		end
		if part.Anchored then
			return
		end
		if part.Parent and part.Parent:FindFirstChildOfClass("Humanoid") then
			return
		end
		if part.Parent and part.Parent:FindFirstChild("Head") then
			return
		end
		if part.Name == "Handle" then
			return
		end
		local count = 0
		for _ in pairs(TARGET_PARTS) do
			count += 1
		end
		if count >= CONFIG.MAX_PARTS then
			return
		end

		pcall(function()
			for _, c in ipairs(part:GetChildren()) do
				if
					c:IsA("BodyMover")
					or c:IsA("RocketPropulsion")
					or c:IsA("LinearVelocity")
					or c:IsA("VectorForce")
					or c:IsA("BodyVelocity")
					or c:IsA("BodyForce")
				then
					c:Destroy()
				end
			end
		end)

		part.CanCollide = true
		part.Massless = false
		claimOwnership(part)

		local function launchAtTarget()
			if not sendTarget then
				return
			end
			local targetChar = sendTarget.Character
			local targetRoot = targetChar and targetChar:FindFirstChild("HumanoidRootPart")
			if not targetRoot then
				return
			end
			pcall(function()
				local old = part:FindFirstChildOfClass("BodyVelocity")
				if old then
					old:Destroy()
				end
				local bv = Instance.new("BodyVelocity")
				bv.MaxForce = Vector3.new(1e9, 1e9, 1e9)
				bv.Velocity = (targetRoot.Position - part.Position).Unit * 500
				bv.Parent = part
			end)
		end

		launchAtTarget()

		local conn
		conn = RunService.Heartbeat:Connect(function()
			if not part.Parent then
				releasePart(part)
				return
			end
			if not blackHoleActive then
				releasePart(part)
				return
			end
			claimOwnership(part)
			if sendTarget then
				local targetChar = sendTarget.Character
				local targetRoot = targetChar and targetChar:FindFirstChild("HumanoidRootPart")
				if targetRoot then
					local bv = part:FindFirstChildOfClass("BodyVelocity")
					if bv then
						bv.Velocity = (targetRoot.Position - part.Position).Unit * 500
					else
						launchAtTarget()
					end
				end
			end
		end)
		TARGET_PARTS[part] = { conn = conn }
	end

	local function cleanupStaleParts()
		for part in pairs(TARGET_PARTS) do
			if not part.Parent then
				releasePart(part)
			end
		end
	end

	local function blackholeLoop()
		local now = tick()
		if now - lastUpdate < CONFIG.UPDATE_INTERVAL then
			return
		end
		lastUpdate = now
		if not blackHoleActive then
			return
		end
		cleanupStaleParts()
	end
	table.insert(CONNECTIONS, RunService.Heartbeat:Connect(blackholeLoop))

	local function getPlayer(name)
		local query = name:lower()
		for _, p in ipairs(Players:GetPlayers()) do
			if p ~= LocalPlayer then
				if p.Name:lower():find(query, 1, true) or p.DisplayName:lower():find(query, 1, true) then
					return p
				end
			end
		end
	end

	local function getValidPlayers()
		local valid = {}
		for _, p in ipairs(Players:GetPlayers()) do
			if p ~= LocalPlayer and p.Character and p.Character:FindFirstChild("HumanoidRootPart") then
				table.insert(valid, p)
			end
		end
		return valid
	end

	local function isTargetValid(target)
		return target
			and target.Character
			and target.Character:FindFirstChildOfClass("Humanoid")
			and target.Character.Humanoid.Health > 0
	end

	local function startSpectating()
		if not isTargetValid(sendTarget) then
			return
		end
		local humanoid = sendTarget.Character:FindFirstChildOfClass("Humanoid")
		if not humanoid then
			return
		end
		if not originalCameraType then
			originalCameraType = Camera.CameraType
			originalCameraSubject = Camera.CameraSubject
		end
		Camera.CameraType = Enum.CameraType.Custom
		Camera.CameraSubject = humanoid
	end

	local function stopSpectating()
		if originalCameraType and originalCameraSubject then
			Camera.CameraType = originalCameraType
			Camera.CameraSubject = originalCameraSubject
		else
			Camera.CameraType = Enum.CameraType.Custom
			Camera.CameraSubject = LocalPlayer.Character and LocalPlayer.Character:FindFirstChildOfClass("Humanoid")
		end
		originalCameraType = nil
		originalCameraSubject = nil
	end
	local screenGui = Instance.new("ScreenGui")
	screenGui.Name = "BH_Gui"
	screenGui.ResetOnSpawn = false
	screenGui.IgnoreGuiInset = true
	screenGui.Parent = (pcall(function()
		return gethui()
	end) and gethui()) or LocalPlayer.PlayerGui

	local Main = Instance.new("Frame")
	Main.Size = UDim2.new(0, 240, 0, 160)
	Main.Position = UDim2.new(0, 16, 0, 16)
	Main.BackgroundColor3 = Color3.fromRGB(14, 14, 14)
	Main.BackgroundTransparency = 0.2
	Main.BorderSizePixel = 0
	Main.Active = true
	Main.Draggable = true
	Main.Parent = screenGui

	local function corner(parent, radius)
		local c = Instance.new("UICorner", parent)
		c.CornerRadius = UDim.new(0, radius or 8)
		return c
	end
	local function stroke(parent, color, thickness)
		local s = Instance.new("UIStroke", parent)
		s.Color = color or Color3.fromRGB(50, 50, 50)
		s.Thickness = thickness or 1
		return s
	end

	corner(Main, 10)
	stroke(Main)

	local titleLabel = Instance.new("TextLabel")
	titleLabel.Size = UDim2.new(1, 0, 0, 28)
	titleLabel.BackgroundColor3 = Color3.fromRGB(22, 22, 22)
	titleLabel.BackgroundTransparency = 0.1
	titleLabel.BorderSizePixel = 0
	titleLabel.Font = Enum.Font.Code
	titleLabel.Text = "Part Flinger"
	titleLabel.TextColor3 = Color3.fromRGB(200, 200, 200)
	titleLabel.TextSize = 12
	titleLabel.Parent = Main
	corner(titleLabel)

	local inputBox = Instance.new("TextBox")
	inputBox.Size = UDim2.new(0, 148, 0, 30)
	inputBox.Position = UDim2.new(0, 8, 0, 34)
	inputBox.BackgroundColor3 = Color3.fromRGB(24, 24, 24)
	inputBox.BorderSizePixel = 0
	inputBox.PlaceholderText = "player name..."
	inputBox.PlaceholderColor3 = Color3.fromRGB(65, 65, 65)
	inputBox.Text = ""
	inputBox.TextColor3 = Color3.fromRGB(210, 210, 210)
	inputBox.TextSize = 13
	inputBox.Font = Enum.Font.Code
	inputBox.ClearTextOnFocus = false
	inputBox.Parent = Main
	corner(inputBox, 6)
	stroke(inputBox, Color3.fromRGB(45, 45, 45))

	local modeBtn = Instance.new("TextButton")
	modeBtn.Size = UDim2.new(0, 72, 0, 30)
	modeBtn.Position = UDim2.new(0, 162, 0, 34)
	modeBtn.BackgroundColor3 = Color3.fromRGB(45, 45, 45)
	modeBtn.BorderSizePixel = 0
	modeBtn.Font = Enum.Font.Code
	modeBtn.Text = "Players"
	modeBtn.TextColor3 = Color3.fromRGB(200, 200, 200)
	modeBtn.TextSize = 12
	modeBtn.Parent = Main
	corner(modeBtn, 6)

	local bringBtn = Instance.new("TextButton")
	bringBtn.Size = UDim2.new(0, 108, 0, 28)
	bringBtn.Position = UDim2.new(0, 8, 0, 72)
	bringBtn.BackgroundColor3 = Color3.fromRGB(45, 45, 45)
	bringBtn.BorderSizePixel = 0
	bringBtn.Font = Enum.Font.Code
	bringBtn.Text = "Bring: Off"
	bringBtn.TextColor3 = Color3.fromRGB(200, 200, 200)
	bringBtn.TextSize = 12
	bringBtn.Parent = Main
	corner(bringBtn, 6)

	local spectateBtn = Instance.new("TextButton")
	spectateBtn.Size = UDim2.new(0, 108, 0, 28)
	spectateBtn.Position = UDim2.new(0, 124, 0, 72)
	spectateBtn.BackgroundColor3 = Color3.fromRGB(45, 45, 45)
	spectateBtn.BorderSizePixel = 0
	spectateBtn.Font = Enum.Font.Code
	spectateBtn.Text = "Spectate: Off"
	spectateBtn.TextColor3 = Color3.fromRGB(200, 200, 200)
	spectateBtn.TextSize = 12
	spectateBtn.Parent = Main
	corner(spectateBtn, 6)

	local statusLabel = Instance.new("TextLabel")
	statusLabel.Size = UDim2.new(1, -16, 0, 24)
	statusLabel.Position = UDim2.new(0, 8, 0, 108)
	statusLabel.BackgroundColor3 = Color3.fromRGB(20, 20, 20)
	statusLabel.BackgroundTransparency = 0.1
	statusLabel.BorderSizePixel = 0
	statusLabel.Font = Enum.Font.Code
	statusLabel.Text = "idle"
	statusLabel.TextColor3 = Color3.fromRGB(80, 80, 80)
	statusLabel.TextSize = 11
	statusLabel.TextXAlignment = Enum.TextXAlignment.Left
	statusLabel.Parent = Main
	corner(statusLabel, 6)
	local statusPadding = Instance.new("UIPadding", statusLabel)
	statusPadding.PaddingLeft = UDim.new(0, 6)
	local countLabel = Instance.new("TextLabel")
	countLabel.Size = UDim2.new(1, -16, 0, 16)
	countLabel.Position = UDim2.new(0, 8, 0, 136)
	countLabel.BackgroundTransparency = 1
	countLabel.Font = Enum.Font.Code
	countLabel.Text = ""
	countLabel.TextColor3 = Color3.fromRGB(60, 60, 60)
	countLabel.TextSize = 10
	countLabel.TextXAlignment = Enum.TextXAlignment.Left
	countLabel.Parent = Main
	local function setStatus(msg, color)
		statusLabel.Text = msg
		statusLabel.TextColor3 = color or Color3.fromRGB(80, 80, 80)
	end

	local function setTarget(player)
		sendTarget = player
		if player then
			setStatus("→ " .. player.Name .. " (" .. player.DisplayName .. ")", Color3.fromRGB(200, 80, 80))
		else
			setStatus("idle")
		end
	end

	local function stopBlackhole()
		blackHoleActive = false
		bringBtn.Text = "Bring: Off"
		bringBtn.BackgroundColor3 = Color3.fromRGB(45, 45, 45)
		if DescendantAddedConnection then
			DescendantAddedConnection:Disconnect()
			DescendantAddedConnection = nil
		end
		if cycleConnection then
			cycleConnection:Disconnect()
			cycleConnection = nil
		end
		for part in pairs(TARGET_PARTS) do
			releasePart(part)
		end
	end

	local function startBlackhole()
		if not sendTarget then
			return
		end
		blackHoleActive = true
		bringBtn.Text = "Bring: On"
		bringBtn.BackgroundColor3 = Color3.fromRGB(160, 35, 35)
		local targetChar = sendTarget.Character
		local targetRoot = targetChar and targetChar:FindFirstChild("HumanoidRootPart")
		if targetRoot then
			Attachment1.WorldCFrame = targetRoot.CFrame
		end
		task.spawn(function()
			for _, v in ipairs(Workspace:GetDescendants()) do
				forcePart(v)
			end
		end)
		DescendantAddedConnection = Workspace.DescendantAdded:Connect(function(v)
			if blackHoleActive then
				task.spawn(function()
					forcePart(v)
				end)
			end
		end)
		if targetMode == "All" then
			cycleConnection = RunService.Heartbeat:Connect(function()
				if tick() % 3 < 0.05 then
					local players = getValidPlayers()
					if #players > 0 then
						cycleIndex = (cycleIndex % #players) + 1
						setTarget(players[cycleIndex])
					end
				end
			end)
		end
	end

	local function toggleSpectate()
		if not sendTarget then
			return
		end
		spectateActive = not spectateActive
		spectateBtn.Text = spectateActive and "Spectate: On" or "Spectate: Off"
		spectateBtn.BackgroundColor3 = spectateActive and Color3.fromRGB(40, 80, 140) or Color3.fromRGB(45, 45, 45)
		if spectateActive then
			startSpectating()
			if spectateMonitorConnection then
				spectateMonitorConnection:Disconnect()
			end
			spectateMonitorConnection = RunService.Heartbeat:Connect(function()
				if not spectateActive then
					spectateMonitorConnection:Disconnect()
					return
				end
				if not isTargetValid(sendTarget) then
					stopSpectating()
					spectateActive = false
					spectateBtn.Text = "Spectate: Off"
					spectateBtn.BackgroundColor3 = Color3.fromRGB(45, 45, 45)
				elseif Camera.CameraSubject ~= sendTarget.Character:FindFirstChildOfClass("Humanoid") then
					startSpectating()
				end
			end)
		else
			stopSpectating()
			if spectateMonitorConnection then
				spectateMonitorConnection:Disconnect()
				spectateMonitorConnection = nil
			end
		end
	end

	table.insert(
		CONNECTIONS,
		RunService.Heartbeat:Connect(function()
			if blackHoleActive then
				local count = 0
				for _ in pairs(TARGET_PARTS) do
					count += 1
				end
				countLabel.Text = "parts claimed: " .. count
			else
				countLabel.Text = ""
			end
		end)
	)

	bringBtn.MouseButton1Click:Connect(function()
		if blackHoleActive then
			stopBlackhole()
		else
			if targetMode == "Players" then
				local p = getPlayer(inputBox.Text)
				if not p then
					setStatus("not found: " .. inputBox.Text, Color3.fromRGB(200, 80, 80))
					return
				end
				setTarget(p)
			else
				local players = getValidPlayers()
				if #players == 0 then
					setStatus("no valid players", Color3.fromRGB(200, 80, 80))
					return
				end
				setTarget(players[1])
			end
			startBlackhole()
		end
	end)

	spectateBtn.MouseButton1Click:Connect(toggleSpectate)

	modeBtn.MouseButton1Click:Connect(function()
		targetMode = targetMode == "Players" and "All" or "Players"
		modeBtn.Text = targetMode
		inputBox.Visible = targetMode == "Players"
		if blackHoleActive then
			stopBlackhole()
			if targetMode == "All" then
				local players = getValidPlayers()
				if #players > 0 then
					setTarget(players[1])
					startBlackhole()
				end
			end
		end
	end)

	inputBox.FocusLost:Connect(function(enterPressed)
		if not enterPressed then
			return
		end
		local p = getPlayer(inputBox.Text)
		if p then
			inputBox.Text = p.Name
			if not blackHoleActive then
				setTarget(p)
			end
		else
			setStatus("not found: " .. inputBox.Text, Color3.fromRGB(200, 80, 80))
		end
	end)

	Players.PlayerRemoving:Connect(function(p)
		if p == sendTarget then
			if spectateActive then
				stopSpectating()
				spectateActive = false
				spectateBtn.Text = "Spectate: Off"
				spectateBtn.BackgroundColor3 = Color3.fromRGB(45, 45, 45)
			end
			if blackHoleActive and targetMode == "All" then
				local players = getValidPlayers()
				if #players > 0 then
					setTarget(players[1])
				else
					stopBlackhole()
					setStatus("no players left")
				end
			elseif blackHoleActive then
				stopBlackhole()
				setStatus("target left")
			else
				setTarget(nil)
			end
		end
	end)

	local guiVisible = true
	UserInputService.InputBegan:Connect(function(input, gpe)
		if gpe then
			return
		end
		if input.KeyCode == Enum.KeyCode.RightControl then
			guiVisible = not guiVisible
			local t = guiVisible and 0.05 or 1
			TweenService:Create(Main, TweenInfo.new(0.25), { BackgroundTransparency = t }):Play()
			for _, child in ipairs(Main:GetDescendants()) do
				if child:IsA("TextLabel") or child:IsA("TextButton") or child:IsA("TextBox") then
					TweenService:Create(child, TweenInfo.new(0.25), {
						TextTransparency = guiVisible and 0 or 1,
						BackgroundTransparency = guiVisible and 0.05 or 1,
					}):Play()
				end
			end
			Main.Active = guiVisible
			Main.Draggable = guiVisible
		end
	end)

	setStatus("idle")
end)

