		SaveHistory = true,
		ShowDebug = false,
		ScanDepth = "deep",
		TargetNames = {
			"ExecuteRemote",
			"G_Execute",
			"ServerSide",
			"RemoteEvent",
			"DataRemote",
			"Handshake",
			"Execute",
