local AntiAdminState = {
	Enabled = false,
	Connections = {},
	Watchdog = nil,
}
local function log(msg: string)
	if notify then
		notify("AntiAdmin", msg, 3)
	else
		print("[AntiAdmin]", msg)
	end
end
local function cleanConnections()
	for i, v in pairs(AntiAdminState.Connections) do
		if typeof(v) == "RBXScriptConnection" then
			v:Disconnect()
		end
	end
	AntiAdminState.Connections = {}
	if AntiAdminState.Watchdog then
		AntiAdminState.Watchdog:Disconnect()
		AntiAdminState.Watchdog = nil
	end
end
local function protectHumanoid(hum: Humanoid)
	if not hum then
		return
	end
	table.insert(
		AntiAdminState.Connections,
		hum:GetPropertyChangedSignal("Health"):Connect(function()
			if hum.Health <= 0 and hum.MaxHealth > 0 then
				pcall(function()
					hum.Health = hum.MaxHealth
				end)
				log("Blocked kill attempt.")
			end
		end)
	)
	table.insert(
		AntiAdminState.Connections,
		hum:GetPropertyChangedSignal("WalkSpeed"):Connect(function()
			if hum.WalkSpeed <= 0 then
				task.defer(function()
					pcall(function()
						hum.WalkSpeed = 16
					end)
				end)
			end
		end)
	)
	table.insert(
		AntiAdminState.Connections,
		hum:GetPropertyChangedSignal("JumpPower"):Connect(function()
			if hum.JumpPower <= 0 then
				task.defer(function()
					pcall(function()
						hum.JumpPower = 50
					end)
				end)
			end
		end)
	)
end
local function applyProtections(char: Model)
	log("Applying character protections...")
	local humanoid = char:WaitForChild("Humanoid", 10)
	local root = char:WaitForChild("HumanoidRootPart", 10)
	if humanoid then
		protectHumanoid(humanoid)
	end
	table.insert(
		AntiAdminState.Connections,
		Workspace.DescendantAdded:Connect(function(obj)
			if obj:IsA("Explosion") and root then
				task.defer(function()
					pcall(function()
						local dist = (obj.Position - root.Position).Magnitude
						if dist < obj.BlastRadius + 50 then
							obj.BlastRadius = 0
							obj.BlastPressure = 0
						end
					end)
				end)
			end
		end)
	)
	table.insert(
		AntiAdminState.Connections,
		char.DescendantAdded:Connect(function(obj)
			if
				obj:IsA("BodyVelocity")
				or obj:IsA("BodyForce")
				or obj:IsA("RocketPropulsion")
				or obj:IsA("BodyAngularVelocity")
			then
				task.defer(function()
					pcall(function()
						obj:Destroy()
					end)
				end)
			end
		end)
	)
	table.insert(
		AntiAdminState.Connections,
		char.ChildRemoved:Connect(function(obj)
			if obj:IsA("ForceField") and humanoid and humanoid.Health > 0 then
				task.defer(function()
					Instance.new("ForceField", char).Visible = false
				end)
			elseif obj:IsA("Tool") then
				task.delay(0.1, function()
					if obj and not obj.Parent then
						pcall(function()
							obj.Parent = lp.Backpack
						end)
					end
				end)
			end
		end)
	)
end
local function setupHooks()
	local hdc = ReplicatedStorage:FindFirstChild("HDAdminHDClient")
	if hdc and hdc:FindFirstChild("Signals") then
		for _, sigName in ipairs({ "ExecuteClientCommand", "ActivateClientCommand", "ReplicationEffectClientCommand" }) do
			local s = hdc.Signals:FindFirstChild(sigName)
			if s then
				table.insert(
					AntiAdminState.Connections,
					s.OnClientEvent:Connect(function(cmd)
						log("Intercepted HD command: " .. tostring(cmd))
					end)
				)
			end
		end
	end
	local adonis = ReplicatedStorage:FindFirstChild("Adonis")
	if adonis then
		local remote = adonis:FindFirstChild("Remote") or adonis:FindFirstChildOfClass("RemoteEvent")
		if remote then
			table.insert(
				AntiAdminState.Connections,
				remote.OnClientEvent:Connect(function(cmd)
					log("Intercepted Adonis signal: " .. tostring(cmd))
				end)
			)
		end
	end
end
local function startWatchdog()
	local lastCheck = 0
	AntiAdminState.Watchdog = RunService.Heartbeat:Connect(function(dt)
		lastCheck += dt
		if lastCheck < 0.5 then
			return
		end
		lastCheck = 0
		local char = lp.Character
		if not char then
			return
		end
		local pg = lp:FindFirstChild("PlayerGui")
		if pg then
			for _, obj in ipairs(pg:GetDescendants()) do
				if
					obj:IsA("Frame")
					and obj.BackgroundTransparency < 0.1
					and obj.BackgroundColor3 == Color3.new(0, 0, 0)
					and obj.Size.X.Scale > 0.9
				then
					pcall(function()
						obj:Destroy()
					end)
				end
			end
		end
		for _, obj in ipairs(Lighting:GetChildren()) do
			if obj:IsA("ColorCorrectionEffect") and obj.Brightness < -0.8 then
				pcall(function()
					obj:Destroy()
				end)
			end
		end
	end)
end
addcmd("antiabuse", { "nahadmin", "bladmin" }, function(args, speaker)
	if AntiAdminState.Enabled then
		AntiAdminState.Enabled = false
		cleanConnections()
		log("AntiAdmin Disabled.")
	else
		AntiAdminState.Enabled = true
		log("AntiAdmin Enabled.")
		if lp.Character then
			applyProtections(lp.Character)
		end
		table.insert(AntiAdminState.Connections, lp.CharacterAdded:Connect(applyProtections))
		setupHooks()
		startWatchdog()
	end
end)
RegisterCommand({
	Name = "debugvoid",
	Aliases = { "dv" },
	Description = "void protection",
	ArgsDesc = {},
	Permissions = {},
}, function(args, speaker)
	local Players = game:GetService("Players")
	local RunService = game:GetService("RunService")
	local LocalPlayer = Players.LocalPlayer
	local Settings = {
		AntiAnchor = true,
		AntiFreeze = true,
		AntiTP = false,
		AntiFling = true,
		VelocityThreshold = 150,
		LastSafeCFrame = nil,
		VoidTrap = true,
		VoidPlatformY = -8000,
		VoidPlatformSize = 1000,
	}
	local function getChar()
		return LocalPlayer.Character
	end
	local function getRoot()
		return getChar() and getChar():FindFirstChild("HumanoidRootPart")
	end
	local function getHum()
		return getChar() and getChar():FindFirstChildOfClass("Humanoid")
	end
	local mt = getrawmetatable(game)
	local old_newindex = mt.__newindex
	setreadonly(mt, false)
	mt.__newindex = newcclosure(function(t, k, v)
		if not checkcaller() then
			if k == "Anchored" and Settings.AntiAnchor and t:IsDescendantOf(getChar()) then
				return nil
			end
			if (k == "WalkSpeed" or k == "JumpPower") and Settings.AntiFreeze and t:IsA("Humanoid") then
				if v == 0 then
					return nil
				end
			end
		end
		return old_newindex(t, k, v)
	end)
	setreadonly(mt, true)
	local voidPlatform = nil
	local function buildVoidPlatform()
		workspace.FallenPartsDestroyHeight = -50000
		voidPlatform = Instance.new("Part")
		voidPlatform.Name = "TITANIUM_VoidBase"
		voidPlatform.Size = Vector3.new(Settings.VoidPlatformSize, 1, Settings.VoidPlatformSize)
		voidPlatform.CFrame = CFrame.new(0, Settings.VoidPlatformY, 0)
		voidPlatform.Anchored = true
		voidPlatform.CanCollide = true
		voidPlatform.Transparency = 1
		voidPlatform.CastShadow = false
		voidPlatform.CanQuery = false
		voidPlatform.Locked = true
		voidPlatform.Parent = workspace
	end
	local function dropToVoid()
		local root = getRoot()
		if root then
			root.CFrame = CFrame.new(0, Settings.VoidPlatformY + 3, 0)
			root.AssemblyLinearVelocity = Vector3.zero
			root.AssemblyAngularVelocity = Vector3.zero
		end
	end
	if Settings.VoidTrap then
		buildVoidPlatform()
		if getChar() then
			dropToVoid()
		else
			LocalPlayer.CharacterAdded:Wait()
			task.wait(0.5)
			dropToVoid()
		end
		RunService.Heartbeat:Connect(function()
			if not (voidPlatform and voidPlatform.Parent) then
				buildVoidPlatform()
			else
				if not voidPlatform.Anchored then
					voidPlatform.Anchored = true
				end
			end
			if workspace.FallenPartsDestroyHeight > -50000 then
				workspace.FallenPartsDestroyHeight = -50000
			end
		end)
	end
	RunService.Heartbeat:Connect(function()
		local char = getChar()
		local root = getRoot()
		local hum = getHum()
		if not (char and root and hum) then
			return
		end
		if Settings.AntiAnchor then
			for _, part in ipairs(char:GetDescendants()) do
				if part:IsA("BasePart") and part.Anchored then
					part.Anchored = false
				end
			end
		end
		if Settings.AntiFreeze then
			if hum.PlatformStand then
				hum.PlatformStand = false
			end
			if hum.Sit and not hum.SeatPart then
				hum.Sit = false
			end
		end
		if Settings.AntiFling then
			local vel = root.AssemblyLinearVelocity
			local rotVel = root.AssemblyAngularVelocity
			if vel.Magnitude > Settings.VelocityThreshold or rotVel.Magnitude > Settings.VelocityThreshold then
				root.AssemblyLinearVelocity = Vector3.zero
				root.AssemblyAngularVelocity = Vector3.zero
				if Settings.LastSafeCFrame then
					root.CFrame = Settings.LastSafeCFrame
				end
			else
				if hum.FloorMaterial ~= Enum.Material.Air then
					Settings.LastSafeCFrame = root.CFrame
				end
			end
		end
		for _, obj in ipairs(char:GetChildren()) do
			if obj:IsA("Model") or obj:IsA("BasePart") then
				local name = obj.Name:lower()
				if name:find("jail") or name:find("cage") or name:find("prison") then
					obj:Destroy()
				end
			end
		end
	end)
	if Settings.AntiTP then
		local lastPos = getRoot() and getRoot().Position
		RunService.Stepped:Connect(function()
			local root = getRoot()
			if root and lastPos then
				if (root.Position - lastPos).Magnitude > 50 then
					root.CFrame = CFrame.new(lastPos)
				end
				lastPos = root.Position
			end
		end)
	end
	game.DescendantAdded:Connect(function(desc)
		if desc:IsA("Explosion") then
			if getRoot() and (desc.Position - getRoot().Position).Magnitude < 20 then
				desc.Visible = false
				desc:Destroy()
			end
		end
	end)
	DoNotif("Void trap")
end)
RegisterCommand({
	Name = "false",
	Aliases = { "block", "forcefalse" },
	Description = "Block a remote.",
	ArgsDesc = {},
	Permissions = {},
}, function(args, speaker)
	local blocked = {}
	local orig
	local active = false
	local function ensureHook()
		if active then
			return
		end
		active = true
		orig = hookmetamethod(
			game,
			"__namecall",
			newcclosure(function(self, ...)
				local method = getnamecallmethod()
				if blocked[self.Name] and (method == "FireServer" or method == "InvokeServer") then
					warn("[BlockRemote] Blocked: " .. self:GetFullName())
					return
				end
				return orig(self, ...)
			end)
		)
	end
end)
local Services = {
	Players = game:GetService("Players"),
	RunService = game:GetService("RunService"),
	CoreGui = game:GetService("CoreGui"),
	TweenService = game:GetService("TweenService"),
	UserInputService = game:GetService("UserInputService"),
}
local LocalPlayer = Services.Players.LocalPlayer
local function makeKey(parentObject, propName)
	local ok, path = pcall(function()
		return parentObject:GetFullName()
	end)
	return (ok and path or tostring(parentObject)) .. "|" .. propName
end
local function safeGet(obj, prop)
	local ok, val = pcall(function()
		return obj[prop]
	end)
	return ok and val or nil
end
local function safeSet(obj, prop, val)
	local ok, err = pcall(function()
		obj[prop] = val
	end)
	return ok, err
end
local function safeGetAttr(obj, name)
	local ok, val = pcall(function()
		return obj:GetAttribute(name)
	end)
	return ok and val or nil
end
local function safeSetAttr(obj, name, val)
	local ok, err = pcall(function()
		obj:SetAttribute(name, val)
	end)
	return ok, err
end
local Editor = {
	State = {
		UI = nil,
		IsMinimized = false,
		IsEnabled = false,
		ActiveOverrides = {},
		HeartbeatConnection = nil,
		ToolConnections = {},
		AttrConnections = {},
		SectionStates = {},
		SearchQuery = "",
		GlowConnection = nil,
	},
	Config = {
		WindowTitle = "Zuka's Prop Editor",
		AccentColor = Color3.fromRGB(0, 255, 255),
		BackgroundColor = Color3.fromRGB(34, 32, 38),
		HeaderColor = Color3.fromRGB(25, 25, 35),
		ItemColor = Color3.fromRGB(48, 48, 58),
		TextColor = Color3.fromRGB(240, 240, 240),
		Font = Enum.Font.Gotham,
		BoldFont = Enum.Font.GothamSemibold,
		MainSize = UDim2.new(0, 360, 0, 480),
		ToggleKey = Enum.KeyCode.RightShift,
	},
}
function Editor:StartHeartbeat()
	local S = self.State
	if S.HeartbeatConnection then
		return
	end
	S.HeartbeatConnection = Services.RunService.Heartbeat:Connect(function()
		self:ForceProperties()
	end)
end
function Editor:StopHeartbeatIfIdle()
	local S = self.State
	if not next(S.ActiveOverrides) and S.HeartbeatConnection then
		S.HeartbeatConnection:Disconnect()
		S.HeartbeatConnection = nil
	end
end
function Editor:ForceProperties()
	local S = self.State
	for key, data in pairs(S.ActiveOverrides) do
		local obj = data.ParentObject
		if not obj or not obj.Parent then
			S.ActiveOverrides[key] = nil
			continue
		end
		local ok, err
		if data.IsAttribute then
			ok, err = safeSetAttr(obj, data.PropName, data.Value)
		else
			ok, err = safeSet(obj, data.PropName, data.Value)
		end
		if not ok then
			warn(("[Editor] Force failed for '%s': %s"):format(key, tostring(err)))
			S.ActiveOverrides[key] = nil
		end
	end
	self:StopHeartbeatIfIdle()
	self:RefreshLiveValues()
end
function Editor:RefreshLiveValues()
	local S = self.State
	local ui = S.UI
	if not (ui and ui.Enabled) then
		return
	end
	local mainFrame = ui:FindFirstChild("MainFrame")
	if not mainFrame then
		return
	end
	local pList = mainFrame:FindFirstChild("PropertyList")
	if not pList then
		return
	end
	for key, data in pairs(S.ActiveOverrides) do
		local row = pList:FindFirstChild(data.PropName .. "Row_" .. key)
		if row then
			local vBox = row:FindFirstChildWhichIsA("TextBox")
			if vBox and not vBox:IsFocused() then
				vBox.Text = tostring(data.Value)
			end
		end
	end
end
function Editor:GetScanTargets()
	local targets = {}
	local character = LocalPlayer.Character
	if not character then
		return targets
	end
	local humanoid = character:FindFirstChildOfClass("Humanoid")
	if humanoid then
		targets["Humanoid"] = { Object = humanoid, IsHumanoid = true }
	end
	local function addPart(obj)
		local uniqueKey = ("%s (%s)"):format(obj.Name, obj.ClassName)
		local i = 1
		local baseKey = uniqueKey
		while targets[uniqueKey] do
			uniqueKey = baseKey .. "_" .. i
			i += 1
		end
		targets[uniqueKey] = { Object = obj, IsHumanoid = false }
	end
	addPart(character)
	for _, desc in ipairs(character:GetDescendants()) do
		if desc:IsA("BasePart") or desc:IsA("Tool") or desc:IsA("Configuration") then
			addPart(desc)
		end
	end
	return targets
end
function Editor:WatchAttributes(targets)
	local S = self.State
	for _, conn in pairs(S.AttrConnections) do
		conn:Disconnect()
	end
	S.AttrConnections = {}
	for _, data in pairs(targets) do
		local obj = data.Object
		local ok, conn = pcall(function()
			return obj.AttributeChanged:Connect(function()
				if S.UI and S.UI.Enabled then
					task.defer(function()
						self:Populate()
					end)
				end
			end)
		end)
		if ok and conn then
			table.insert(S.AttrConnections, conn)
		end
	end
end
function Editor:Populate()
	local S, C = self.State, self.Config
	local mainFrame = S.UI and S.UI:FindFirstChild("MainFrame")
	if not mainFrame then
		return
	end
	local propertyList = mainFrame:FindFirstChild("PropertyList")
	if not propertyList then
		return
	end
	for _, child in ipairs(propertyList:GetChildren()) do
		if not child:IsA("UIListLayout") then
			child:Destroy()
		end
	end
	local character = LocalPlayer.Character
	local humanoid = character and character:FindFirstChildOfClass("Humanoid")
	if not humanoid then
		return
	end
	local targets = self:GetScanTargets()
	self:WatchAttributes(targets)
	local layoutCounter = 0
	local searchQuery = S.SearchQuery:lower()
	local function matchesSearch(name)
		return searchQuery == "" or name:lower():find(searchQuery, 1, true)
	end
	local function addHeader(text)
		layoutCounter += 1
		local isCollapsed = S.SectionStates[text] or false
		local header = Instance.new("TextButton")
		header.Name = text .. "Header"
		header.Parent = propertyList
		header.Size = UDim2.new(1, 0, 0, 26)
		header.Text = ("%s %s"):format(isCollapsed and "" or "▼", text)
		header.TextColor3 = C.AccentColor
		header.Font = C.BoldFont
		header.TextSize = 14
		header.BackgroundColor3 = Color3.fromRGB(30, 30, 42)
		header.AutoButtonColor = false
		header.LayoutOrder = layoutCounter
		Instance.new("UICorner", header).CornerRadius = UDim.new(0, 4)
		header.MouseButton1Click:Connect(function()
			S.SectionStates[text] = not S.SectionStates[text]
			task.defer(function()
				self:Populate()
			end)
		end)
		return header, isCollapsed
	end
	local _, humanoidCollapsed = addHeader("Humanoid")
	if not humanoidCollapsed then
		local humanoidProps = {
			"WalkSpeed",
			"JumpPower",
			"JumpHeight",
			"HipHeight",
			"MaxHealth",
			"Health",
		}
		for _, propName in ipairs(humanoidProps) do
			if not matchesSearch(propName) then
				continue
			end
			local value = safeGet(humanoid, propName)
			if typeof(value) == "number" then
				layoutCounter += 1
				self:CreateNumberRow(propName, value, false, humanoid, layoutCounter)
			end
		end
	end
	local sectionNames = {}
	for name in pairs(targets) do
		table.insert(sectionNames, name)
	end
	table.sort(sectionNames)
	for _, objectName in ipairs(sectionNames) do
		local data = targets[objectName]
		local obj = data.Object
		if not obj or not obj.Parent then
			continue
		end
		if data.IsHumanoid then
			continue
		end
		local attrs = pcall(function()
			return obj:GetAttributes()
		end) and obj:GetAttributes() or {}
		if not next(attrs) then
			continue
		end
		local numAttrs, boolAttrs, strAttrs, vec3Attrs = {}, {}, {}, {}
		for name, value in pairs(attrs) do
			if not matchesSearch(name) then
				continue
			end
			local t = typeof(value)
			if t == "number" then
				table.insert(numAttrs, { Name = name, Value = value })
			elseif t == "boolean" then
				table.insert(boolAttrs, { Name = name, Value = value })
			elseif t == "string" then
				table.insert(strAttrs, { Name = name, Value = value })
			elseif t == "Vector3" then
				table.insert(vec3Attrs, { Name = name, Value = value })
			end
		end
		if not next(numAttrs) and not next(boolAttrs) and not next(strAttrs) and not next(vec3Attrs) then
			continue
		end
		local _, sectionCollapsed = addHeader(objectName)
		if sectionCollapsed then
			continue
		end
		table.sort(numAttrs, function(a, b)
			return a.Name < b.Name
		end)
		table.sort(boolAttrs, function(a, b)
			return a.Name < b.Name
		end)
		table.sort(strAttrs, function(a, b)
			return a.Name < b.Name
		end)
		table.sort(vec3Attrs, function(a, b)
			return a.Name < b.Name
		end)
		for _, d in ipairs(numAttrs) do
			layoutCounter += 1
			self:CreateNumberRow(d.Name, d.Value, true, obj, layoutCounter)
		end
		for _, d in ipairs(boolAttrs) do
			layoutCounter += 1
			self:CreateBooleanRow(d.Name, d.Value, true, obj, layoutCounter)
		end
		for _, d in ipairs(strAttrs) do
			layoutCounter += 1
			self:CreateStringRow(d.Name, d.Value, true, obj, layoutCounter)
		end
		for _, d in ipairs(vec3Attrs) do
			layoutCounter += 1
			self:CreateVector3Row(d.Name, d.Value, true, obj, layoutCounter)
		end
	end
end
local function makeBaseRow(parent, name, C, layoutOrder, compositeKey)
	local frame = Instance.new("Frame", parent)
	frame.Name = name .. "Row_" .. compositeKey
	frame.Size = UDim2.new(1, 0, 0, 30)
	frame.BackgroundColor3 = C.ItemColor
	frame.LayoutOrder = layoutOrder
	Instance.new("UICorner", frame).CornerRadius = UDim.new(0, 6)
	local nameLabel = Instance.new("TextLabel", frame)
	nameLabel.Size = UDim2.new(0.38, 0, 1, 0)
	nameLabel.Text = "  " .. name
	nameLabel.Font = C.Font
	nameLabel.TextSize = 13
	nameLabel.TextColor3 = C.TextColor
	nameLabel.TextXAlignment = Enum.TextXAlignment.Left
	nameLabel.BackgroundTransparency = 1
	nameLabel.TextTruncate = Enum.TextTruncate.AtEnd
	return frame
end
local function makeLockButton(parent, C, S, compositeKey)
	local lockButton = Instance.new("TextButton", parent)
	lockButton.Name = "LockButton"
	lockButton.Size = UDim2.new(0.18, -4, 1, -6)
	lockButton.Position = UDim2.new(0.82, 4, 0.5, 0)
	lockButton.AnchorPoint = Vector2.new(0, 0.5)
	lockButton.Font = C.BoldFont
	lockButton.TextSize = 13
	lockButton.TextColor3 = Color3.new(1, 1, 1)
	Instance.new("UICorner", lockButton).CornerRadius = UDim.new(0, 4)
	local function refresh()
		if S.ActiveOverrides[compositeKey] then
			lockButton.BackgroundColor3 = Color3.fromRGB(40, 140, 80)
			lockButton.Text = "+"
		else
			lockButton.BackgroundColor3 = Color3.fromRGB(100, 40, 50)
			lockButton.Text = "LOCK"
		end
	end
	refresh()
	return lockButton, refresh
end
function Editor:CreateNumberRow(name, value, isAttribute, parentObject, layoutOrder)
	local C, S = self.Config, self.State
	local pList = S.UI.MainFrame.PropertyList
	local compKey = makeKey(parentObject, name)
	local frame = makeBaseRow(pList, name, C, layoutOrder, compKey)
	local valueBox = Instance.new("TextBox", frame)
	valueBox.Size = UDim2.new(0.42, -5, 1, -6)
	valueBox.Position = UDim2.new(0.38, 5, 0.5, 0)
	valueBox.AnchorPoint = Vector2.new(0, 0.5)
	valueBox.BackgroundColor3 = C.HeaderColor
	valueBox.Font = C.Font
	valueBox.TextSize = 13
	valueBox.TextColor3 = Color3.new(1, 1, 1)
	valueBox.Text = tostring(value)
	valueBox.ClearTextOnFocus = false
	Instance.new("UICorner", valueBox).CornerRadius = UDim.new(0, 4)
	local lockButton, refreshLock = makeLockButton(frame, C, S, compKey)
	lockButton.MouseButton1Click:Connect(function()
		local numValue = tonumber(valueBox.Text)
		if not numValue then
			return
		end
		if S.ActiveOverrides[compKey] then
			S.ActiveOverrides[compKey] = nil
			self:StopHeartbeatIfIdle()
		else
			S.ActiveOverrides[compKey] = {
				Value = numValue,
				IsAttribute = isAttribute,
				ParentObject = parentObject,
				PropName = name,
			}
			self:StartHeartbeat()
		end
		refreshLock()
	end)
	valueBox.FocusLost:Connect(function(enterPressed)
		if not enterPressed then
			return
		end
		local newValue = tonumber(valueBox.Text)
		if not newValue then
			valueBox.Text = tostring(value)
			return
		end
		if isAttribute then
			safeSetAttr(parentObject, name, newValue)
			local v = safeGetAttr(parentObject, name)
			valueBox.Text = tostring(v)
		else
			safeSet(parentObject, name, newValue)
			local v = safeGet(parentObject, name)
			valueBox.Text = tostring(v)
		end
		if S.ActiveOverrides[compKey] then
			S.ActiveOverrides[compKey].Value = newValue
		end
	end)
	if S.ActiveOverrides[compKey] then
		valueBox.TextColor3 = C.AccentColor
	end
end
function Editor:CreateBooleanRow(name, value, isAttribute, parentObject, layoutOrder)
	local C, S = self.Config, self.State
	local pList = S.UI.MainFrame.PropertyList
	local compKey = makeKey(parentObject, name)
	local frame = makeBaseRow(pList, name, C, layoutOrder, compKey)
	local valueButton = Instance.new("TextButton", frame)
	valueButton.Size = UDim2.new(0.42, -5, 1, -6)
	valueButton.Position = UDim2.new(0.38, 5, 0.5, 0)
	valueButton.AnchorPoint = Vector2.new(0, 0.5)
	valueButton.Font = C.BoldFont
	valueButton.TextSize = 13
	valueButton.TextColor3 = Color3.new(1, 1, 1)
	Instance.new("UICorner", valueButton).CornerRadius = UDim.new(0, 4)
	local lockButton, refreshLock = makeLockButton(frame, C, S, compKey)
	local currentValue = value
	local function updateValueButton()
		valueButton.Text = currentValue and "TRUE" or "FALSE"
		valueButton.BackgroundColor3 = currentValue and Color3.fromRGB(50, 140, 80) or Color3.fromRGB(140, 50, 60)
		if isAttribute then
			safeSetAttr(parentObject, name, currentValue)
		end
		if S.ActiveOverrides[compKey] then
			S.ActiveOverrides[compKey].Value = currentValue
		end
	end
	updateValueButton()
	valueButton.MouseButton1Click:Connect(function()
		currentValue = not currentValue
		updateValueButton()
	end)
	lockButton.MouseButton1Click:Connect(function()
		if S.ActiveOverrides[compKey] then
			S.ActiveOverrides[compKey] = nil
			self:StopHeartbeatIfIdle()
		else
			S.ActiveOverrides[compKey] = {
				Value = currentValue,
				IsAttribute = isAttribute,
				ParentObject = parentObject,
				PropName = name,
			}
			self:StartHeartbeat()
		end
		refreshLock()
	end)
end
function Editor:CreateStringRow(name, value, isAttribute, parentObject, layoutOrder)
	local C, S = self.Config, self.State
	local pList = S.UI.MainFrame.PropertyList
	local compKey = makeKey(parentObject, name)
	local frame = makeBaseRow(pList, name, C, layoutOrder, compKey)
	local valueBox = Instance.new("TextBox", frame)
	valueBox.Size = UDim2.new(0.42, -5, 1, -6)
	valueBox.Position = UDim2.new(0.38, 5, 0.5, 0)
	valueBox.AnchorPoint = Vector2.new(0, 0.5)
	valueBox.BackgroundColor3 = C.HeaderColor
	valueBox.Font = C.Font
	valueBox.TextSize = 12
	valueBox.TextColor3 = Color3.fromRGB(200, 200, 150)
	valueBox.Text = tostring(value)
	valueBox.ClearTextOnFocus = false
	Instance.new("UICorner", valueBox).CornerRadius = UDim.new(0, 4)
	local lockButton, refreshLock = makeLockButton(frame, C, S, compKey)
	lockButton.MouseButton1Click:Connect(function()
		if S.ActiveOverrides[compKey] then
			S.ActiveOverrides[compKey] = nil
			self:StopHeartbeatIfIdle()
		else
			S.ActiveOverrides[compKey] = {
				Value = valueBox.Text,
				IsAttribute = isAttribute,
				ParentObject = parentObject,
				PropName = name,
			}
			self:StartHeartbeat()
		end
		refreshLock()
	end)
	valueBox.FocusLost:Connect(function(enterPressed)
		if not enterPressed then
			return
		end
		if isAttribute then
			safeSetAttr(parentObject, name, valueBox.Text)
		end
		if S.ActiveOverrides[compKey] then
			S.ActiveOverrides[compKey].Value = valueBox.Text
		end
	end)
end
function Editor:CreateVector3Row(name, value, isAttribute, parentObject, layoutOrder)
	local C, S = self.Config, self.State
	local pList = S.UI.MainFrame.PropertyList
	local compKey = makeKey(parentObject, name)
	local frame = Instance.new("Frame", pList)
	frame.Name = name .. "Row_" .. compKey
	frame.Size = UDim2.new(1, 0, 0, 50)
	frame.BackgroundColor3 = C.ItemColor
	frame.LayoutOrder = layoutOrder
	Instance.new("UICorner", frame).CornerRadius = UDim.new(0, 6)
	local nameLabel = Instance.new("TextLabel", frame)
	nameLabel.Size = UDim2.new(0.38, 0, 0, 20)
	nameLabel.Position = UDim2.new(0, 0, 0, 2)
	nameLabel.Text = "  " .. name
	nameLabel.Font = C.Font
	nameLabel.TextSize = 12
	nameLabel.TextColor3 = C.TextColor
	nameLabel.TextXAlignment = Enum.TextXAlignment.Left
	nameLabel.BackgroundTransparency = 1
	local axes = { "X", "Y", "Z" }
	local boxes = {}
	for i, axis in ipairs(axes) do
		local box = Instance.new("TextBox", frame)
		box.Size = UDim2.new(0.12, 0, 0, 20)
		box.Position = UDim2.new(0.38 + (i - 1) * 0.14, 2, 0, 28)
		box.BackgroundColor3 = C.HeaderColor
		box.Font = C.Font
		box.TextSize = 11
		box.TextColor3 = Color3.fromRGB(180, 220, 255)
		box.Text = tostring(math.round(value[axis] * 1000) / 1000)
		box.ClearTextOnFocus = false
		box.PlaceholderText = axis
		Instance.new("UICorner", box).CornerRadius = UDim.new(0, 3)
		boxes[axis] = box
	end
	local lockButton, refreshLock = makeLockButton(frame, C, S, compKey)
	lockButton.Position = UDim2.new(0.82, 4, 0, 4)
	lockButton.Size = UDim2.new(0.18, -4, 0, 20)
	lockButton.AnchorPoint = Vector2.new(0, 0)
	local function applyVector3()
		local x = tonumber(boxes.X.Text) or value.X
		local y = tonumber(boxes.Y.Text) or value.Y
		local z = tonumber(boxes.Z.Text) or value.Z
		local v3 = Vector3.new(x, y, z)
		if isAttribute then
			safeSetAttr(parentObject, name, v3)
		end
		if S.ActiveOverrides[compKey] then
			S.ActiveOverrides[compKey].Value = v3
		end
		return v3
	end
	for _, box in pairs(boxes) do
		box.FocusLost:Connect(function(enterPressed)
			if enterPressed then
				applyVector3()
			end
		end)
	end
	lockButton.MouseButton1Click:Connect(function()
		if S.ActiveOverrides[compKey] then
			S.ActiveOverrides[compKey] = nil
			self:StopHeartbeatIfIdle()
		else
			local v3 = applyVector3()
			S.ActiveOverrides[compKey] = {
				Value = v3,
				IsAttribute = isAttribute,
				ParentObject = parentObject,
				PropName = name,
			}
			self:StartHeartbeat()
		end
		refreshLock()
	end)
end
function Editor:ToggleMinimize()
	local S, C = self.State, self.Config
	S.IsMinimized = not S.IsMinimized
	local mainFrame = S.UI.MainFrame
	local propertyList = mainFrame.PropertyList
	local searchBar = mainFrame:FindFirstChild("SearchBar")
	local minButton = mainFrame.TitleLabel.MinimizeButton
	local targetSize = S.IsMinimized and UDim2.new(C.MainSize.X.Scale, C.MainSize.X.Offset, 0, 30) or C.MainSize
	Services.TweenService
		:Create(mainFrame, TweenInfo.new(0.2, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), { Size = targetSize })
		:Play()
	propertyList.Visible = not S.IsMinimized
	if searchBar then
		searchBar.Visible = not S.IsMinimized
	end
	minButton.Text = S.IsMinimized and "+" or "_"
end
